fn block_vote_weight(
    slot: u64,
    block_hash: &Hash,
    vote_agg: &VoteAggregator,
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
) -> u64 {
    if let Some(votes) = vote_agg.get_votes(slot, block_hash) {
        let total_stake = stake_pool.total_stake();
        if total_stake == 0 {
            return votes
                .iter()
                .filter_map(|vote| validator_set.get_validator(&vote.validator))
                .map(|v| v.voting_weight())
                .sum();
        }

        return votes
            .iter()
            .filter_map(|vote| stake_pool.get_stake(&vote.validator))
            .map(|stake_info| stake_info.total_stake())
            .sum();
    }

    0
}

fn block_fee_at_index(
    state: &StateStore,
    block: &Block,
    tx_index: usize,
    fee_config: &FeeConfig,
) -> u64 {
    let Some(tx) = block.transactions.get(tx_index) else {
        return 0;
    };
    if tx.is_consensus() {
        return 0;
    }

    if let Some(exact_fee) = TxProcessor::exact_transaction_fee_from_state(state, tx, fee_config) {
        return exact_fee;
    }

    let fallback_fee = TxProcessor::compute_transaction_fee(tx, fee_config);
    if block.tx_fees_paid.len() == block.transactions.len() {
        block
            .tx_fees_paid
            .get(tx_index)
            .copied()
            .unwrap_or(fallback_fee)
    } else {
        fallback_fee
    }
}

fn block_total_fees_paid(state: &StateStore, block: &Block, fee_config: &FeeConfig) -> u64 {
    // AUDIT-FIX HIGH-01: Never trust producer-supplied tx_fees_paid.
    // Always derive fees locally from state receipts or re-computation.
    block
        .transactions
        .iter()
        .filter(|tx| !tx.is_consensus())
        .map(|tx| {
            TxProcessor::exact_transaction_fee_from_state(state, tx, fee_config)
                .unwrap_or_else(|| TxProcessor::compute_transaction_fee(tx, fee_config))
        })
        .sum()
}

fn deterministic_fee_recipient_validators(stake_pool: &StakePool) -> Vec<Pubkey> {
    let mut validators = stake_pool.active_validators();
    validators.sort_by_key(|pk| pk.0);
    validators
}

// =========================================================================
//  CONSENSUS ORACLE MIRROR — Deterministic derived state from finalized prices
//
//  Validators submit signed native oracle attestation transactions. After a
//  block executes, every validator reads the same finalized consensus oracle
//  state and mirrors it into legacy contract storage layouts used by DEX,
//  analytics, and compatibility surfaces.
// =========================================================================

/// Apply consensus-oracle derived state after a block is processed.
///
/// Called on ALL validators after `apply_block_effects`. This function does
/// not trust proposer-carried oracle payloads. Instead, it reads the native
/// consensus oracle state finalized by the block's transactions and mirrors
/// that data into legacy contract storage layouts.
fn apply_oracle_from_block(state: &StateStore, block: &Block) -> Result<(), String> {
    if block.header.slot == 0 {
        return Ok(());
    }

    let slot = block.header.slot;
    let now_ts = block.header.timestamp;

    // Resolve contract pubkeys via symbol registry
    let oracle_pk = match state.get_symbol_registry("ORACLE") {
        Ok(Some(entry)) => entry.program,
        _ => return Ok(()),
    };
    let analytics_pk = match state.get_symbol_registry("ANALYTICS") {
        Ok(Some(entry)) => entry.program,
        _ => return Ok(()),
    };
    let dex_pk = match state.get_symbol_registry("DEX") {
        Ok(Some(entry)) => entry.program,
        _ => Pubkey([0u8; 32]),
    };
    let feeder = match state.get_genesis_pubkey() {
        Ok(Some(gpk)) => gpk.0,
        _ => return Ok(()),
    };

    const PRICE_SCALE: u64 = 1_000_000_000; // 1e9 for DEX price scaling

    let wsol_usd =
        lichen_core::consensus::consensus_oracle_price_from_state(state, "wSOL").unwrap_or(0.0);
    let weth_usd =
        lichen_core::consensus::consensus_oracle_price_from_state(state, "wETH").unwrap_or(0.0);
    let wbnb_usd =
        lichen_core::consensus::consensus_oracle_price_from_state(state, "wBNB").unwrap_or(0.0);
    let wneo_usd =
        lichen_core::consensus::consensus_oracle_price_from_state(state, "wNEO").unwrap_or(0.0);
    let wgas_usd =
        lichen_core::consensus::consensus_oracle_price_from_state(state, "wGAS").unwrap_or(0.0);
    let wbtc_usd =
        lichen_core::consensus::consensus_oracle_price_from_state(state, "wBTC").unwrap_or(0.0);
    let (wneo_enabled, wgas_enabled, wbtc_enabled) = wrapped_oracle_assets_enabled(state);

    if wsol_usd <= 0.0
        && weth_usd <= 0.0
        && wbnb_usd <= 0.0
        && (!wneo_enabled || wneo_usd <= 0.0)
        && (!wgas_enabled || wgas_usd <= 0.0)
        && (!wbtc_enabled || wbtc_usd <= 0.0)
    {
        return Ok(());
    }

    let licn_usd = lichen_core::consensus::licn_price_from_state(state);
    let mut batch = state.begin_batch_at_slot(slot);

    // ── Phase A: Mirror consensus prices into ORACLE compatibility storage ──
    for asset in oracle_asset_symbols(state) {
        let consensus_feed =
            lichen_core::consensus::read_consensus_oracle_price_from_state(state, asset)
                .map(|(price_raw, decimals, _)| (price_raw, decimals));
        let Some((price_raw, decimals)) = consensus_feed else {
            continue;
        };

        // Build 49-byte oracle feed: price(8)+timestamp(8)+decimals(1)+feeder(32)
        let mut feed = Vec::with_capacity(49);
        feed.extend_from_slice(&price_raw.to_le_bytes());
        feed.extend_from_slice(&now_ts.to_le_bytes());
        feed.push(decimals);
        feed.extend_from_slice(&feeder);

        let price_key = format!("price_{}", asset);
        batch.put_contract_storage(&oracle_pk, price_key.as_bytes(), &feed)?;

        // Also write indexed key for aggregation
        let indexed_key = format!("{}_0", price_key);
        batch.put_contract_storage(&oracle_pk, indexed_key.as_bytes(), &feed)?;
    }

    // ── Phase B: Write DEX price bands to DEX contract ──
    // dex_band_{pair_id}: 16 bytes = reference_price(8) + slot(8)
    // The dex_core contract reads this during place_order to enforce
    // ±5% (market) / ±10% (limit) price band protection.
    let pair_prices = oracle_pair_prices(
        OraclePairPriceInputs {
            licn_usd,
            wsol_usd,
            weth_usd,
            wbnb_usd,
            wneo_usd,
            wgas_usd,
            wbtc_usd,
        },
        wneo_enabled,
        wgas_enabled,
        wbtc_enabled,
    );

    if dex_pk.0 != [0u8; 32] {
        for (pair_id, price_f64) in &pair_prices {
            if *price_f64 <= 0.0 {
                continue;
            }
            let price_scaled = (*price_f64 * PRICE_SCALE as f64) as u64;
            let band_key = format!("dex_band_{}", pair_id);
            let mut band_data = Vec::with_capacity(16);
            band_data.extend_from_slice(&price_scaled.to_le_bytes());
            band_data.extend_from_slice(&slot.to_le_bytes());
            batch.put_contract_storage(&dex_pk, band_key.as_bytes(), &band_data)?;
        }
    }

    // ── Phase C: Write analytics indicative prices + CANDLES ──
    // Every validator reads the same finalized consensus oracle prices and
    // writes identical derived analytics state.
    // Candle intervals: 1m, 5m, 15m, 1h, 4h, 1d, 3d, 1w, 1y
    const CANDLE_INTERVALS: [u64; 9] = [60, 300, 900, 3600, 14400, 86400, 259200, 604800, 31536000];

    for (pair_id, price_f64) in &pair_prices {
        if *price_f64 <= 0.0 {
            continue;
        }
        let price_scaled = (*price_f64 * PRICE_SCALE as f64) as u64;

        // Check if a real trade occurred within 60 seconds
        let ts_key = format!("ana_last_trade_ts_{}", pair_id);
        let last_trade_ts: u64 =
            match batch.get_contract_storage(&analytics_pk, ts_key.as_bytes())? {
                Some(d) if d.len() >= 8 => u64::from_le_bytes(d[0..8].try_into().unwrap_or([0; 8])),
                _ => 0,
            };
        let trade_active = last_trade_ts > 0 && now_ts.saturating_sub(last_trade_ts) < 60;

        if trade_active {
            continue; // Active market: trades drive displayed prices + candles
        }

        // Inactive market: write indicative price from oracle
        let lp_key = format!("ana_lp_{}", pair_id);
        batch.put_contract_storage(
            &analytics_pk,
            lp_key.as_bytes(),
            &price_scaled.to_le_bytes(),
        )?;

        // Update 24h stats (read-modify-write)
        let stats_key = format!("ana_24h_{}", pair_id);
        let (vol, mut high, mut low, open, _close, trades) =
            match batch.get_contract_storage(&analytics_pk, stats_key.as_bytes())? {
                Some(d) if d.len() >= 48 => (
                    u64::from_le_bytes(d[0..8].try_into().unwrap_or([0; 8])),
                    u64::from_le_bytes(d[8..16].try_into().unwrap_or([0; 8])),
                    u64::from_le_bytes(d[16..24].try_into().unwrap_or([0; 8])),
                    u64::from_le_bytes(d[24..32].try_into().unwrap_or([0; 8])),
                    u64::from_le_bytes(d[32..40].try_into().unwrap_or([0; 8])),
                    u64::from_le_bytes(d[40..48].try_into().unwrap_or([0; 8])),
                ),
                _ => (0, 0, u64::MAX, price_scaled, price_scaled, 0),
            };

        if price_scaled > high {
            high = price_scaled;
        }
        if price_scaled < low {
            low = price_scaled;
        }

        let mut stats = Vec::with_capacity(48);
        stats.extend_from_slice(&vol.to_le_bytes());
        stats.extend_from_slice(&high.to_le_bytes());
        stats.extend_from_slice(&low.to_le_bytes());
        stats.extend_from_slice(&open.to_le_bytes());
        stats.extend_from_slice(&price_scaled.to_le_bytes()); // close = current
        stats.extend_from_slice(&trades.to_le_bytes());
        batch.put_contract_storage(&analytics_pk, stats_key.as_bytes(), &stats)?;

        // ── Candles: update all 9 intervals with oracle price ──
        // This is consensus-deterministic: every validator processing this block
        // writes the same candle data from the same oracle prices.
        for &interval in &CANDLE_INTERVALS {
            oracle_update_candle(
                &mut batch,
                &analytics_pk,
                *pair_id,
                interval,
                price_scaled,
                now_ts,
            )?;
        }
    }
    state.commit_batch(batch)
}

struct CommittedOracleAttestation {
    signer: Pubkey,
    asset: String,
    price: u64,
    decimals: u8,
}

fn parse_committed_oracle_attestation(
    ix: &lichen_core::Instruction,
) -> Result<Option<CommittedOracleAttestation>, String> {
    if ix.program_id != CORE_SYSTEM_PROGRAM_ID || ix.data.first().copied() != Some(30) {
        return Ok(None);
    }
    if ix.data.len() < 4 {
        return Err(
            "OracleAttestation: data too short (need opcode + asset_len + asset + price + decimals)"
                .to_string(),
        );
    }
    let asset_len = ix.data[1] as usize;
    if !(ORACLE_ASSET_MIN_LEN..=ORACLE_ASSET_MAX_LEN).contains(&asset_len) {
        return Err(format!(
            "OracleAttestation: asset name length {} out of range {}..={}",
            asset_len, ORACLE_ASSET_MIN_LEN, ORACLE_ASSET_MAX_LEN
        ));
    }
    let expected_len = 2 + asset_len + 9;
    if ix.data.len() < expected_len {
        return Err(format!(
            "OracleAttestation: data too short (need {} bytes, got {})",
            expected_len,
            ix.data.len()
        ));
    }
    let asset = std::str::from_utf8(&ix.data[2..2 + asset_len])
        .map_err(|_| "OracleAttestation: asset name is not valid UTF-8".to_string())?
        .to_string();
    let price_offset = 2 + asset_len;
    let price = u64::from_le_bytes(
        ix.data[price_offset..price_offset + 8]
            .try_into()
            .map_err(|_| "OracleAttestation: invalid price bytes".to_string())?,
    );
    let decimals = ix.data[price_offset + 8];
    if price == 0 {
        return Err("OracleAttestation: price must be > 0".to_string());
    }
    if decimals > 18 {
        return Err("OracleAttestation: decimals must be 0..=18".to_string());
    }
    let signer = ix
        .accounts
        .first()
        .copied()
        .ok_or_else(|| "OracleAttestation: requires validator account".to_string())?;

    Ok(Some(CommittedOracleAttestation {
        signer,
        asset,
        price,
        decimals,
    }))
}

fn stage_committed_oracle_attestation_effects(
    state: &StateStore,
    batch: &mut StateBatch,
    block: &Block,
    height_start_stake_pool: &StakePool,
    execution_results: &[lichen_core::TxResult],
) -> Result<(), String> {
    // Oracle records are derived state excluded from the transaction state
    // root, but they still belong to the canonical crash-consistency boundary.
    if block.header.slot == 0 || block.transactions.is_empty() {
        return Ok(());
    }

    let total_active_stake = height_start_stake_pool.active_stake();
    if total_active_stake == 0 {
        return Ok(());
    }
    let active_validators = height_start_stake_pool.active_validators().len();
    let min_attestors = if active_validators <= 1 { 1 } else { 2 };
    let threshold = (total_active_stake as u128) * 2 / 3;

    let executable = block.transactions.iter().filter(|tx| !tx.is_consensus());
    let mut staged = BTreeMap::<String, BTreeMap<Pubkey, lichen_core::OracleAttestation>>::new();
    let mut asset_decimals = BTreeMap::<String, u8>::new();
    for (tx, result) in executable.zip(execution_results) {
        if !result.success {
            continue;
        }
        for ix in &tx.message.instructions {
            let Some(attestation) = parse_committed_oracle_attestation(ix)? else {
                continue;
            };

            let stake_info = height_start_stake_pool
                .get_stake(&attestation.signer)
                .ok_or_else(|| "OracleAttestation: signer has no stake".to_string())?;
            if !stake_info.is_active || !stake_info.meets_minimum() {
                return Err("OracleAttestation: signer is not an active validator".to_string());
            }
            asset_decimals.insert(attestation.asset.clone(), attestation.decimals);
            staged.entry(attestation.asset).or_default().insert(
                attestation.signer,
                lichen_core::OracleAttestation {
                    validator: attestation.signer,
                    price: attestation.price,
                    decimals: attestation.decimals,
                    stake: stake_info.total_stake(),
                    slot: block.header.slot,
                },
            );
        }
    }

    for (asset, pending) in staged {
        let mut attestations: BTreeMap<Pubkey, lichen_core::OracleAttestation> = state
            .get_oracle_attestations(&asset, block.header.slot, ORACLE_STALENESS_SLOTS)?
            .into_iter()
            .map(|attestation| (attestation.validator, attestation))
            .collect();
        for (validator, attestation) in pending {
            batch.put_oracle_attestation(&asset, &attestation)?;
            attestations.insert(validator, attestation);
        }
        let attestations: Vec<_> = attestations.into_values().collect();
        let attested_stake: u128 = attestations
            .iter()
            .map(|attestation| attestation.stake as u128)
            .sum();
        if attested_stake >= threshold && attestations.len() >= min_attestors {
            batch.put_oracle_consensus_price(&lichen_core::OracleConsensusPrice {
                asset: asset.clone(),
                price: compute_stake_weighted_median(&attestations),
                decimals: asset_decimals[&asset],
                slot: block.header.slot,
                attestation_count: attestations.len() as u32,
            })?;
        }
    }

    Ok(())
}

/// Compute BFT timestamp for a new block proposal.
///
/// Looks up the parent block from state and computes the stake-weighted
/// median of its commit vote timestamps (CometBFT BFT Time model).
/// Falls back to wall-clock time if the parent has no commit signatures
/// (genesis or first blocks before BFT activation).
fn compute_proposed_timestamp(
    state: &StateStore,
    parent_hash: &Hash,
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
) -> Option<u64> {
    // Find parent block by hash
    let parent_slot = match state.get_last_slot() {
        Ok(s) => s,
        Err(_) => return None,
    };
    // Search recent blocks for the parent
    let parent_block = if parent_slot == 0 {
        state.get_block_by_slot(0).ok().flatten()
    } else {
        // The parent is at parent_slot (tip)
        let block = state.get_block_by_slot(parent_slot).ok().flatten();
        match block {
            Some(b) if b.hash() == *parent_hash => Some(b),
            _ => None,
        }
    };

    let parent = parent_block?;

    if parent.commit_signatures.is_empty() {
        return None;
    }

    let bft_ts = compute_bft_timestamp(
        &parent.commit_signatures,
        validator_set,
        stake_pool,
        Some(parent.header.timestamp),
    )?;

    // Clamp BFT timestamp to wall-clock + 1s to prevent future-drift blocks.
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    Some(bft_ts.min(now + 1))
}

fn current_unix_millis() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis()
        .min(u128::from(u64::MAX)) as u64
}

fn chain_slot_clock_delay_ms(
    genesis_time_secs: u64,
    height: u64,
    slot_duration_ms: u64,
    now_ms: u64,
) -> u64 {
    let slot_duration_ms = slot_duration_ms.max(1);
    let genesis_ms = genesis_time_secs.saturating_mul(1000);
    let slot_offset_ms = height.saturating_mul(slot_duration_ms);
    let target_ms = genesis_ms.saturating_add(slot_offset_ms);
    target_ms.saturating_sub(now_ms)
}

fn proposal_slot_delay_ms(
    state: &StateStore,
    parent_hash: &Hash,
    genesis_time_secs: u64,
    height: u64,
    slot_duration_ms: u64,
) -> u64 {
    let cadence_delay = chain_slot_clock_delay_ms(
        genesis_time_secs,
        height,
        slot_duration_ms,
        current_unix_millis(),
    );
    block_producer::wall_clock_safe_delay(state, parent_hash, cadence_delay)
}

fn duration_millis_u64(duration: Duration) -> u64 {
    duration.as_millis().min(u128::from(u64::MAX)) as u64
}

fn propose_timeout_delay(slot_boundary_delay_ms: u64, configured_timeout: Duration) -> Duration {
    let configured_timeout_ms = duration_millis_u64(configured_timeout).max(1);
    let delay_ms = slot_boundary_delay_ms.saturating_add(configured_timeout_ms);
    Duration::from_millis(delay_ms)
}

fn propose_timeout_delay_for_role(
    slot_boundary_delay_ms: u64,
    configured_timeout: Duration,
    _slot_duration_ms: u64,
    _local_proposer: bool,
) -> Duration {
    // All validators must give the designated proposer the configured network
    // window. A sub-slot "missed proposer" grace can nil-vote before a valid
    // proposal arrives when a peer is catching up or serving archive ranges.
    propose_timeout_delay(slot_boundary_delay_ms, configured_timeout)
}

/// Validate a received or committed block by deterministically executing its
/// transactions into an in-memory batch, checking the advertised pre-effects
/// state root, then committing that batch exactly once to canonical state.
fn validate_then_replay_block_transactions(
    state: &StateStore,
    block: &Block,
    context: &str,
    allow_schema_detection: bool,
) -> Result<(), String> {
    validate_block_transactions_against_state(state, block, context, allow_schema_detection, true)
}

fn validate_block_transactions_against_state(
    state: &StateStore,
    block: &Block,
    context: &str,
    allow_schema_detection: bool,
    commit: bool,
) -> Result<(), String> {
    if block.header.slot == 0 {
        return validate_state_root_with_schema(
            state,
            block.header.slot,
            block.header.state_root,
            context,
            allow_schema_detection,
        );
    }
    if block.header.state_root == Hash::default() {
        return Err(format!(
            "slot {} {} missing state-root commitment",
            block.header.slot, context
        ));
    }
    let executable: Vec<(usize, Transaction)> = block
        .transactions
        .iter()
        .enumerate()
        .filter(|(_, transaction)| !transaction.is_consensus())
        .map(|(index, transaction)| (index, transaction.clone()))
        .collect();
    if !block.tx_fees_paid.is_empty() && block.tx_fees_paid.len() != block.transactions.len() {
        return Err(format!(
            "slot {} {} fee metadata length mismatch: block has {} entries for {} transactions",
            block.header.slot,
            context,
            block.tx_fees_paid.len(),
            block.transactions.len(),
        ));
    }
    for (tx_index, transaction) in block.transactions.iter().enumerate() {
        if transaction.is_consensus()
            && block
                .tx_fees_paid
                .get(tx_index)
                .is_some_and(|fee| *fee != 0)
        {
            return Err(format!(
                "slot {} {} canonical commit transaction has nonzero fee metadata",
                block.header.slot, context
            ));
        }
    }
    if executable.is_empty() {
        return validate_state_root_with_schema(
            state,
            block.header.slot,
            block.header.state_root,
            context,
            allow_schema_detection,
        );
    }

    let producer = Pubkey(block.header.validator);
    let speculative_processor = TxProcessor::new_speculative(state.clone());
    let executable_transactions: Vec<Transaction> = executable
        .iter()
        .map(|(_, transaction)| transaction.clone())
        .collect();
    let mut speculative = speculative_processor.process_transactions_speculative_at_slot(
        &executable_transactions,
        &producer,
        block.header.slot,
    );

    let computed_root = state.compute_state_root_for_batch(&speculative.batch);
    if computed_root != block.header.state_root {
        return Err(format!(
            "slot {} {} state-root mismatch: local={} expected={}",
            block.header.slot,
            context,
            computed_root.to_hex(),
            block.header.state_root.to_hex(),
        ));
    }

    for ((tx_index, _), result) in executable.iter().zip(&speculative.results) {
        if !result.receipt_eligible {
            return Err(format!(
                "slot {} {} tx {} is not eligible for a canonical receipt: {}",
                block.header.slot,
                context,
                tx_index,
                result.error.as_deref().unwrap_or("unknown error"),
            ));
        }
    }

    for ((tx_index, _), result) in executable.iter().zip(&speculative.results) {
        if let Some(block_fee) = block.tx_fees_paid.get(*tx_index) {
            if *block_fee != result.fee_paid {
                return Err(format!(
                    "slot {} {} tx {} fee metadata mismatch: block={} local={}",
                    block.header.slot, context, tx_index, block_fee, result.fee_paid,
                ));
            }
        }
    }

    if commit {
        let height_start_stake_pool = state.get_stake_pool()?;
        stage_committed_oracle_attestation_effects(
            state,
            &mut speculative.batch,
            block,
            &height_start_stake_pool,
            &speculative.results,
        )?;
        state.commit_batch_with_block(
            speculative.batch,
            block,
            Some(block.header.slot),
            Some(block.header.slot),
        )
    } else {
        Ok(())
    }
}

struct ConsensusProposalValidationContext<'a> {
    expected_parent_hash: Hash,
    expected_validators_hash: Hash,
    min_validator_stake: u64,
    chain_id: &'a str,
}

fn validate_consensus_proposal_before_prevote(
    state: &StateStore,
    proposal: &Proposal,
    context: ConsensusProposalValidationContext<'_>,
) -> Result<(), String> {
    let ConsensusProposalValidationContext {
        expected_parent_hash,
        expected_validators_hash,
        min_validator_stake,
        chain_id,
    } = context;
    let block = &proposal.block;
    if block.header.slot != proposal.height {
        return Err(format!(
            "proposal h={} r={} rejected: block slot {} does not match proposal height",
            proposal.height, proposal.round, block.header.slot
        ));
    }
    if block.header.parent_hash != expected_parent_hash {
        return Err(format!(
            "proposal h={} r={} rejected: parent hash {} does not match local tip {}",
            proposal.height,
            proposal.round,
            block.header.parent_hash.to_hex(),
            expected_parent_hash.to_hex(),
        ));
    }
    if block.header.validators_hash != expected_validators_hash {
        return Err(format!(
            "proposal h={} r={} rejected: validators_hash {} does not match frozen height set {}",
            proposal.height,
            proposal.round,
            block.header.validators_hash.to_hex(),
            expected_validators_hash.to_hex(),
        ));
    }
    if !block.verify_signature_with_chain_id(chain_id) {
        return Err(format!(
            "proposal h={} r={} rejected: block signature is invalid",
            proposal.height, proposal.round,
        ));
    }

    let consensus_transactions: Vec<_> = block
        .transactions
        .iter()
        .enumerate()
        .filter(|(_, transaction)| transaction.is_consensus())
        .collect();
    if proposal.height <= 1 {
        if !consensus_transactions.is_empty() {
            return Err(format!(
                "proposal h={} r={} rejected: genesis child must not carry a parent commit certificate",
                proposal.height, proposal.round
            ));
        }
    } else {
        if consensus_transactions.len() != 1 || consensus_transactions[0].0 != 0 {
            return Err(format!(
                "proposal h={} r={} rejected: exactly one canonical parent commit transaction is required at index 0",
                proposal.height, proposal.round
            ));
        }
        let certificate =
            CanonicalCommitCertificate::from_transaction(consensus_transactions[0].1)?
                .ok_or_else(|| "canonical parent commit transaction is missing".to_string())?;
        certificate.verify_child_metadata(&block.tx_fees_paid, &block.oracle_prices)?;
        let parent = state
            .get_block(&expected_parent_hash)?
            .ok_or_else(|| "canonical parent block is unavailable".to_string())?;
        certificate.verify_parent(&parent, chain_id, min_validator_stake)?;
        let local_parent_post_state_root = state.compute_state_root();
        if certificate.parent_post_state_root != local_parent_post_state_root {
            return Err(format!(
                "proposal h={} r={} rejected: parent post-state root {} does not match local {}",
                proposal.height,
                proposal.round,
                certificate.parent_post_state_root.to_hex(),
                local_parent_post_state_root.to_hex(),
            ));
        }
    }

    validate_block_payload_commitments(block)?;

    validate_block_transactions_against_state(state, block, "consensus proposal", false, false)
}

fn canonical_tip_at_or_past_height(state: &StateStore, height: u64) -> Option<u64> {
    let tip = state.get_last_slot().unwrap_or(0);
    (tip >= height).then_some(tip)
}

type EpochRewardDistributionLog = (u64, u64, usize, Vec<(Pubkey, u64, u64, u64)>);

/// Reverse the financial effects of a replaced block during fork choice.
/// Attempts to debit the old producer's reward and credit treasury back.
/// Fee distribution reversal is approximate — voter shares remain (small
/// amounts relative to block reward). This prevents the worst case of the
/// wrong producer keeping an entire block reward.
async fn revert_block_effects(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    old_block: &Block,
) {
    // AUDIT-FIX 2.20: Read-all → compute-all → write-all pattern to prevent
    // TOCTOU races from concurrent revert/apply operations.
    let old_producer = Pubkey(old_block.header.validator);
    let slot = old_block.header.slot;

    // Phase 1: Read all needed state
    let treasury_pubkey = match state.get_treasury_pubkey() {
        Ok(Some(pk)) => pk,
        _ => {
            warn!("revert_block_effects: no treasury pubkey, skipping");
            return;
        }
    };

    let mut producer_account = match state.get_account(&old_producer) {
        Ok(Some(acc)) => acc,
        _ => {
            warn!("revert_block_effects: producer account not found, skipping");
            return;
        }
    };

    let mut treasury_account = match state.get_account(&treasury_pubkey) {
        Ok(Some(acc)) => acc,
        _ => {
            warn!("revert_block_effects: treasury account not found, skipping");
            return;
        }
    };

    // NOTE: No per-slot inflation reward reversal needed — inflation is now
    // distributed at epoch boundaries, not per-block. Only fee reversal applies.

    // Compute fee reversal — fees are still treasury-sourced
    let fee_config = state
        .get_fee_config()
        .unwrap_or_else(|_| lichen_core::FeeConfig::default_from_constants());
    let total_fee = block_total_fees_paid(state, old_block, &fee_config);

    if total_fee > 0 {
        let producer_share = total_fee * fee_config.fee_producer_percent / 100;
        if producer_share > 0 {
            let fee_debit = producer_share.min(producer_account.spendable);
            producer_account.spores = producer_account.spores.saturating_sub(fee_debit);
            producer_account.spendable = producer_account.spendable.saturating_sub(fee_debit);
            treasury_account.spores = treasury_account.spores.saturating_add(fee_debit);
            treasury_account.spendable = treasury_account.spendable.saturating_add(fee_debit);
        }
    }

    // Phase 3: Write all changes atomically via batch
    let mut batch = state.begin_batch();
    if let Err(e) = batch.put_account(&old_producer, &producer_account) {
        warn!("revert_block_effects: failed to batch-put producer: {}", e);
    }
    if let Err(e) = batch.put_account(&treasury_pubkey, &treasury_account) {
        warn!("revert_block_effects: failed to batch-put treasury: {}", e);
    }
    if let Err(e) = state.commit_batch(batch) {
        warn!("revert_block_effects: failed to commit batch: {}", e);
    }

    // Clear distribution hashes so apply_block_effects can run for the new block
    if let Err(e) = state.clear_reward_distribution_hash(slot) {
        warn!(
            "revert_block_effects: failed to clear reward hash for slot {}: {}",
            slot, e
        );
    }
    if let Err(e) = state.clear_fee_distribution_hash(slot) {
        warn!(
            "revert_block_effects: failed to clear fee hash for slot {}: {}",
            slot, e
        );
    }
    if let Err(e) = state.clear_stake_pool_production_hash(slot) {
        warn!(
            "revert_block_effects: failed to clear stake pool production hash for slot {}: {}",
            slot, e
        );
    }
    if let Err(e) = state.clear_post_block_effects_hash(slot) {
        warn!(
            "revert_block_effects: failed to clear post-block effects hash for slot {}: {}",
            slot, e
        );
    }

    // Keep validator production counters aligned with canonical chain.
    {
        let mut vs = validator_set.write().await;
        if let Some(val_info) = vs.get_validator_mut(&old_producer) {
            val_info.blocks_proposed = val_info.blocks_proposed.saturating_sub(1);
        }

        let vs_snapshot = vs.clone();
        drop(vs);
        if let Err(e) = state.save_validator_set(&vs_snapshot) {
            warn!(
                "⚠️  Failed to persist validator set counter revert for {}: {}",
                old_producer.to_base58(),
                e
            );
        }
    }

    {
        let mut pool = stake_pool.write().await;
        if let Some(stake_info) = pool.get_stake_mut(&old_producer) {
            stake_info.blocks_produced = stake_info.blocks_produced.saturating_sub(1);
        }

        let pool_snapshot = pool.clone();
        drop(pool);
        if let Err(e) = state.put_stake_pool(&pool_snapshot) {
            warn!(
                "⚠️  Failed to persist stake pool counter revert for {}: {}",
                old_producer.to_base58(),
                e
            );
        }
    }

    info!(
        "⚖️  Reverted block effects for slot {} (old producer: {})",
        slot,
        old_producer.to_base58()
    );
}

/// C7 fix: Reverse user transaction effects of a replaced block during fork choice.
/// For each transaction: reverse transfer instructions, refund fees, remove tx record
/// so the new block's transactions can be properly replayed.
/// For non-revertible instructions (contract calls, NFT, staking), attempts to
/// restore affected accounts from the nearest RocksDB checkpoint.
fn revert_block_transactions(state: &StateStore, old_block: &Block, data_dir: &str) {
    use lichen_core::SYSTEM_PROGRAM_ID;

    if old_block.header.slot == 0 {
        return;
    }

    let fee_config = state
        .get_fee_config()
        .unwrap_or_else(|_| lichen_core::FeeConfig::default_from_constants());

    // AUDIT-FIX C7: Collect accounts touched by non-revertible instructions
    // so we can restore them from checkpoint if needed.
    let mut non_revertible_accounts: Vec<lichen_core::Pubkey> = Vec::new();

    for (tx_index, tx) in old_block.transactions.iter().enumerate().rev() {
        let succeeded = state
            .get_tx_meta_full(&tx.signature())
            .ok()
            .flatten()
            .map(|meta| meta.succeeded())
            .unwrap_or(true);
        // AUDIT-FIX 0.5: Detect non-system-transfer instructions that can't be reverted
        let has_non_revertible = succeeded
            && tx.message.instructions.iter().any(|ix| {
                if ix.program_id != SYSTEM_PROGRAM_ID {
                    return true; // Contract call — can't revert
                }
                if ix.data.is_empty() {
                    return false;
                }
                // Only types 0,2,3,4,5 (transfers) are revertible
                !matches!(ix.data[0], 0 | 2 | 3 | 4 | 5)
            });
        if has_non_revertible {
            // AUDIT-FIX C7: Collect all accounts from non-revertible instructions
            // for checkpoint-based restoration instead of best-effort field reversal.
            for ix in &tx.message.instructions {
                if ix.program_id != SYSTEM_PROGRAM_ID
                    || (!ix.data.is_empty() && !matches!(ix.data[0], 0 | 2 | 3 | 4 | 5))
                {
                    for acct in &ix.accounts {
                        non_revertible_accounts.push(*acct);
                    }
                    // Also include the contract/program itself
                    non_revertible_accounts.push(ix.program_id);
                }
            }
            warn!(
                "⚠️  Block {} contains non-revertible instructions — will restore from checkpoint. Tx: {}",
                old_block.header.slot,
                tx.hash().to_hex()
            );
        }

        // 1. Reverse each system transfer instruction
        // L4-01 fix: collect all account mutations in an overlay, then flush
        // them atomically via a single WriteBatch to prevent partial reversals.
        let mut overlay: HashMap<lichen_core::Pubkey, Account> = HashMap::new();

        for ix in &tx.message.instructions {
            if succeeded && ix.program_id == SYSTEM_PROGRAM_ID && !ix.data.is_empty() {
                let ix_type = ix.data[0];
                // Types 0,2,3,4,5 are all transfers
                if matches!(ix_type, 0 | 2 | 3 | 4 | 5)
                    && ix.accounts.len() >= 2
                    && ix.data.len() >= 9
                {
                    let from = ix.accounts[0]; // original sender
                    let to = ix.accounts[1]; // original receiver
                    let amount_bytes: [u8; 8] = match ix.data[1..9].try_into() {
                        Ok(b) => b,
                        Err(_) => continue,
                    };
                    let amount = u64::from_le_bytes(amount_bytes);

                    // Reverse: credit sender, debit receiver
                    if amount > 0 {
                        let receiver = overlay.entry(to).or_insert_with(|| {
                            state
                                .get_account(&to)
                                .ok()
                                .flatten()
                                .unwrap_or_else(|| Account::new(0, SYSTEM_ACCOUNT_OWNER))
                        });
                        let debit = amount.min(receiver.spendable);
                        receiver.spores = receiver.spores.saturating_sub(debit);
                        receiver.spendable = receiver.spendable.saturating_sub(debit);

                        let sender = overlay.entry(from).or_insert_with(|| {
                            state
                                .get_account(&from)
                                .ok()
                                .flatten()
                                .unwrap_or_else(|| Account::new(0, SYSTEM_ACCOUNT_OWNER))
                        });
                        sender.spores = sender.spores.saturating_add(debit);
                        sender.spendable = sender.spendable.saturating_add(debit);
                    }
                }
            }
        }

        // 2. Refund fee to fee payer
        if let Some(first_ix) = tx.message.instructions.first() {
            if let Some(&fee_payer) = first_ix.accounts.first() {
                let fee = block_fee_at_index(state, old_block, tx_index, &fee_config);
                if fee > 0 {
                    let payer = overlay.entry(fee_payer).or_insert_with(|| {
                        state
                            .get_account(&fee_payer)
                            .ok()
                            .flatten()
                            .unwrap_or_else(|| Account::new(0, SYSTEM_ACCOUNT_OWNER))
                    });
                    payer.spores = payer.spores.saturating_add(fee);
                    payer.spendable = payer.spendable.saturating_add(fee);
                }
            }
        }

        // Flush all modified accounts atomically
        if !overlay.is_empty() {
            let batch_accounts: Vec<(&lichen_core::Pubkey, &Account)> = overlay.iter().collect();
            if let Err(e) = state.atomic_put_accounts(&batch_accounts, 0) {
                warn!("⚠️  Failed to atomically revert tx accounts: {}", e);
            }
        }

        // 3. Remove transaction record so new block's txs can be replayed
        let tx_hash = tx.hash();
        state.delete_transaction(&tx_hash).ok();
    }

    // AUDIT-FIX C7: Restore non-revertible accounts from nearest checkpoint.
    // This ensures contract storage, NFT state, staking mutations, etc.
    // are properly rolled back during a fork switch.
    if !non_revertible_accounts.is_empty() {
        non_revertible_accounts.sort_by_key(|a| a.0);
        non_revertible_accounts.dedup();

        // Find the nearest checkpoint at or below the reverted block's slot
        let checkpoints = StateStore::list_checkpoints(data_dir);
        let nearest = checkpoints
            .iter()
            .rev()
            .find(|(cp_slot, _)| *cp_slot < old_block.header.slot);

        if let Some((cp_slot, cp_path)) = nearest {
            match StateStore::open_checkpoint(cp_path) {
                Ok(checkpoint_store) => {
                    // L4-01 fix: collect all restored accounts, then flush atomically
                    let mut restore_accounts: Vec<(lichen_core::Pubkey, Account)> = Vec::new();
                    let mut skipped = 0usize;
                    for acct_key in &non_revertible_accounts {
                        match checkpoint_store.get_account(acct_key) {
                            Ok(Some(cp_account)) => {
                                restore_accounts.push((*acct_key, cp_account));
                            }
                            Ok(None) => {
                                // Account didn't exist at checkpoint time — zero it out
                                // (it was created by the reverted block's contract call)
                                let zeroed = lichen_core::Account {
                                    spores: 0,
                                    spendable: 0,
                                    staked: 0,
                                    locked: 0,
                                    data: Vec::new(),
                                    public_key: None,
                                    owner: SYSTEM_ACCOUNT_OWNER,
                                    executable: false,
                                    rent_epoch: 0,
                                    dormant: false,
                                    missed_rent_epochs: 0,
                                };
                                restore_accounts.push((*acct_key, zeroed));
                            }
                            Err(e) => {
                                warn!(
                                    "⚠️  Failed to read account {} from checkpoint: {}",
                                    acct_key.to_base58(),
                                    e
                                );
                                skipped += 1;
                            }
                        }
                    }
                    if !restore_accounts.is_empty() {
                        let batch_refs: Vec<(&lichen_core::Pubkey, &Account)> =
                            restore_accounts.iter().map(|(k, v)| (k, v)).collect();
                        match state.atomic_put_accounts(&batch_refs, 0) {
                            Ok(()) => {
                                info!(
                                    "🔄 AUDIT-FIX C7+L4-01: Atomically restored {}/{} non-revertible accounts from checkpoint slot {}{}",
                                    restore_accounts.len(), non_revertible_accounts.len(), cp_slot,
                                    if skipped > 0 { format!(" ({} skipped)", skipped) } else { String::new() }
                                );
                            }
                            Err(e) => {
                                error!("🚨 CRITICAL: Atomic checkpoint restore failed: {}", e);
                            }
                        }
                    }
                }
                Err(e) => {
                    error!(
                        "🚨 CRITICAL: Failed to open checkpoint at {} for fork-switch account restoration: {}",
                        cp_path, e
                    );
                }
            }
        } else {
            error!(
                "🚨 CRITICAL: No checkpoint available before slot {} for fork-switch restoration. \
                 {} accounts may have inconsistent state from non-revertible instructions.",
                old_block.header.slot,
                non_revertible_accounts.len()
            );
        }
    }

    info!(
        "⚖️  Reverted {} user transactions for slot {}{}",
        old_block.transactions.len(),
        old_block.header.slot,
        if non_revertible_accounts.is_empty() {
            String::new()
        } else {
            format!(
                " (restored {} accounts from checkpoint)",
                non_revertible_accounts.len()
            )
        }
    );
}

async fn apply_block_effects(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    block: &Block,
    skip_rewards: bool,
    min_validator_stake: u64,
) {
    if block.header.slot == 0 || block.header.validator == [0u8; 32] {
        return;
    }

    // Reload only when block execution could have mutated the persisted stake pool.
    // Empty, transfer-only, DEX, contract, oracle, and governance-readiness blocks
    // keep the in-memory pool authoritative and avoid a full pool deserialize per slot.
    if block_may_mutate_stake_pool(block) {
        match state.get_stake_pool() {
            Ok(fresh_pool) => {
                let entry_count = fresh_pool.stake_entries().len();
                let mut pool = stake_pool.write().await;
                *pool = fresh_pool;
                drop(pool);
                info!(
                    "📊 apply_block_effects slot {}: reloaded pool with {} entries after stake-pool transaction",
                    block.header.slot, entry_count
                );
            }
            Err(err) => {
                error!(
                    "❌ CRITICAL: failed to reload stake pool after a mutating block at slot {}: {}",
                    block.header.slot, err
                );
                std::process::exit(1);
            }
        }
    }

    let producer = Pubkey(block.header.validator);
    let slot = block.header.slot;
    let block_hash = block.hash();
    let canonical_parent_commit = block
        .transactions
        .iter()
        .find(|transaction| transaction.is_consensus())
        .map(|transaction| {
            CanonicalCommitCertificate::from_transaction(transaction).and_then(|certificate| {
                certificate.ok_or_else(|| {
                    "consensus transaction did not contain a canonical commit certificate"
                        .to_string()
                })
            })
        })
        .transpose()
        .unwrap_or_else(|err| {
            error!(
                "FATAL: malformed canonical parent commit in applied block {}: {}",
                slot, err
            );
            std::process::exit(1);
        });

    let user_transaction_count = block
        .transactions
        .iter()
        .filter(|transaction| !transaction.is_consensus())
        .count();
    let has_user_transactions = user_transaction_count > 0;
    let is_liveness_only = !has_user_transactions;
    let reward_already = if !skip_rewards {
        match state.get_reward_distribution_hash(slot) {
            Ok(Some(hash)) if hash == block_hash => true,
            Ok(Some(hash)) => {
                error!(
                    "❌ CRITICAL: reward marker for slot {} has hash {}, expected {}; refusing to mask post-block state drift",
                    slot,
                    hash.to_hex(),
                    block_hash.to_hex()
                );
                std::process::exit(1);
            }
            Ok(None) => false,
            Err(e) => {
                error!(
                    "❌ CRITICAL: failed to read reward distribution marker for slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }
        }
    } else {
        false
    };
    let stake_pool_production_already = if !skip_rewards {
        match state.get_stake_pool_production_hash(slot) {
            Ok(Some(hash)) if hash == block_hash => true,
            Ok(Some(hash)) => {
                error!(
                    "❌ CRITICAL: stake pool production marker for slot {} has hash {}, expected {}; refusing to mask post-block state drift",
                    slot,
                    hash.to_hex(),
                    block_hash.to_hex()
                );
                std::process::exit(1);
            }
            Ok(None) => false,
            Err(e) => {
                error!(
                    "❌ CRITICAL: failed to read stake pool production marker for slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }
        }
    } else {
        false
    };

    let stake_amount = {
        let pool = stake_pool.read().await;
        pool.get_stake(&producer)
            .map(|stake_info| stake_info.total_stake())
            .unwrap_or(0)
    };

    {
        let mut vs = validator_set.write().await;
        let observed_at_ms = block.header.timestamp.saturating_mul(1_000);
        let mut validator_set_changed = false;
        if !reward_already {
            if let Some(certificate) = canonical_parent_commit.as_ref() {
                validator_set_changed |= apply_canonical_commit_activity(&mut vs, certificate) > 0;
            }
        }
        if let Some(val_info) = vs.get_validator_mut(&producer) {
            if !reward_already {
                val_info.blocks_proposed += 1;
                val_info.transactions_processed += user_transaction_count as u64;
                // F-05 audit fix: reputation update moved inside the guard
                // to prevent double-counting on duplicate apply_block_effects calls
                val_info.update_reputation(true);
            }
            val_info.note_block_observation(slot, observed_at_ms);
            validator_set_changed = true;
        } else if stake_amount >= min_validator_stake {
            warn!(
                "⚠️  Stake-backed block producer {} at slot {} is not in local ValidatorSet; admission is deferred to deterministic height-boundary stake reconciliation",
                producer.to_base58(),
                slot
            );
        } else {
            warn!(
                "⚠️  Ignoring unknown unstaked block producer {} at slot {}; block headers cannot create ValidatorSet entries",
                producer.to_base58(),
                slot
            );
        }

        if validator_set_changed {
            // PERF-OPT 4: Clone under lock, persist AFTER dropping write guard.
            // This frees the RwLock while RocksDB I/O runs, unblocking all readers.
            let vs_snapshot = vs.clone();
            drop(vs);
            if let Err(e) = state.save_validator_set(&vs_snapshot) {
                error!(
                    "❌ CRITICAL: failed to persist validator set update at slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }
        } else {
            drop(vs);
        }
    }

    // ── Protocol-level epoch rewards (Solana model) ───────────────────
    // Inflation is NOT distributed per-slot. Instead, at each epoch boundary,
    // the total epoch mint is computed and distributed to ALL active stakers
    // proportionally by stake weight. Block producers still earn tx fees per-block.
    // Every validator deterministically applies the same rewards.
    if !skip_rewards {
        // Compute total supply for inflation curve: genesis + minted - burned
        let total_minted = state.get_total_minted().unwrap_or_else(|err| {
            error!(
                "❌ CRITICAL: failed to read total minted supply at slot {}: {}",
                slot, err
            );
            std::process::exit(1);
        });
        let total_burned = state.get_total_burned().unwrap_or_else(|err| {
            error!(
                "❌ CRITICAL: failed to read total burned supply at slot {}: {}",
                slot, err
            );
            std::process::exit(1);
        });
        let total_supply = GENESIS_SUPPLY_SPORES
            .saturating_add(total_minted)
            .saturating_sub(total_burned);

        // ── Per-block: record block production (no per-slot inflation) ──
        // Inflation is distributed at epoch boundaries to ALL stakers proportionally.
        // Block producers still earn transaction fees per-block (below).
        if !stake_pool_production_already {
            let mut pool = stake_pool.write().await;
            let legacy_high_watermark_counted = pool
                .get_stake(&producer)
                .map(|stake_info| stake_info.last_reward_slot >= slot)
                .unwrap_or(false);
            if !legacy_high_watermark_counted {
                // distribute_block_reward now only updates last_reward_slot (returns 0)
                pool.distribute_block_reward(&producer, slot, is_liveness_only, total_supply);
                pool.record_block_produced(&producer);
            } else {
                debug!(
                    "Stake pool block-production effects for slot {} already satisfy the legacy high-water mark; backfilling marker",
                    slot
                );
            }
            let pool_snapshot = pool.clone();
            drop(pool);
            let mut production_batch = state.begin_batch_at_slot(slot);
            if let Err(e) = production_batch.put_stake_pool(&pool_snapshot) {
                error!(
                    "❌ CRITICAL: failed to stage stake pool block-production update for slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }
            if let Err(e) = production_batch.set_stake_pool_production_hash(slot, &block_hash) {
                error!(
                    "❌ CRITICAL: failed to stage stake pool production marker for slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }
            if let Err(e) = state.commit_batch(production_batch) {
                error!(
                    "❌ CRITICAL: failed to persist stake pool block-production batch for slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }
        } else {
            debug!(
                "Stake pool block-production effects for slot {} already marked complete",
                slot
            );
        }

        if !reward_already {
            let mut reward_batch = state.begin_batch_at_slot(slot);
            let mut epoch_reward_log: Option<EpochRewardDistributionLog> = None;
            let mut mossstake_reward_log: Option<(u64, usize)> = None;
            let mut governance_changes_applied = 0usize;

            // ── Epoch boundary: distribute inflation to ALL stakers proportionally ──
            // At the start of each new epoch, mint the previous epoch's inflation
            // and distribute to every active staker by stake weight, routed through
            // the vesting pipeline (bootstrap debt repayment).
            if lichen_core::is_epoch_boundary(slot) && slot > 0 {
                let completed_epoch_start = lichen_core::epoch_start_slot(
                    lichen_core::consensus::slot_to_epoch(slot).saturating_sub(1),
                );
                let epoch_mint =
                    lichen_core::compute_epoch_mint(completed_epoch_start, total_supply);
                let moss_reward_pool = match state.get_mossstake_pool() {
                    Ok(moss_pool) if moss_pool.st_licn_token.total_supply > 0 => {
                        let (_, moss_reward_pool) = lichen_core::consensus::split_epoch_mint(
                            completed_epoch_start,
                            total_supply,
                        );
                        moss_reward_pool
                    }
                    Ok(_) => 0,
                    Err(e) => {
                        error!(
                            "❌ CRITICAL: failed to load MossStake pool before epoch distribution at slot {}: {}",
                            slot, e
                        );
                        std::process::exit(1);
                    }
                };
                let staker_reward_pool = if moss_reward_pool > 0 {
                    epoch_mint.saturating_sub(moss_reward_pool)
                } else {
                    epoch_mint
                };

                let (total_minted, distributions) = {
                    let mut pool = stake_pool.write().await;
                    let result = pool.distribute_epoch_staker_rewards_from_pool(
                        staker_reward_pool,
                        completed_epoch_start,
                    );
                    let pool_snapshot = pool.clone();
                    drop(pool);
                    if let Err(e) = reward_batch.put_stake_pool(&pool_snapshot) {
                        error!(
                            "❌ CRITICAL: failed to stage stake pool epoch reward update at slot {}: {}",
                            slot, e
                        );
                        std::process::exit(1);
                    }
                    result
                };

                if total_minted > 0 {
                    // Credit each validator's liquid reward to their on-chain account
                    for (validator_pk, _reward, liquid, _debt_payment) in &distributions {
                        if *liquid > 0 {
                            let mut account = match reward_batch.get_account(validator_pk) {
                                Ok(Some(account)) => account,
                                Ok(None) => Account::new(0, SYSTEM_ACCOUNT_OWNER),
                                Err(e) => {
                                    error!(
                                        "❌ CRITICAL: failed to load epoch reward account {} at slot {}: {}",
                                        validator_pk, slot, e
                                    );
                                    std::process::exit(1);
                                }
                            };
                            if let Err(e) = account.add_spendable(*liquid) {
                                error!(
                                    "❌ CRITICAL: overflow crediting epoch reward to {} at slot {}: {}",
                                    validator_pk, slot, e
                                );
                                std::process::exit(1);
                            }
                            if let Err(e) = reward_batch.put_account(validator_pk, &account) {
                                error!(
                                    "❌ CRITICAL: failed to stage epoch reward account {} at slot {}: {}",
                                    validator_pk, slot, e
                                );
                                std::process::exit(1);
                            }
                        }
                    }
                    reward_batch.add_minted(total_minted);
                    epoch_reward_log = Some((
                        lichen_core::consensus::slot_to_epoch(slot).saturating_sub(1),
                        total_minted,
                        distributions.len(),
                        distributions.clone(),
                    ));
                }

                // ── MossStake liquid staking reward distribution ──
                // Allocate MOSSSTAKE_BLOCK_SHARE_BPS (10%) of epoch inflation
                // to the MossStake pool, funding stLICN yield.
                if moss_reward_pool > 0 {
                    match state.get_mossstake_pool() {
                        Ok(mut moss_pool) => {
                            if moss_pool.st_licn_token.total_supply > 0 {
                                moss_pool.distribute_rewards(moss_reward_pool);
                                let position_count = moss_pool.positions.len();
                                if let Err(e) = reward_batch.put_mossstake_pool(&moss_pool) {
                                    error!(
                                        "❌ CRITICAL: failed to stage MossStake epoch distribution at slot {}: {}",
                                        slot, e
                                    );
                                    std::process::exit(1);
                                }
                                reward_batch.add_minted(moss_reward_pool);
                                mossstake_reward_log = Some((moss_reward_pool, position_count));
                            }
                        }
                        Err(e) => {
                            error!(
                                "❌ CRITICAL: failed to load MossStake pool for epoch distribution at slot {}: {}",
                                slot, e
                            );
                            std::process::exit(1);
                        }
                    }
                }

                // ── Apply pending governance parameter changes at epoch boundary ──
                governance_changes_applied = match reward_batch.apply_pending_governance_changes() {
                    Ok(n) => n,
                    Err(e) => {
                        error!(
                            "❌ CRITICAL: failed to stage governance parameter changes at slot {}: {}",
                            slot, e
                        );
                        std::process::exit(1);
                    }
                };
            }

            if let Err(e) = reward_batch.set_reward_distribution_hash(slot, &block_hash) {
                error!(
                    "❌ CRITICAL: failed to stage reward distribution marker for slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }
            if let Err(e) = state.commit_batch(reward_batch) {
                error!(
                    "❌ CRITICAL: failed to commit reward/governance effects for slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }

            if let Some((epoch, total_minted, staker_count, distributions)) = epoch_reward_log {
                info!(
                    "🏛️  Epoch {} rewards: minted {:.3} LICN to {} stakers",
                    epoch,
                    total_minted as f64 / 1_000_000_000.0,
                    staker_count,
                );
                for (pk, reward, liquid, debt) in &distributions {
                    debug!(
                        "  └─ {} : reward {:.6}, liquid {:.6}, debt {:.6}",
                        pk,
                        *reward as f64 / 1_000_000_000.0,
                        *liquid as f64 / 1_000_000_000.0,
                        *debt as f64 / 1_000_000_000.0,
                    );
                }
            }
            if let Some((moss_reward_pool, position_count)) = mossstake_reward_log {
                debug!(
                    "🌊 MossStake: minted {:.6} LICN to {} stakers (epoch)",
                    moss_reward_pool as f64 / 1_000_000_000.0,
                    position_count,
                );
            }
            if governance_changes_applied > 0 {
                let epoch = lichen_core::consensus::slot_to_epoch(slot);
                info!(
                    "🏛️  Epoch {} governance: applied {} parameter change(s)",
                    epoch, governance_changes_applied,
                );
            }
        }
    }

    match state.get_fee_distribution_hash(slot) {
        Ok(Some(existing)) if existing == block_hash => return,
        Ok(Some(existing)) => {
            error!(
                "❌ CRITICAL: fee distribution marker for slot {} has hash {}, expected {}; refusing to mask post-block state drift",
                slot,
                existing.to_hex(),
                block_hash.to_hex()
            );
            std::process::exit(1);
        }
        Ok(None) => {}
        Err(e) => {
            error!(
                "❌ CRITICAL: failed to read fee distribution marker for slot {}: {}",
                slot, e
            );
            std::process::exit(1);
        }
    }

    let fee_config = state.get_fee_config().unwrap_or_else(|err| {
        error!(
            "❌ CRITICAL: failed to read fee configuration at slot {}: {}",
            slot, err
        );
        std::process::exit(1);
    });
    if let Err(err) = fee_config.validate_distribution() {
        error!(
            "❌ CRITICAL: invalid fee distribution at slot {}: {}",
            slot, err
        );
        std::process::exit(1);
    }
    let total_fee = block_total_fees_paid(state, block, &fee_config);

    if total_fee == 0 {
        if let Err(e) = state.set_fee_distribution_hash(slot, &block_hash) {
            error!(
                "❌ CRITICAL: failed to store zero-fee distribution marker for slot {}: {}",
                slot, e
            );
            std::process::exit(1);
        }
        return;
    }

    let treasury_pubkey = match state.get_treasury_pubkey() {
        Ok(Some(pubkey)) => pubkey,
        Ok(None) => {
            error!(
                "❌ CRITICAL: treasury pubkey missing at fee-bearing slot {}",
                slot
            );
            std::process::exit(1);
        }
        Err(err) => {
            error!(
                "❌ CRITICAL: failed to read treasury pubkey at slot {}: {}",
                slot, err
            );
            std::process::exit(1);
        }
    };

    let mut treasury_account = match state.get_account(&treasury_pubkey) {
        Ok(Some(account)) => account,
        Ok(None) => {
            error!(
                "❌ CRITICAL: treasury account {} missing at fee-bearing slot {}",
                treasury_pubkey, slot
            );
            std::process::exit(1);
        }
        Err(err) => {
            error!(
                "❌ CRITICAL: failed to read treasury account at slot {}: {}",
                slot, err
            );
            std::process::exit(1);
        }
    };

    let fee_share =
        |percent: u64| -> u64 { (total_fee as u128 * percent as u128 / 100u128) as u64 };
    let burn = fee_share(fee_config.fee_burn_percent);
    let producer_share = fee_share(fee_config.fee_producer_percent);
    let voters_share = fee_share(fee_config.fee_voters_percent);
    let community_share = fee_share(fee_config.fee_community_percent);
    let mut voters_paid: u64 = 0;
    let mut fee_liquid: u64 = 0; // actual liquid amount after vesting split

    // NOTE: burn was already applied in charge_fee (processor.rs) during
    // transaction processing.  Do NOT call add_burned again here — that
    // caused a double-burn destroying twice the intended supply.

    // AUDIT-FIX 0.6: All fee distribution writes go through an atomic
    // WriteBatch. Nothing hits disk until commit_batch() succeeds, so a
    // crash mid-distribution cannot leave state half-credited.
    let mut batch = state.begin_batch_at_slot(slot);

    if producer_share > 0 {
        // Route producer fee share through vesting pipeline (same as block rewards).
        // distribute_fees() → add_reward() → claim_rewards() → vesting split.
        // While bootstrap_debt > 0 only ~50% is liquid; rest repays debt.
        let (liquid, _debt) = {
            let mut pool = stake_pool.write().await;
            let is_active = pool
                .get_stake(&producer)
                .map(|info| info.is_active)
                .unwrap_or(false);
            if is_active {
                pool.distribute_fees(&producer, producer_share, slot);
                let result = pool.claim_rewards(&producer, slot);
                let pool_snapshot = pool.clone();
                drop(pool);
                if let Err(e) = batch.put_stake_pool(&pool_snapshot) {
                    error!(
                        "❌ CRITICAL: failed to stage stake pool fee update at slot {}: {}",
                        slot, e
                    );
                    std::process::exit(1);
                }
                result
            } else {
                drop(pool);
                (0u64, 0u64)
            }
        };
        fee_liquid = liquid;

        if fee_liquid > 0 {
            let mut producer_account = match state.get_account(&producer) {
                Ok(Some(account)) => account,
                _ => Account::new(0, SYSTEM_ACCOUNT_OWNER),
            };
            if let Err(e) = producer_account.add_spendable(fee_liquid) {
                error!(
                    "❌ CRITICAL: overflow crediting producer fees for slot {}: {}",
                    slot, e
                );
                std::process::exit(1);
            }
            if let Err(e) = batch.put_account(&producer, &producer_account) {
                error!(
                    "❌ CRITICAL: failed to stage producer fee credit for {} at slot {}: {}",
                    producer.to_base58(),
                    slot,
                    e
                );
                std::process::exit(1);
            }
        }
    }

    if voters_share > 0 {
        let pool = stake_pool.read().await;
        let voter_pubkeys = deterministic_fee_recipient_validators(&pool);

        if !voter_pubkeys.is_empty() {
            // Commit signatures are finality evidence, not canonical state input:
            // different validators can commit after seeing different supermajority
            // subsets. Fee state must derive only from block data and active stake.
            let total_voter_stake: u128 = voter_pubkeys
                .iter()
                .filter_map(|validator| pool.get_stake(validator))
                .map(|stake_info| stake_info.total_stake() as u128)
                .sum();

            let mut remaining = voters_share;
            for (idx, validator) in voter_pubkeys.iter().enumerate() {
                // AUDIT-FIX A7-02: Skip slashed/inactive validators
                let is_active = pool
                    .get_stake(validator)
                    .map(|s| s.is_active)
                    .unwrap_or(false);
                if !is_active {
                    continue;
                }

                let share = if total_voter_stake > 0 {
                    let stake = pool
                        .get_stake(validator)
                        .map(|stake_info| stake_info.total_stake())
                        .unwrap_or(0);
                    (voters_share as u128 * stake as u128)
                        .checked_div(total_voter_stake)
                        .unwrap_or(0)
                        .min(remaining as u128) as u64
                } else {
                    let remaining_validators = (voter_pubkeys.len() - idx) as u64;
                    (remaining / remaining_validators).min(remaining)
                };

                if share == 0 {
                    continue;
                }

                let mut voter_account = match batch.get_account(validator) {
                    Ok(Some(account)) => account,
                    _ => match state.get_account(validator) {
                        Ok(Some(account)) => account,
                        _ => Account::new(0, SYSTEM_ACCOUNT_OWNER),
                    },
                };
                if let Err(e) = voter_account.add_spendable(share) {
                    error!(
                        "❌ CRITICAL: overflow crediting voter fees for {} at slot {}: {}",
                        validator.to_base58(),
                        slot,
                        e
                    );
                    std::process::exit(1);
                }
                if let Err(e) = batch.put_account(validator, &voter_account) {
                    error!(
                        "❌ CRITICAL: failed to stage voter fee credit for {} at slot {}: {}",
                        validator.to_base58(),
                        slot,
                        e
                    );
                    std::process::exit(1);
                }
                remaining = remaining.saturating_sub(share);
                voters_paid = voters_paid.saturating_add(share);
            }
        }
        drop(pool);
    }

    let external_allocation = burn
        .checked_add(fee_liquid)
        .and_then(|value| value.checked_add(voters_paid))
        .and_then(|value| value.checked_add(community_share))
        .unwrap_or_else(|| {
            error!("❌ CRITICAL: fee allocation overflow at slot {}", slot);
            std::process::exit(1);
        });
    let treasury_share = total_fee.saturating_sub(external_allocation);

    // Credit community treasury wallet
    if community_share > 0 {
        let community_pubkey = match state.get_community_treasury_pubkey() {
            Ok(Some(pubkey)) => pubkey,
            Ok(None) => {
                error!(
                    "❌ CRITICAL: community treasury pubkey missing at fee-bearing slot {}",
                    slot
                );
                std::process::exit(1);
            }
            Err(err) => {
                error!(
                    "❌ CRITICAL: failed to read community treasury pubkey at slot {}: {}",
                    slot, err
                );
                std::process::exit(1);
            }
        };
        let mut community_account = match batch.get_account(&community_pubkey) {
            Ok(Some(account)) => account,
            Ok(None) => Account::new(0, SYSTEM_ACCOUNT_OWNER),
            Err(err) => {
                error!(
                    "❌ CRITICAL: failed to read community treasury account at slot {}: {}",
                    slot, err
                );
                std::process::exit(1);
            }
        };
        if let Err(e) = community_account.add_spendable(community_share) {
            error!(
                "❌ CRITICAL: overflow crediting community treasury fees at slot {}: {}",
                slot, e
            );
            std::process::exit(1);
        }
        if let Err(e) = batch.put_account(&community_pubkey, &community_account) {
            error!(
                "❌ CRITICAL: failed to stage community treasury fee credit at slot {}: {}",
                slot, e
            );
            std::process::exit(1);
        }
    }

    // charge_fee credited treasury with (fee − burn) for each tx.
    // We debit what we're distributing out: fee_liquid + voters_paid + community_share.
    // fee_liquid is the vesting-adjusted producer share (≤ producer_share).
    // The debt repayment portion stays in treasury as internal bookkeeping.
    // Treasury retains its own share (≈10%) automatically.
    let distributed_debit = fee_liquid
        .checked_add(voters_paid)
        .and_then(|value| value.checked_add(community_share))
        .unwrap_or_else(|| {
            error!(
                "❌ CRITICAL: fee distribution debit overflow at slot {}",
                slot
            );
            std::process::exit(1);
        });
    let treasury_spores_before = treasury_account.spores;
    treasury_account.spores = treasury_spores_before
        .checked_sub(distributed_debit)
        .unwrap_or_else(|| {
            error!(
                "❌ CRITICAL: treasury total balance {} is below distribution debit {} at slot {}",
                treasury_spores_before, distributed_debit, slot
            );
            std::process::exit(1);
        });
    let treasury_spendable_before = treasury_account.spendable;
    treasury_account.spendable = treasury_spendable_before
        .checked_sub(distributed_debit)
        .unwrap_or_else(|| {
            error!(
                "❌ CRITICAL: treasury spendable balance {} is below distribution debit {} at slot {}",
                treasury_spendable_before, distributed_debit, slot
            );
            std::process::exit(1);
        });
    if let Err(e) = batch.put_account(&treasury_pubkey, &treasury_account) {
        error!(
            "❌ CRITICAL: failed to stage treasury fee debit at slot {}: {}",
            slot, e
        );
        std::process::exit(1);
    }

    if let Err(e) = batch.set_fee_distribution_hash(slot, &block_hash) {
        error!(
            "❌ CRITICAL: failed to stage fee distribution marker for slot {}: {}",
            slot, e
        );
        std::process::exit(1);
    }

    // Commit all fee distribution writes atomically
    if let Err(e) = state.commit_batch(batch) {
        error!(
            "❌ CRITICAL: failed to commit fee distribution batch for slot {}: {}",
            slot, e
        );
        std::process::exit(1);
    }

    if treasury_share > 0 {
        info!(
            "🏦 Treasury fees retained: {:.6} LICN",
            treasury_share as f64 / 1_000_000_000.0
        );
    }
}

fn apply_founding_vesting_from_block(
    state: &StateStore,
    block_slot: u64,
    block_time: u64,
) -> Result<(), String> {
    let Some((cliff_end, vest_end, total_amount)) = state.get_founding_vesting_params()? else {
        return Ok(());
    };
    if block_time < cliff_end {
        return Ok(());
    }
    let Some(founding_pubkey) = state.get_founding_symbionts_pubkey()? else {
        return Ok(());
    };
    let mut batch = state.begin_batch_at_slot(block_slot);
    let Some(mut account) = batch.get_account(&founding_pubkey)? else {
        return Err("founding symbionts vesting account is missing".to_string());
    };
    let target_unlocked = lichen_core::consensus::founding_vesting_unlocked(
        total_amount,
        cliff_end,
        vest_end,
        block_time,
    );
    let already_unlocked = total_amount.saturating_sub(account.locked);
    if target_unlocked <= already_unlocked {
        return Ok(());
    }

    let new_unlock = target_unlocked - already_unlocked;
    account.spendable = account
        .spendable
        .checked_add(new_unlock)
        .ok_or_else(|| "founding symbionts spendable balance overflow".to_string())?;
    account.locked = account
        .locked
        .checked_sub(new_unlock)
        .ok_or_else(|| "founding symbionts locked balance underflow".to_string())?;
    batch.put_account(&founding_pubkey, &account)?;
    state.commit_batch(batch)?;

    if new_unlock > 1_000_000_000 {
        info!(
            "🔓 Founding symbionts vest: unlocked {:.2} LICN (total {:.2}M / {:.2}M)",
            new_unlock as f64 / 1_000_000_000.0,
            target_unlocked as f64 / 1_000_000_000_000_000_000.0,
            total_amount as f64 / 1_000_000_000_000_000_000.0,
        );
    }
    Ok(())
}

async fn apply_post_block_effects_after_store(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    block: &Block,
    min_validator_stake: u64,
    _slot_duration_ms: u64,
) {
    apply_block_effects(
        state,
        validator_set,
        stake_pool,
        block,
        false,
        min_validator_stake,
    )
    .await;
    if let Err(err) =
        apply_founding_vesting_from_block(state, block.header.slot, block.header.timestamp)
    {
        error!("Atomic founding vesting projection failed: {}", err);
        std::process::exit(1);
    }
    if let Err(err) = apply_oracle_from_block(state, block) {
        error!("Consensus oracle mirror failed: {}", err);
        std::process::exit(1);
    }

    // Height-boundary validator activation is deterministic post-block state.
    // Keep it after the canonical block write, matching BFT commit ordering.
    {
        let pool = stake_pool.read().await.clone();
        activate_pending_validators_for_height(
            state,
            validator_set,
            &pool,
            block.header.slot,
            min_validator_stake,
        )
        .await;
    }

    if let Err(err) =
        ensure_canonical_analytics_v2(state, block.header.slot, block.header.timestamp)
    {
        error!("Canonical analytics migration failed: {}", err);
        std::process::exit(1);
    }
    if let Err(err) =
        run_analytics_bridge_from_state(state, block.header.slot, block.header.timestamp)
    {
        error!("Canonical analytics projection failed: {}", err);
        std::process::exit(1);
    }
    if let Err(err) = run_sltp_triggers_from_state(state, block.header.slot) {
        error!("Atomic SL/TP trigger projection failed: {}", err);
        std::process::exit(1);
    }
    if let Err(err) = reset_24h_stats_if_expired(state, block.header.slot, block.header.timestamp) {
        error!("Atomic 24-hour analytics rollover failed: {}", err);
        std::process::exit(1);
    }
    if let Err(e) = maybe_activate_legacy_testnet_mossstake_slot_only(
        state,
        block.header.slot,
        "post-block boundary",
    ) {
        error!("Failed post-block MossStake slot-only activation: {}", e);
        std::process::exit(1);
    }
    if let Err(e) = maybe_activate_testnet_governed_signer_recovery(
        state,
        block.header.slot,
        "post-block boundary",
    ) {
        error!(
            "Failed post-block testnet governed signer recovery activation: {}",
            e
        );
        std::process::exit(1);
    }
    if let Err(err) = mark_post_block_effects_complete(state, block) {
        error!("Failed to commit comprehensive post-block marker: {}", err);
        std::process::exit(1);
    }
    record_post_block_state_commitment_anchor(state, block, "post-block effects");
}

fn mark_post_block_effects_complete(state: &StateStore, block: &Block) -> Result<(), String> {
    let mut batch = state.begin_batch_at_slot(block.header.slot);
    batch.set_post_block_effects_hash(block.header.slot, &block.hash())?;
    state.commit_batch(batch)
}

fn record_post_block_state_commitment_anchor(state: &StateStore, block: &Block, context: &str) {
    if block.header.slot == 0 {
        return;
    }

    let block_hash = block.hash();
    let post_state_root = state.compute_state_root();
    match state.get_post_state_commitment_anchor(block.header.slot) {
        Ok(Some(existing))
            if existing.block_hash == block_hash && existing.state_root == post_state_root =>
        {
            return;
        }
        Ok(Some(existing)) => {
            warn!(
                "⚠️  Replacing post-state commitment anchor at slot {} during {}: old_block={} old_root={} new_block={} new_root={}",
                block.header.slot,
                context,
                existing.block_hash.to_hex(),
                existing.state_root.to_hex(),
                block_hash.to_hex(),
                post_state_root.to_hex(),
            );
        }
        Ok(None) => {}
        Err(e) => {
            warn!(
                "⚠️  Failed to read post-state commitment anchor at slot {} during {}: {}",
                block.header.slot, context, e
            );
        }
    }

    if let Err(e) =
        state.put_post_state_commitment_anchor(block.header.slot, &block_hash, &post_state_root)
    {
        warn!(
            "⚠️  Failed to store post-state commitment anchor at slot {} during {}: {}",
            block.header.slot, context, e
        );
    } else {
        debug!(
            "🧾 Post-state commitment anchored slot {} block={} root={} ({})",
            block.header.slot,
            block_hash.to_hex(),
            post_state_root.to_hex(),
            context,
        );
    }
}

fn clean_mossstake_wall_clock_state(state: &StateStore, context: &str) -> Result<bool, String> {
    let mut pool = state.get_mossstake_pool()?;
    let before_hash = if state.is_mossstake_slot_only() {
        pool.canonical_hash()
    } else {
        pool.legacy_canonical_hash()
    };
    let changed = pool.clear_wall_clock_times();
    let slot_only_enabled = matches!(
        state
            .get_metadata(MOSSSTAKE_SLOT_ONLY_METADATA_KEY)?
            .as_deref(),
        Some(b"1")
    );

    if !changed && slot_only_enabled {
        return Ok(false);
    }

    state.put_metadata(MOSSSTAKE_SLOT_ONLY_METADATA_KEY, b"1")?;
    state.put_mossstake_pool(&pool)?;
    let after_hash = pool.canonical_hash();
    if changed {
        warn!(
            "🔧 {}: cleared legacy MossStake wall-clock fields and enabled slot-only mode ({} -> {})",
            context,
            before_hash.to_hex(),
            after_hash.to_hex(),
        );
    } else {
        info!("🔧 {}: enabled MossStake slot-only mode", context);
    }
    Ok(true)
}

const LEGACY_TESTNET_MOSSSTAKE_SLOT_ONLY_ACTIVATION_PARENT_SLOT: u64 = 2_710_766;

fn state_chain_id_metadata(state: &StateStore) -> Option<String> {
    state
        .get_metadata(CHAIN_ID_METADATA_KEY)
        .ok()
        .flatten()
        .and_then(|bytes| String::from_utf8(bytes).ok())
}

fn genesis_bundle_declares_mossstake_slot_only(state: &StateStore) -> Result<bool, String> {
    let Some(genesis) = state.get_block_by_slot(0)? else {
        return Ok(false);
    };
    let Some(bundle) = extract_genesis_state_bundle(&genesis)? else {
        return Ok(false);
    };
    Ok(bundle
        .categories
        .iter()
        .find(|category| category.name == "stats")
        .map(|category| {
            category.entries.iter().any(|(key, value)| {
                key == MOSSSTAKE_SLOT_ONLY_METADATA_KEY.as_bytes() && value.as_slice() == b"1"
            })
        })
        .unwrap_or(false))
}

fn uses_legacy_testnet_mossstake_history(state: &StateStore) -> Result<bool, String> {
    let Some(chain_id) = state_chain_id_metadata(state) else {
        return Ok(false);
    };
    if !chain_id.to_ascii_lowercase().contains("testnet") {
        return Ok(false);
    }
    Ok(!genesis_bundle_declares_mossstake_slot_only(state)?)
}

fn verify_mossstake_slot_only_not_premature(
    state: &StateStore,
    context: &str,
) -> Result<(), String> {
    if !uses_legacy_testnet_mossstake_history(state)? {
        return Ok(());
    }
    let tip = state.get_last_slot().unwrap_or(0);
    if tip < LEGACY_TESTNET_MOSSSTAKE_SLOT_ONLY_ACTIVATION_PARENT_SLOT
        && state.is_mossstake_slot_only()
    {
        return Err(format!(
            "{}: legacy testnet DB has MossStake slot-only marker at slot {}, before activation parent slot {}; this local chain state was migrated too early and must be discarded/resynced from peers with validator identity preserved",
            context,
            tip,
            LEGACY_TESTNET_MOSSSTAKE_SLOT_ONLY_ACTIVATION_PARENT_SLOT
        ));
    }
    Ok(())
}

fn maybe_activate_legacy_testnet_mossstake_slot_only(
    state: &StateStore,
    parent_slot: u64,
    context: &str,
) -> Result<bool, String> {
    if !uses_legacy_testnet_mossstake_history(state)? {
        return Ok(false);
    }
    if parent_slot < LEGACY_TESTNET_MOSSSTAKE_SLOT_ONLY_ACTIVATION_PARENT_SLOT {
        return Ok(false);
    }

    clean_mossstake_wall_clock_state(state, context)
}

fn parse_testnet_recovery_pubkey(role: &str, value: &str) -> Result<Pubkey, String> {
    Pubkey::from_base58(value).map_err(|err| {
        format!(
            "invalid testnet governed signer recovery pubkey for role {}: {}",
            role, err
        )
    })
}

fn testnet_governed_signer_recovery_roles() -> Result<Vec<(String, Pubkey)>, String> {
    TESTNET_GOVERNED_SIGNER_RECOVERY_V1_SIGNERS
        .iter()
        .map(|(role, pubkey)| {
            Ok((
                (*role).to_string(),
                parse_testnet_recovery_pubkey(role, pubkey)?,
            ))
        })
        .collect()
}

fn recovery_distribution_signers(role_signers: &[(String, Pubkey)]) -> Result<Vec<Pubkey>, String> {
    let mut signers = Vec::with_capacity(TESTNET_GOVERNED_SIGNER_RECOVERY_V1_SIGNERS.len());
    for (role, pubkey) in role_signers {
        if !signers.contains(pubkey) {
            signers.push(*pubkey);
        } else {
            return Err(format!(
                "duplicate signer pubkey in testnet governed signer recovery for role {}",
                role
            ));
        }
    }
    Ok(signers)
}

fn preserve_governed_config_policy(
    mut replacement: lichen_core::multisig::GovernedWalletConfig,
    existing: Option<lichen_core::multisig::GovernedWalletConfig>,
) -> Result<lichen_core::multisig::GovernedWalletConfig, String> {
    if let Some(existing) = existing {
        if usize::from(existing.threshold) > replacement.signers.len() {
            return Err(format!(
                "refusing to downgrade governed threshold {} below replacement signer count {} for {}",
                existing.threshold,
                replacement.signers.len(),
                replacement.label
            ));
        }
        replacement.threshold = existing.threshold;
        replacement.timelock_epochs = existing.timelock_epochs;
        replacement.transfer_velocity_policy = existing.transfer_velocity_policy;
    }
    Ok(replacement)
}

fn set_recovered_governed_config(
    state: &StateStore,
    authority: &Pubkey,
    replacement: lichen_core::multisig::GovernedWalletConfig,
) -> Result<(), String> {
    let existing = state.get_governed_wallet_config(authority)?;
    let config = preserve_governed_config_policy(replacement, existing)?;
    state.set_governed_wallet_config(authority, &config)
}

fn maybe_activate_testnet_governed_signer_recovery(
    state: &StateStore,
    parent_slot: u64,
    context: &str,
) -> Result<bool, String> {
    if parent_slot < TESTNET_GOVERNED_SIGNER_RECOVERY_V1_ACTIVATION_PARENT_SLOT {
        return Ok(false);
    }

    if matches!(
        state
            .get_metadata(TESTNET_GOVERNED_SIGNER_RECOVERY_V1_METADATA_KEY)?
            .as_deref(),
        Some(b"1")
    ) {
        return Ok(false);
    }

    let Some(chain_id) = state_chain_id_metadata(state) else {
        return Ok(false);
    };
    if !chain_id.eq_ignore_ascii_case("lichen-testnet-1") {
        return Ok(false);
    }

    let expected_community = parse_testnet_recovery_pubkey(
        "community_treasury_wallet",
        TESTNET_GOVERNED_SIGNER_RECOVERY_V1_COMMUNITY_TREASURY,
    )?;
    let Some(community_treasury) = state.get_community_treasury_pubkey()? else {
        return Ok(false);
    };
    if community_treasury != expected_community {
        return Ok(false);
    }

    let role_signers = testnet_governed_signer_recovery_roles()?;
    let distribution_signers = recovery_distribution_signers(&role_signers)?;
    let committee_role_signers: Vec<(String, Pubkey)> = role_signers
        .iter()
        .filter(|(role, _)| role != "genesis")
        .cloned()
        .collect();

    for &(role, _, _) in GENESIS_DISTRIBUTION {
        let Some(wallet) = state.get_wallet_pubkey(role)? else {
            return Err(format!(
                "testnet governed signer recovery missing genesis wallet role {}",
                role
            ));
        };
        let replacement = governed_wallet_config_for_role(role, &distribution_signers)
            .ok_or_else(|| format!("no governed wallet config template for role {}", role))?;
        set_recovered_governed_config(state, &wallet, replacement)?;
    }

    let (guardian_authority, guardian_config) =
        incident_guardian_config_for_roles(&committee_role_signers, &community_treasury)?;
    state.set_incident_guardian_authority(&guardian_authority)?;
    set_recovered_governed_config(state, &guardian_authority, guardian_config)?;

    let (bridge_authority, bridge_config) =
        bridge_committee_admin_config_for_roles(&committee_role_signers, &community_treasury)?;
    state.set_bridge_committee_admin_authority(&bridge_authority)?;
    set_recovered_governed_config(state, &bridge_authority, bridge_config)?;

    let (oracle_authority, oracle_config) =
        oracle_committee_admin_config_for_roles(&committee_role_signers, &community_treasury)?;
    state.set_oracle_committee_admin_authority(&oracle_authority)?;
    set_recovered_governed_config(state, &oracle_authority, oracle_config)?;

    let (treasury_authority, treasury_config) =
        treasury_executor_config_for_roles(&committee_role_signers, &community_treasury)?;
    state.set_treasury_executor_authority(&treasury_authority)?;
    set_recovered_governed_config(state, &treasury_authority, treasury_config)?;

    let (upgrade_authority, upgrade_config) =
        upgrade_proposer_config_for_roles(&committee_role_signers, &community_treasury)?;
    state.set_upgrade_proposer_authority(&upgrade_authority)?;
    set_recovered_governed_config(state, &upgrade_authority, upgrade_config)?;

    let (veto_authority, veto_config) =
        upgrade_veto_guardian_config_for_roles(&committee_role_signers, &community_treasury)?;
    state.set_upgrade_veto_guardian_authority(&veto_authority)?;
    set_recovered_governed_config(state, &veto_authority, veto_config)?;

    state.put_metadata(TESTNET_GOVERNED_SIGNER_RECOVERY_V1_METADATA_KEY, b"1")?;
    warn!(
        "🔐 {}: activated testnet governed signer recovery v1 at parent slot {} ({} signers)",
        context,
        parent_slot,
        distribution_signers.len()
    );
    Ok(true)
}

fn genesis_sync_incomplete(state: &StateStore) -> bool {
    matches!(
        state
            .get_metadata(GENESIS_SYNC_INCOMPLETE_MARKER)
            .ok()
            .flatten()
            .as_deref(),
        Some(b"1")
    )
}

fn ensure_tip_post_state_commitment_anchor(state: &StateStore) -> Result<(), String> {
    let tip = state.get_last_slot()?;
    if tip == 0 {
        return Ok(());
    }

    let Some(block) = state.get_block_by_slot(tip)? else {
        return Err(format!(
            "stored tip slot {} is missing its canonical block",
            tip
        ));
    };

    let block_hash = block.hash();
    let post_state_root = state.compute_state_root();
    match state.get_post_state_commitment_anchor(tip)? {
        Some(existing)
            if existing.block_hash == block_hash && existing.state_root == post_state_root =>
        {
            Ok(())
        }
        Some(existing) => {
            warn!(
                "⚠️  Repairing tip post-state commitment anchor at slot {}: old_block={} old_root={} new_block={} new_root={}",
                tip,
                existing.block_hash.to_hex(),
                existing.state_root.to_hex(),
                block_hash.to_hex(),
                post_state_root.to_hex(),
            );
            state.put_post_state_commitment_anchor(tip, &block_hash, &post_state_root)
        }
        None => {
            info!(
                "🧾 Startup: anchoring tip {} post-state root {} to block {}",
                tip,
                post_state_root.to_hex(),
                block_hash.to_hex(),
            );
            state.put_post_state_commitment_anchor(tip, &block_hash, &post_state_root)
        }
    }
}

fn repair_active_sparse_state_commitment_before_tip_anchor(
    state: &StateStore,
) -> Result<(), String> {
    if !state.uses_sparse_state_commitment() {
        return Ok(());
    }

    let startup_report = state.audit_and_repair_active_sparse_state_commitment()?;
    if !startup_report.rebuilt {
        info!(
            "🧾 Startup: active sparse state commitment matches canonical state; skipped rebuild: slot={} root={} accounts={} contracts={}",
            startup_report.commitment.last_slot,
            startup_report.commitment.current_state_root.to_hex(),
            startup_report.commitment.accounts_leaf_count,
            startup_report.commitment.contract_leaf_count,
        );
        return Ok(());
    }

    if let Some(err) = startup_report.prior_verification_error.as_deref() {
        warn!(
            "⚠️  Startup: active sparse state commitment did not match canonical state; rebuilt it before tip anchoring: {}",
            err
        );
    }
    info!(
        "🧾 Startup: repaired active sparse state commitment before tip anchoring: slot={} root={} accounts={} contracts={}",
        startup_report.commitment.last_slot,
        startup_report.commitment.current_state_root.to_hex(),
        startup_report.commitment.accounts_leaf_count,
        startup_report.commitment.contract_leaf_count,
    );
    Ok(())
}

fn tip_post_block_effects_complete(state: &StateStore, block: &Block) -> Result<bool, String> {
    let slot = block.header.slot;
    if slot == 0 || block.header.validator == [0u8; 32] {
        return Ok(true);
    }

    let block_hash = block.hash();
    match state.get_post_block_effects_hash(slot)? {
        Some(hash) if hash == block_hash => canonical_economic_block_effects_complete(state, block),
        Some(hash) => Err(format!(
            "slot {} post-block effects marker hash {} differs from stored block hash {}",
            slot,
            hash.to_hex(),
            block_hash.to_hex(),
        )),
        None => Ok(false),
    }
}

fn validate_optional_post_block_effects_marker(
    state: &StateStore,
    block: &Block,
) -> Result<(), String> {
    let slot = block.header.slot;
    let block_hash = block.hash();
    if let Some(hash) = state.get_post_block_effects_hash(slot)? {
        if hash != block_hash {
            return Err(format!(
                "slot {} post-block effects marker hash {} differs from stored block hash {}",
                slot,
                hash.to_hex(),
                block_hash.to_hex(),
            ));
        }
    }
    Ok(())
}

fn post_block_effects_activation_slot(state: &StateStore) -> Result<Option<u64>, String> {
    let Some(encoded) = state.get_metadata(POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY)? else {
        return Ok(None);
    };
    let bytes: [u8; 8] = encoded.try_into().map_err(|value: Vec<u8>| {
        format!(
            "invalid {} metadata length: expected 8 bytes, found {}",
            POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY,
            value.len()
        )
    })?;
    let slot = u64::from_le_bytes(bytes);
    if slot == 0 {
        return Err(format!(
            "{} must be at least slot 1",
            POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY
        ));
    }
    Ok(Some(slot))
}

fn persist_post_block_effects_activation_slot(
    state: &StateStore,
    requested_slot: u64,
) -> Result<u64, String> {
    if requested_slot == 0 {
        return Err(format!(
            "{} must be at least slot 1",
            POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY
        ));
    }
    if let Some(existing_slot) = post_block_effects_activation_slot(state)? {
        if existing_slot == requested_slot {
            return Ok(existing_slot);
        }
        return Err(format!(
            "{} is already {} and cannot be changed to {}",
            POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY, existing_slot, requested_slot
        ));
    }

    state.put_metadata(
        POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY,
        &requested_slot.to_le_bytes(),
    )?;
    state.sync_hot_wal()?;

    let persisted = post_block_effects_activation_slot(state)?;
    if persisted != Some(requested_slot) {
        return Err(format!(
            "failed to durably verify {} at slot {}",
            POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY, requested_slot
        ));
    }
    Ok(requested_slot)
}

fn initialize_post_block_effects_activation_slot(
    state: &StateStore,
    allow_existing_chain_initialization: bool,
) -> Result<u64, String> {
    if let Some(slot) = post_block_effects_activation_slot(state)? {
        return Ok(slot);
    }

    let tip = state.get_last_slot()?;
    if tip > 0 && !allow_existing_chain_initialization {
        return Err(format!(
            "existing public chain at slot {} has no {}; stop and align every validator at one exact tip, then run {} with that common next slot before starting this release",
            tip,
            POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY,
            PREPARE_CONSENSUS_V1_ACTIVATION_FLAG
        ));
    }
    let slot = tip
        .checked_add(1)
        .ok_or_else(|| "cannot activate post-block effects after u64::MAX".to_string())?
        .max(1);
    persist_post_block_effects_activation_slot(state, slot)
}

fn maybe_run_post_block_effects_activation_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, PREPARE_CONSENSUS_V1_ACTIVATION_FLAG) {
        return None;
    }

    let network = get_flag_value(args, &["--network"])
        .map(|value| value.to_ascii_lowercase())
        .unwrap_or_else(|| "testnet".to_string());
    if network != "testnet" && network != "mainnet" {
        eprintln!(
            "Refusing consensus-v1 activation preparation on unsupported network '{network}'"
        );
        return Some(1);
    }
    let requested_slot = match get_flag_value(args, &["--activation-slot"])
        .and_then(|value| value.parse::<u64>().ok())
    {
        Some(slot) if slot > 0 => slot,
        _ => {
            eprintln!("Missing or invalid --activation-slot; expected a positive integer");
            return Some(2);
        }
    };
    let execute = has_flag(args, "--execute");
    let expected_confirmation = format!("consensus-v1-activation:{network}:{requested_slot}");
    if execute && get_flag_value(args, &["--confirm"]) != Some(expected_confirmation.as_str()) {
        eprintln!("Refusing write without --confirm {expected_confirmation}");
        return Some(1);
    }

    let data_dir = restriction_schema_data_dir(args);
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let state = match StateStore::open_with_cache_mb(&data_dir, cache_size_mb) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("Failed to open state DB at {}: {err}", data_dir.display());
            return Some(1);
        }
    };
    let tip = match state.get_last_slot() {
        Ok(slot) => slot,
        Err(err) => {
            eprintln!("Failed to read local tip: {err}");
            return Some(1);
        }
    };
    let expected_slot = match tip.checked_add(1) {
        Some(slot) => slot.max(1),
        None => {
            eprintln!("Cannot activate after u64::MAX");
            return Some(1);
        }
    };
    let existing_slot = match post_block_effects_activation_slot(&state) {
        Ok(slot) => slot,
        Err(err) => {
            eprintln!("Failed to read consensus-v1 activation boundary: {err}");
            return Some(1);
        }
    };

    println!("data_dir={}", data_dir.display());
    println!("network={network}");
    println!("last_slot={tip}");
    println!("expected_activation_slot={expected_slot}");
    println!("requested_activation_slot={requested_slot}");
    println!(
        "existing_activation_slot={}",
        existing_slot
            .map(|slot| slot.to_string())
            .unwrap_or_else(|| "unset".to_string())
    );
    println!("execute={execute}");

    if let Some(existing_slot) = existing_slot {
        if existing_slot != requested_slot {
            eprintln!(
                "Refusing activation change: durable slot is {existing_slot}, requested {requested_slot}"
            );
            return Some(1);
        }
        println!("activation_ready=true");
        println!("activation_already_persisted=true");
        return Some(0);
    }
    if requested_slot != expected_slot {
        eprintln!(
            "Refusing activation at slot {requested_slot}: stopped local tip is {tip}, so the only valid boundary is {expected_slot}"
        );
        return Some(1);
    }
    println!("activation_ready=true");
    println!("activation_already_persisted=false");
    if !execute {
        return Some(0);
    }

    match persist_post_block_effects_activation_slot(&state, requested_slot) {
        Ok(slot) => {
            println!("persisted_activation_slot={slot}");
            Some(0)
        }
        Err(err) => {
            eprintln!("Failed to persist consensus-v1 activation boundary: {err}");
            Some(1)
        }
    }
}

fn require_post_block_effects_repairable_slot(
    block: &Block,
    activation_slot: u64,
) -> Result<(), String> {
    if block.header.slot < activation_slot {
        return Err(format!(
            "refusing post-block repair for pre-activation slot {} (activation_slot={}): missing historical markers do not prove missing effects",
            block.header.slot, activation_slot
        ));
    }
    Ok(())
}

fn canonical_economic_block_effects_complete(
    state: &StateStore,
    block: &Block,
) -> Result<bool, String> {
    let slot = block.header.slot;
    if slot == 0 || block.header.validator == [0u8; 32] {
        return Ok(true);
    }

    let block_hash = block.hash();
    let stake_complete = match state.get_stake_pool_production_hash(slot)? {
        Some(hash) if hash == block_hash => true,
        Some(hash) => {
            return Err(format!(
                "slot {} stake-pool production marker hash {} differs from stored block hash {}",
                slot,
                hash.to_hex(),
                block_hash.to_hex(),
            ));
        }
        None => false,
    };
    let rewards_complete = match state.get_reward_distribution_hash(slot)? {
        Some(hash) if hash == block_hash => true,
        Some(hash) => {
            return Err(format!(
                "slot {} reward distribution marker hash {} differs from stored block hash {}",
                slot,
                hash.to_hex(),
                block_hash.to_hex(),
            ));
        }
        None => false,
    };
    let fees_complete = match state.get_fee_distribution_hash(slot)? {
        Some(hash) if hash == block_hash => true,
        Some(hash) => {
            return Err(format!(
                "slot {} fee distribution marker hash {} differs from stored block hash {}",
                slot,
                hash.to_hex(),
                block_hash.to_hex(),
            ));
        }
        None => false,
    };
    Ok(stake_complete && rewards_complete && fees_complete)
}

async fn recover_stored_block_economic_effects_if_needed(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    block: &Block,
    activation_slot: u64,
    min_validator_stake: u64,
    context: &str,
) -> Result<bool, String> {
    require_post_block_effects_repairable_slot(block, activation_slot)?;
    validate_optional_post_block_effects_marker(state, block)?;
    if canonical_economic_block_effects_complete(state, block)? {
        return Ok(false);
    }

    warn!(
        "🔧 {}: completing deterministic economic post-block effects for stored slot {}",
        context, block.header.slot
    );
    apply_block_effects(
        state,
        validator_set,
        stake_pool,
        block,
        false,
        min_validator_stake,
    )
    .await;
    if !canonical_economic_block_effects_complete(state, block)? {
        return Err(format!(
            "economic post-block effects for stored slot {} are still incomplete after recovery",
            block.header.slot
        ));
    }
    Ok(true)
}

#[derive(Clone, Copy)]
struct PostBlockEffectsRuntime {
    activation_slot: u64,
    min_validator_stake: u64,
    slot_duration_ms: u64,
}

async fn recover_tip_post_block_effects_if_needed(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    activation_slot: u64,
    min_validator_stake: u64,
    slot_duration_ms: u64,
) -> Result<(), String> {
    let tip = state.get_last_slot()?;
    if tip == 0 || tip < activation_slot {
        return Ok(());
    }

    let Some(block) = state.get_block_by_slot(tip)? else {
        return Err(format!(
            "stored tip slot {} is missing its canonical block",
            tip
        ));
    };

    recover_stored_block_post_effects_if_needed(
        state,
        validator_set,
        stake_pool,
        &block,
        PostBlockEffectsRuntime {
            activation_slot,
            min_validator_stake,
            slot_duration_ms,
        },
        "Startup recovery",
    )
    .await?;

    Ok(())
}

async fn recover_recent_stored_block_post_effects_if_needed(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    activation_slot: u64,
    min_validator_stake: u64,
    window: u64,
    context: &str,
) -> Result<u64, String> {
    let tip = state.get_last_slot()?;
    if tip <= 1 || window == 0 || tip <= activation_slot {
        return Ok(0);
    }

    let last_historical_slot = tip.saturating_sub(1);
    let first_slot = last_historical_slot
        .saturating_sub(window.saturating_sub(1))
        .max(activation_slot);
    if first_slot > last_historical_slot {
        return Ok(0);
    }
    let mut repaired = 0u64;
    let total_slots = last_historical_slot
        .saturating_sub(first_slot)
        .saturating_add(1);
    let mut scanned = 0u64;

    for slot in first_slot..=last_historical_slot {
        let block = state.get_block_by_slot(slot)?.ok_or_else(|| {
            format!(
                "{}: activated canonical slot {} is missing its stored block while recovering through tip {}",
                context, slot, tip
            )
        })?;
        scanned = scanned.saturating_add(1);
        if recover_stored_block_economic_effects_if_needed(
            state,
            validator_set,
            stake_pool,
            &block,
            activation_slot,
            min_validator_stake,
            context,
        )
        .await?
        {
            repaired = repaired.saturating_add(1);
        }
        if scanned.is_multiple_of(256) || slot == last_historical_slot {
            info!(
                "🔎 {} progress: scanned {}/{} historical slots, repaired {}",
                context, scanned, total_slots, repaired
            );
        }
    }

    if repaired > 0 {
        let fresh_pool = state.get_stake_pool()?;
        let mut live_pool = stake_pool.write().await;
        *live_pool = fresh_pool;
        drop(live_pool);
        info!(
            "✅ {} completed deterministic economic post-block effects for {} stored historical block(s) in slots {}..{}",
            context, repaired, first_slot, last_historical_slot
        );
        ensure_tip_post_state_commitment_anchor(state)?;
    }

    Ok(repaired)
}

async fn recover_stored_block_post_effects_if_needed(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    block: &Block,
    runtime: PostBlockEffectsRuntime,
    context: &str,
) -> Result<(), String> {
    require_post_block_effects_repairable_slot(block, runtime.activation_slot)?;
    if tip_post_block_effects_complete(state, block)? {
        return Ok(());
    }

    // Canonical execution state and the block anchor commit together. If the
    // process stopped before the normal post-commit index pass, replay that
    // idempotent pass before deterministic post-block recovery.
    state.put_block_atomic(block, Some(block.header.slot), Some(block.header.slot))?;

    warn!(
        "🔧 {}: completing deterministic post-block effects for stored slot {} before continuing",
        context, block.header.slot
    );
    apply_post_block_effects_after_store(
        state,
        validator_set,
        stake_pool,
        block,
        runtime.min_validator_stake,
        runtime.slot_duration_ms,
    )
    .await;

    if !tip_post_block_effects_complete(state, block)? {
        return Err(format!(
            "post-block effects for stored tip {} are still incomplete after recovery",
            block.header.slot
        ));
    }

    info!(
        "✅ {} completed deterministic post-block effects for stored slot {}",
        context, block.header.slot
    );
    Ok(())
}

async fn ensure_recent_stored_post_block_effects_before_bft(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    runtime: PostBlockEffectsRuntime,
    verified_tip: &mut u64,
    window: u64,
    context: &str,
) -> Result<u64, String> {
    let tip = state.get_last_slot()?;
    if tip == 0 || tip < runtime.activation_slot {
        *verified_tip = 0;
        if tip > 0 {
            *verified_tip = tip;
        }
        return Ok(0);
    }
    if tip <= *verified_tip {
        return Ok(0);
    }

    let initial_scan = *verified_tip < runtime.activation_slot.saturating_sub(1);
    let first_slot = if initial_scan {
        tip.saturating_sub(window.saturating_sub(1))
            .max(runtime.activation_slot)
    } else {
        (*verified_tip)
            .saturating_add(1)
            .max(runtime.activation_slot)
    };
    let mut repaired = 0u64;

    for slot in first_slot..=tip {
        let Some(block) = state.get_block_by_slot(slot)? else {
            if initial_scan {
                continue;
            }
            return Err(format!(
                "{}: canonical slot {} is missing its stored block while verifying post-block effects through tip {}",
                context, slot, tip
            ));
        };
        let repaired_block = if slot < tip {
            // For an activated non-tip block, replay only independently
            // idempotent economic effects. Replaying historical oracle hooks
            // could apply current prices at old timestamps; the tip path
            // reconciles cumulative non-economic state without claiming a
            // comprehensive marker for this earlier block.
            recover_stored_block_economic_effects_if_needed(
                state,
                validator_set,
                stake_pool,
                &block,
                runtime.activation_slot,
                runtime.min_validator_stake,
                context,
            )
            .await?
        } else {
            let was_complete = tip_post_block_effects_complete(state, &block)?;
            if !was_complete {
                recover_stored_block_post_effects_if_needed(
                    state,
                    validator_set,
                    stake_pool,
                    &block,
                    runtime,
                    context,
                )
                .await?;
            }
            !was_complete
        };
        if repaired_block {
            repaired = repaired.saturating_add(1);
        }
    }

    let fresh_pool = state.get_stake_pool()?;
    let mut live_pool = stake_pool.write().await;
    *live_pool = fresh_pool;
    drop(live_pool);
    *verified_tip = tip;

    if repaired > 0 {
        ensure_tip_post_state_commitment_anchor(state)?;
        info!(
            "✅ {} completed deterministic post-block effects for {} stored block(s) before BFT continued (slots {}..{})",
            context, repaired, first_slot, tip
        );
    }

    Ok(repaired)
}

async fn activate_pending_validators_before_replay_height(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    block_slot: u64,
    min_validator_stake: u64,
) {
    if block_slot == 0 {
        return;
    }

    let pool = stake_pool.read().await.clone();
    activate_pending_validators_for_height(
        state,
        validator_set,
        &pool,
        block_slot,
        min_validator_stake,
    )
    .await;
}

async fn activate_pending_validators_for_height(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    height_pool: &StakePool,
    new_height: u64,
    min_validator_stake: u64,
) {
    // ── Phase 1: Discover validators from on-chain pool that are NOT in
    //    the in-memory set yet.  This closes the race where a
    //    RegisterValidator tx lands on-chain before the P2P announcement
    //    propagates, causing different nodes to have asymmetric validator
    //    sets.  The on-chain pool is deterministic (same blocks → same pool).
    {
        let known: std::collections::HashSet<Pubkey> = validator_set
            .read()
            .await
            .validators()
            .iter()
            .map(|v| v.pubkey)
            .collect();

        let mut discovered = Vec::new();
        for stake_info in height_pool.stake_entries() {
            let pubkey = stake_info.validator;
            if !known.contains(&pubkey)
                && stake_info.total_stake() >= min_validator_stake
                && stake_info.start_slot > 0
            {
                discovered.push((pubkey, stake_info.total_stake(), stake_info.start_slot));
            }
        }

        if !discovered.is_empty() {
            let mut vs = validator_set.write().await;
            for (pubkey, stake, start_slot) in &discovered {
                if vs.get_validator(pubkey).is_none() {
                    vs.add_validator(ValidatorInfo {
                        pubkey: *pubkey,
                        stake: *stake,
                        reputation: 100,
                        blocks_proposed: 0,
                        votes_cast: 0,
                        correct_votes: 0,
                        joined_slot: *start_slot,
                        last_active_slot: *start_slot,
                        last_observed_at_ms: 0,
                        last_observed_block_at_ms: 0,
                        last_observed_block_slot: 0,
                        commission_rate: 500,
                        transactions_processed: 0,
                        pending_activation: true,
                    });
                    info!(
                        "📋 Height {}: Discovered validator {} from on-chain pool (stake: {} LICN, start_slot: {})",
                        new_height,
                        pubkey.to_base58(),
                        stake / 1_000_000_000,
                        start_slot,
                    );
                }
            }
        }
    }

    // ── Phase 2: Reconcile in-memory set with pool stakes and activate
    //    pending validators deterministically using on-chain start_slot.
    let validator_snapshot: Vec<(Pubkey, u64, bool)> = validator_set
        .read()
        .await
        .validators()
        .iter()
        .map(|validator| {
            (
                validator.pubkey,
                validator.stake,
                validator.pending_activation,
            )
        })
        .collect();

    if validator_snapshot.is_empty() {
        return;
    }

    let mut reconciled = Vec::new();
    for (pubkey, current_stake, pending_activation) in validator_snapshot {
        // Resolve stake: pool first, then on-chain account, then keep current.
        // The pool may not have the validator yet (P2P announcement arrives
        // before RegisterValidator tx is processed), so fall back to the
        // on-chain staked balance which is authoritative.
        let resolved_stake = if let Some(stake) = height_pool.get_stake(&pubkey) {
            stake.total_stake()
        } else {
            match state.get_account(&pubkey) {
                Ok(Some(account)) => account.staked,
                Ok(None) => current_stake,
                Err(err) => {
                    error!(
                        "❌ CRITICAL: failed to read validator account {} at height {}: {}",
                        pubkey, new_height, err
                    );
                    std::process::exit(1);
                }
            }
        };

        // Always include pending validators so they get checked for activation
        // every height, even if their stake hasn't changed yet.
        if resolved_stake != current_stake || pending_activation {
            reconciled.push((pubkey, resolved_stake, pending_activation));
        }
    }

    if reconciled.is_empty() {
        return;
    }

    let mut vs = validator_set.write().await;
    let mut activated = Vec::new();
    let mut changed = false;
    for (pubkey, resolved_stake, pending_activation) in reconciled {
        if let Some(validator) = vs.get_validator_mut(&pubkey) {
            if validator.stake != resolved_stake {
                validator.stake = resolved_stake;
                changed = true;
            }
            if pending_activation
                && validator.pending_activation
                && resolved_stake >= min_validator_stake
            {
                // Activation warmup: new validators must wait ACTIVATION_WARMUP
                // slots before entering the consensus set.  This ensures the
                // joining node has time to fully sync, enter the BFT loop, and
                // be ready to propose/vote.  Without this, a validator activated
                // 1 slot after registration gets selected as BFT leader before
                // it has even finished syncing, causing the chain to stall.
                //
                // 100 slots ≈ 40s at 400ms/slot — enough for sync + BFT entry.
                // Ethereum uses ~6.4min activation queue for comparison.
                let deterministic_join = height_pool
                    .get_stake(&pubkey)
                    .map(|si| si.start_slot)
                    .unwrap_or(0);
                if deterministic_join > 0
                    && new_height
                        > deterministic_join.saturating_add(VALIDATOR_ACTIVATION_WARMUP_SLOTS)
                {
                    validator.pending_activation = false;
                    validator.joined_slot = deterministic_join;
                    changed = true;
                    activated.push(pubkey);
                }
            }
        }
    }

    if !changed {
        return;
    }

    let snapshot = vs.clone();
    drop(vs);

    if let Err(e) = state.save_validator_set(&snapshot) {
        error!(
            "❌ CRITICAL: failed to persist validator set after height-boundary activation at height {}: {}",
            new_height, e
        );
        std::process::exit(1);
    }

    for pubkey in activated {
        info!(
            "🔓 Height {}: Activated validator {} for consensus",
            new_height,
            pubkey.to_base58()
        );
    }
}

async fn freeze_consensus_snapshot_for_height(
    state: &StateStore,
    validator_set: &Arc<RwLock<ValidatorSet>>,
    stake_pool: &Arc<RwLock<StakePool>>,
    height: u64,
    min_validator_stake: u64,
) -> (ValidatorSet, StakePool) {
    let height_pool = stake_pool.read().await.clone();

    if lichen_core::is_epoch_boundary(height) {
        let epoch = lichen_core::slot_to_epoch(height);
        {
            let mut vs = validator_set.write().await;

            if let Ok(pending) = state.get_pending_validator_changes(epoch) {
                for change in &pending {
                    if change.change_type == lichen_core::ValidatorChangeType::Remove {
                        vs.remove_validator(&change.pubkey);
                        if let Err(e) = state.delete_validator(&change.pubkey) {
                            warn!(
                                "⚠️  Failed to remove deregistered validator {} from state: {}",
                                change.pubkey.to_base58(),
                                e
                            );
                        }
                        info!(
                            "🔒 Epoch {}: Deregistered validator {} (voluntary exit)",
                            epoch,
                            change.pubkey.to_base58()
                        );
                    }
                }
            }

            if let Err(e) = state.save_validator_set(&vs) {
                warn!(
                    "⚠️  Failed to persist validator set after epoch transition: {}",
                    e
                );
            }
        }
        if let Err(e) = state.clear_pending_validator_changes(epoch) {
            warn!(
                "⚠️  Failed to clear pending validator changes for epoch {}: {}",
                epoch, e
            );
        }

        activate_pending_validators_for_height(
            state,
            validator_set,
            &height_pool,
            height,
            min_validator_stake,
        )
        .await;

        let (mut frozen, pending_count) = {
            let vs = validator_set.read().await;
            (vs.consensus_set(), vs.pending_count())
        };
        frozen.set_frozen_epoch(epoch);
        info!(
            "🧊 Epoch {}: Froze validator set ({} active, {} pending)",
            epoch,
            frozen.validators().len(),
            pending_count,
        );
        persist_validator_power_snapshot_or_exit(state, &frozen, &height_pool, height);
        return (frozen, height_pool);
    }

    activate_pending_validators_for_height(
        state,
        validator_set,
        &height_pool,
        height,
        min_validator_stake,
    )
    .await;

    let frozen = validator_set.read().await.consensus_set();
    persist_validator_power_snapshot_or_exit(state, &frozen, &height_pool, height);
    (frozen, height_pool)
}

fn persist_validator_power_snapshot_or_exit(
    state: &StateStore,
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
    height: u64,
) {
    let powers = canonical_validator_powers(validator_set, stake_pool);
    let validators_hash = compute_validators_hash(validator_set, stake_pool);
    if let Err(err) = state.put_validator_power_snapshot(&validators_hash, &powers) {
        error!(
            "FATAL: failed to persist validator power snapshot for height {} hash {}: {}",
            height, validators_hash, err
        );
        std::process::exit(1);
    }
}

const DEFAULT_CHECKPOINT_KEEP_COUNT: usize = 2;
const MAX_CHECKPOINT_KEEP_COUNT: usize = 16;
const DEFAULT_CHECKPOINT_MAX_BYTES: u64 = 8 * 1024 * 1024 * 1024;
const MAX_CHECKPOINT_MAX_BYTES: u64 = 128 * 1024 * 1024 * 1024;

#[cfg(all(unix, target_os = "linux"))]
fn statvfs_block_count(value: libc::fsblkcnt_t) -> u64 {
    value
}

#[cfg(all(unix, not(target_os = "linux")))]
fn statvfs_block_count(value: libc::fsblkcnt_t) -> u64 {
    value as u64
}

#[cfg(unix)]
fn filesystem_available_bytes(path: &Path) -> Result<u64, String> {
    use std::ffi::CString;
    use std::os::unix::ffi::OsStrExt;

    let path_bytes = CString::new(path.as_os_str().as_bytes())
        .map_err(|_| format!("filesystem path contains a NUL byte: {}", path.display()))?;
    let mut stat = std::mem::MaybeUninit::<libc::statvfs>::uninit();
    let rc = unsafe { libc::statvfs(path_bytes.as_ptr(), stat.as_mut_ptr()) };
    if rc != 0 {
        return Err(format!(
            "failed to inspect filesystem capacity for {}: {}",
            path.display(),
            std::io::Error::last_os_error()
        ));
    }
    let stat = unsafe { stat.assume_init() };
    let block_size = if stat.f_frsize > 0 {
        stat.f_frsize
    } else {
        stat.f_bsize
    };
    Ok(statvfs_block_count(stat.f_bavail).saturating_mul(block_size))
}

#[cfg(not(unix))]
fn filesystem_available_bytes(_path: &Path) -> Result<u64, String> {
    Err("filesystem capacity inspection is unsupported on this platform".to_string())
}

fn has_required_disk_headroom(available_bytes: u64, minimum_bytes: u64) -> bool {
    available_bytes >= minimum_bytes
}

fn require_runtime_disk_headroom(path: &Path) -> Result<u64, String> {
    let available = filesystem_available_bytes(path)?;
    if !has_required_disk_headroom(available, MIN_RUNTIME_AVAILABLE_BYTES) {
        return Err(format!(
            "{} has {} available bytes; at least {} are required to open a validator safely",
            path.display(),
            available,
            MIN_RUNTIME_AVAILABLE_BYTES
        ));
    }
    Ok(available)
}

fn directory_allocated_bytes(path: &Path) -> Result<u64, String> {
    let mut total = 0u64;
    let mut stack = vec![path.to_path_buf()];
    #[cfg(unix)]
    let mut seen_files = std::collections::HashSet::new();

    while let Some(current) = stack.pop() {
        let metadata = fs::symlink_metadata(&current)
            .map_err(|err| format!("failed to stat {}: {}", current.display(), err))?;
        if metadata.file_type().is_symlink() {
            continue;
        }
        if metadata.is_dir() {
            for entry in fs::read_dir(&current)
                .map_err(|err| format!("failed to read {}: {}", current.display(), err))?
            {
                let entry = entry.map_err(|err| {
                    format!("failed to read entry in {}: {}", current.display(), err)
                })?;
                stack.push(entry.path());
            }
            continue;
        }
        if !metadata.is_file() {
            continue;
        }

        #[cfg(unix)]
        {
            use std::os::unix::fs::MetadataExt;
            if seen_files.insert((metadata.dev(), metadata.ino())) {
                total = total.saturating_add(metadata.blocks().saturating_mul(512));
            }
        }
        #[cfg(not(unix))]
        {
            total = total.saturating_add(metadata.len());
        }
    }

    Ok(total)
}

fn snapshot_apply_required_available_bytes(staging_allocated_bytes: u64) -> u64 {
    staging_allocated_bytes
        .saturating_mul(SNAPSHOT_APPLY_COMPACTION_COPIES)
        .saturating_add(MIN_RUNTIME_AVAILABLE_BYTES)
}

fn require_snapshot_apply_disk_headroom(
    filesystem_path: &Path,
    staging_path: &Path,
) -> Result<(u64, u64, u64), String> {
    let available_bytes = filesystem_available_bytes(filesystem_path)?;
    let staging_allocated_bytes = directory_allocated_bytes(staging_path)?;
    let required_bytes = snapshot_apply_required_available_bytes(staging_allocated_bytes);
    if available_bytes < required_bytes {
        return Err(format!(
            "{} has {} available bytes, but applying verified staging DB {} ({} allocated bytes) requires at least {} available bytes: one replacement copy, one compaction copy, and the {} byte runtime reserve",
            filesystem_path.display(),
            available_bytes,
            staging_path.display(),
            staging_allocated_bytes,
            required_bytes,
            MIN_RUNTIME_AVAILABLE_BYTES,
        ));
    }
    Ok((available_bytes, staging_allocated_bytes, required_bytes))
}

fn spawn_runtime_disk_guard(path: PathBuf) {
    tokio::spawn(async move {
        let mut interval =
            tokio::time::interval(Duration::from_secs(DISK_CAPACITY_CHECK_INTERVAL_SECS));
        interval.tick().await;
        loop {
            interval.tick().await;
            match require_runtime_disk_headroom(&path) {
                Ok(_) => {}
                Err(err) => {
                    error!(
                        "FATAL: validator disk headroom exhausted: {}. Stopping without restart to protect RocksDB.",
                        err
                    );
                    std::process::exit(EXIT_CODE_FATAL_STARTUP);
                }
            }
        }
    });
}

fn parse_checkpoint_keep_count(raw: Option<&str>) -> usize {
    raw.and_then(|value| value.trim().parse::<usize>().ok())
        .filter(|value| *value > 0)
        .map(|value| value.min(MAX_CHECKPOINT_KEEP_COUNT))
        .unwrap_or(DEFAULT_CHECKPOINT_KEEP_COUNT)
}

fn checkpoint_keep_count_from_env() -> usize {
    parse_checkpoint_keep_count(env::var("LICHEN_CHECKPOINT_KEEP_COUNT").ok().as_deref())
}

fn parse_checkpoint_max_bytes(raw: Option<&str>) -> Option<u64> {
    match raw.and_then(|value| value.trim().parse::<u64>().ok()) {
        Some(0) => None,
        Some(value) => Some(value.min(MAX_CHECKPOINT_MAX_BYTES)),
        None => Some(DEFAULT_CHECKPOINT_MAX_BYTES),
    }
}

fn checkpoint_max_bytes_from_env() -> Option<u64> {
    parse_checkpoint_max_bytes(env::var("LICHEN_CHECKPOINT_MAX_BYTES").ok().as_deref())
}

fn prune_state_checkpoints(data_dir: &str, context: &str) {
    let keep_count = checkpoint_keep_count_from_env();
    let max_bytes = checkpoint_max_bytes_from_env();
    match StateStore::prune_checkpoints_with_size_limit(data_dir, keep_count, max_bytes) {
        Ok(removed) if removed > 0 => {
            info!(
                "🧹 Pruned {} old checkpoint(s) after {}; keeping up to {} recent checkpoint(s), max_size={}",
                removed,
                context,
                keep_count,
                max_bytes
                    .map(|bytes| bytes.to_string())
                    .unwrap_or_else(|| "disabled".to_string())
            );
        }
        Ok(_) => {}
        Err(e) => warn!(
            "⚠️  Failed to prune old checkpoints after {}: {}",
            context, e
        ),
    }
}

/// Periodic checkpoint creation — called after every block to check if
/// the current slot should trigger a RocksDB checkpoint.
/// Checkpoints are created every CHECKPOINT_INTERVAL (1,000) slots and
/// provide O(1) state snapshots for new validator catch-up.
async fn maybe_create_checkpoint(
    state: &StateStore,
    slot: u64,
    data_dir: &str,
    sync_manager: &Arc<SyncManager>,
) {
    use crate::sync::SyncManager;
    if !SyncManager::should_checkpoint(slot) {
        return;
    }
    let checkpoint_root = Path::new(data_dir);
    match filesystem_available_bytes(checkpoint_root) {
        Ok(available) if !has_required_disk_headroom(available, MIN_CHECKPOINT_AVAILABLE_BYTES) => {
            warn!(
                "Skipping checkpoint at slot {}: {} available bytes is below the {} byte checkpoint safety floor",
                slot, available, MIN_CHECKPOINT_AVAILABLE_BYTES
            );
            return;
        }
        Ok(_) => {}
        Err(err) => {
            warn!(
                "Skipping checkpoint at slot {} because disk capacity cannot be verified: {}",
                slot, err
            );
            return;
        }
    }
    let checkpoint_path = format!("{}/checkpoints/slot-{}", data_dir, slot);
    match state.create_checkpoint(&checkpoint_path, slot) {
        Ok(meta) => {
            info!(
                "📸 Checkpoint created at slot {} ({} accounts, interval: every {} slots)",
                meta.slot,
                meta.total_accounts,
                SyncManager::checkpoint_interval()
            );
            // Record the checkpoint in SyncManager for fast bootstrapping
            sync_manager.set_checkpoint(slot).await;
            prune_state_checkpoints(data_dir, "periodic checkpoint");
        }
        Err(e) => {
            warn!("⚠️  Failed to create checkpoint at slot {}: {}", slot, e);
        }
    }
}

#[cfg(test)]
fn latest_verified_checkpoint(
    data_dir: &str,
    state: &StateStore,
    chain_id: &str,
    min_validator_stake: u64,
) -> Option<(
    lichen_core::CheckpointMeta,
    String,
    Block,
    Vec<SnapshotCategoryDigest>,
)> {
    let ctx = CheckpointVerificationContext {
        data_dir,
        state,
        chain_id,
        min_validator_stake,
    };
    recent_verified_checkpoints(ctx, 1, 1)
        .into_iter()
        .next()
        .map(|checkpoint| checkpoint.checkpoint())
}

#[derive(Clone, Copy)]
struct CheckpointVerificationContext<'a> {
    data_dir: &'a str,
    state: &'a StateStore,
    chain_id: &'a str,
    min_validator_stake: u64,
}

fn canonical_checkpoint_certificate(
    state: &StateStore,
    checkpoint_block: &Block,
    chain_id: &str,
    min_validator_stake: u64,
) -> Result<(CanonicalCommitCertificate, CheckpointCanonicalProof), String> {
    let child_slot = checkpoint_block
        .header
        .slot
        .checked_add(1)
        .ok_or_else(|| "checkpoint slot overflow".to_string())?;
    let child = state.get_block_by_slot(child_slot)?.ok_or_else(|| {
        format!(
            "checkpoint block {} has no canonical child",
            checkpoint_block.header.slot
        )
    })?;
    if child.header.parent_hash != checkpoint_block.hash() {
        return Err(format!(
            "checkpoint child {} does not extend checkpoint block {}",
            child_slot, checkpoint_block.header.slot
        ));
    }
    validate_block_payload_commitments(&child)?;
    let consensus_transactions: Vec<_> = child
        .transactions
        .iter()
        .enumerate()
        .filter(|(_, transaction)| transaction.is_consensus())
        .collect();
    if consensus_transactions.len() != 1 || consensus_transactions[0].0 != 0 {
        return Err(format!(
            "checkpoint child {} does not contain exactly one canonical certificate at index 0",
            child_slot
        ));
    }
    let certificate = CanonicalCommitCertificate::from_transaction(consensus_transactions[0].1)?
        .ok_or_else(|| format!("checkpoint child {} certificate is missing", child_slot))?;
    certificate.verify_child_metadata(&child.tx_fees_paid, &child.oracle_prices)?;
    let child_validator_powers = state
        .get_validator_power_snapshot(&child.header.validators_hash)?
        .ok_or_else(|| {
            format!(
                "checkpoint child {} validator power snapshot {} is unavailable",
                child_slot, child.header.validators_hash
            )
        })?;
    let canonical_proof = CheckpointCanonicalProof {
        child_header: child.header.clone(),
        certificate_merkle_proof: lichen_core::merkle_tx_proof(&child.transactions, 0).ok_or_else(
            || {
                format!(
                    "checkpoint child {} certificate proof is unavailable",
                    child_slot
                )
            },
        )?,
        child_commit_round: child.commit_round,
        child_commit_signatures: child.commit_signatures.clone(),
        child_validator_powers,
    };
    verify_checkpoint_canonical_proof(
        checkpoint_block,
        &certificate,
        &canonical_proof,
        chain_id,
        min_validator_stake,
    )?;
    Ok((certificate, canonical_proof))
}

fn verify_checkpoint_canonical_proof(
    checkpoint_block: &Block,
    certificate: &CanonicalCommitCertificate,
    proof: &CheckpointCanonicalProof,
    chain_id: &str,
    min_validator_stake: u64,
) -> Result<(), String> {
    let child_slot = checkpoint_block
        .header
        .slot
        .checked_add(1)
        .ok_or_else(|| "checkpoint slot overflow".to_string())?;
    if proof.child_header.slot != child_slot
        || proof.child_header.parent_hash != checkpoint_block.hash()
    {
        return Err(
            "checkpoint canonical proof child does not extend checkpoint block".to_string(),
        );
    }
    let certificate_transaction = certificate.to_transaction()?;
    if !lichen_core::verify_merkle_tx_proof(
        &proof.child_header.tx_root,
        &certificate_transaction.hash(),
        &proof.certificate_merkle_proof,
    ) {
        return Err(
            "checkpoint certificate is not included in canonical child tx root".to_string(),
        );
    }
    let child = Block {
        header: proof.child_header.clone(),
        transactions: Vec::new(),
        tx_fees_paid: Vec::new(),
        oracle_prices: Vec::new(),
        commit_round: proof.child_commit_round,
        commit_signatures: proof.child_commit_signatures.clone(),
    };
    if !child.verify_signature_with_chain_id(chain_id) {
        return Err("checkpoint canonical child producer signature is invalid".to_string());
    }
    CanonicalCommitCertificate::from_committed_block(
        &child,
        proof.child_validator_powers.clone(),
        Hash::hash(b"LICHEN_CHECKPOINT_CHILD_COMMIT_VERIFICATION"),
    )?
    .verify_parent(&child, chain_id, min_validator_stake)?;
    certificate.verify_parent(checkpoint_block, chain_id, min_validator_stake)
}

fn recent_verified_checkpoints(
    ctx: CheckpointVerificationContext<'_>,
    limit: usize,
    manifest_limit: usize,
) -> Vec<VerifiedCheckpointData> {
    if limit == 0 {
        return Vec::new();
    }

    let Ok(finalized_slot) = ctx.state.get_last_finalized_slot() else {
        return Vec::new();
    };
    let checkpoints = StateStore::list_checkpoints(ctx.data_dir);
    let mut verified = Vec::new();

    for (_, path) in checkpoints.into_iter().rev() {
        let meta_path = std::path::Path::new(&path).join("checkpoint_meta.json");
        let Ok(data) = std::fs::read_to_string(&meta_path) else {
            continue;
        };
        let Ok(meta) = serde_json::from_str::<lichen_core::CheckpointMeta>(&data) else {
            continue;
        };

        if meta.slot == 0 || meta.slot > finalized_slot {
            continue;
        }

        let Some(block) = ctx.state.get_block_by_slot(meta.slot).ok().flatten() else {
            continue;
        };
        let checkpoint_store = match StateStore::open_checkpoint(&path) {
            Ok(store) => store,
            Err(err) => {
                warn!(
                    "⚠️  Rejecting checkpoint at slot {}: failed to open checkpoint store: {}",
                    meta.slot, err
                );
                continue;
            }
        };
        if let Err(err) = validate_checkpoint_state_root_read_only(
            &checkpoint_store,
            meta.slot,
            Hash(meta.state_root),
        ) {
            warn!("⚠️  Rejecting checkpoint at slot {}: {}", meta.slot, err);
            continue;
        }
        let (commit_certificate, canonical_proof) = match canonical_checkpoint_certificate(
            ctx.state,
            &block,
            ctx.chain_id,
            ctx.min_validator_stake,
        ) {
            Ok(certificate) => certificate,
            Err(err) => {
                warn!(
                    "⚠️  Rejecting checkpoint at slot {}: commit verification failed: {}",
                    meta.slot, err
                );
                continue;
            }
        };
        if commit_certificate.parent_post_state_root != Hash(meta.state_root) {
            warn!(
                "⚠️  Rejecting checkpoint at slot {}: checkpoint root {} does not match canonical post-state root {}",
                meta.slot,
                hex::encode(meta.state_root),
                commit_certificate.parent_post_state_root.to_hex(),
            );
            continue;
        }
        let snapshot_manifest = if verified.len() < manifest_limit {
            if let Err(err) = validate_snapshot_archive_completeness(&checkpoint_store, meta.slot) {
                warn!("⚠️  Rejecting checkpoint at slot {}: {}", meta.slot, err);
                continue;
            }
            match compute_checkpoint_snapshot_manifest(&checkpoint_store, MAX_SNAPSHOT_CHUNK_SIZE) {
                Ok(manifest) => manifest,
                Err(err) => {
                    warn!(
                        "⚠️  Rejecting checkpoint at slot {}: failed to compute complete checkpoint snapshot manifest: {}",
                        meta.slot, err
                    );
                    continue;
                }
            }
        } else {
            Vec::new()
        };
        if !snapshot_manifest.is_empty() {
            if let Err(err) = validate_advertised_snapshot_manifest_shape(&snapshot_manifest) {
                warn!("⚠️  Rejecting checkpoint at slot {}: {}", meta.slot, err);
                continue;
            }
        }

        verified.push(VerifiedCheckpointData {
            meta,
            checkpoint_path: path,
            block,
            commit_certificate,
            canonical_proof,
            snapshot_manifest,
        });

        if verified.len() >= limit {
            break;
        }
    }

    verified
}

#[derive(Clone, Copy)]
struct CheckpointSnapshotRequestAnchor {
    slot: u64,
    state_root: [u8; 32],
    snapshot_manifest_root: [u8; 32],
}

#[cfg(test)]
fn verified_checkpoint_for_anchor(
    data_dir: &str,
    state: &StateStore,
    chain_id: &str,
    min_validator_stake: u64,
    anchor: CheckpointSnapshotRequestAnchor,
) -> Option<(
    lichen_core::CheckpointMeta,
    String,
    Block,
    &'static [&'static str],
)> {
    let requested_slot = anchor.slot;
    let requested_state_root = anchor.state_root;
    let requested_snapshot_manifest_root = anchor.snapshot_manifest_root;

    if requested_slot == 0
        || requested_state_root == [0u8; 32]
        || requested_snapshot_manifest_root == [0u8; 32]
    {
        return None;
    }

    let finalized_slot = state.get_last_finalized_slot().ok()?;
    if requested_slot > finalized_slot {
        return None;
    }

    let checkpoints = StateStore::list_checkpoints(data_dir);
    for (slot, path) in checkpoints {
        if slot != requested_slot {
            continue;
        }
        let meta_path = std::path::Path::new(&path).join("checkpoint_meta.json");
        let Ok(data) = std::fs::read_to_string(&meta_path) else {
            continue;
        };
        let Ok(meta) = serde_json::from_str::<lichen_core::CheckpointMeta>(&data) else {
            continue;
        };
        if meta.slot != requested_slot || meta.state_root != requested_state_root {
            continue;
        }
        let Some(block) = state.get_block_by_slot(meta.slot).ok().flatten() else {
            continue;
        };
        let checkpoint_store = match StateStore::open_checkpoint(&path) {
            Ok(store) => store,
            Err(err) => {
                warn!(
                    "⚠️  Rejecting requested checkpoint at slot {}: failed to open checkpoint store: {}",
                    meta.slot, err
                );
                continue;
            }
        };
        if let Err(err) = validate_checkpoint_state_root_read_only(
            &checkpoint_store,
            meta.slot,
            Hash(meta.state_root),
        ) {
            warn!(
                "⚠️  Rejecting requested checkpoint at slot {}: {}",
                meta.slot, err
            );
            continue;
        }
        let (certificate, _) =
            match canonical_checkpoint_certificate(state, &block, chain_id, min_validator_stake) {
                Ok(proof) => proof,
                Err(err) => {
                    warn!(
                    "⚠️  Rejecting requested checkpoint at slot {}: commit verification failed: {}",
                    meta.slot, err
                );
                    continue;
                }
            };
        if certificate.parent_post_state_root != Hash(meta.state_root) {
            warn!(
                "⚠️  Rejecting requested checkpoint at slot {}: root is not consensus-committed",
                meta.slot
            );
            continue;
        }
        let manifest_started = Instant::now();
        if let Err(err) = validate_snapshot_archive_completeness(&checkpoint_store, meta.slot) {
            warn!(
                "⚠️  Rejecting requested checkpoint at slot {}: {}",
                meta.slot, err
            );
            continue;
        }
        let snapshot_manifest = match compute_checkpoint_snapshot_manifest(
            &checkpoint_store,
            MAX_SNAPSHOT_CHUNK_SIZE,
        ) {
            Ok(manifest) => manifest,
            Err(err) => {
                warn!(
                        "⚠️  Rejecting requested checkpoint at slot {}: failed to compute complete checkpoint snapshot manifest: {}",
                        meta.slot, err
                    );
                continue;
            }
        };
        if manifest_started.elapsed().as_secs() >= 2 {
            warn!(
                "⚠️  State-repair snapshot manifest authorization for checkpoint slot {} took {}s",
                meta.slot,
                manifest_started.elapsed().as_secs()
            );
        }
        let snapshot_categories = match advertised_snapshot_manifest_categories(&snapshot_manifest)
        {
            Ok(categories) => categories,
            Err(err) => {
                warn!(
                    "⚠️  Rejecting requested checkpoint at slot {}: {}",
                    meta.slot, err
                );
                continue;
            }
        };
        if !snapshot_categories
            .iter()
            .all(|category| WARP_SNAPSHOT_CATEGORIES.contains(category))
        {
            warn!(
                "⚠️  Rejecting requested checkpoint at slot {}: advertised snapshot profile contains unsupported categories",
                meta.slot
            );
            continue;
        }
        let actual_manifest_root = snapshot_manifest_root(&snapshot_manifest);
        if actual_manifest_root != requested_snapshot_manifest_root {
            warn!(
                "⚠️  Rejecting requested checkpoint at slot {}: manifest root mismatch requested={} actual={}",
                meta.slot,
                hex::encode(&requested_snapshot_manifest_root[..8]),
                hex::encode(&actual_manifest_root[..8]),
            );
            continue;
        }
        return Some((meta, path, block, snapshot_categories));
    }

    None
}

async fn latest_verified_checkpoint_cached(
    cache: &mut Option<VerifiedCheckpointCacheEntry>,
    refresh: &mut Option<tokio::task::JoinHandle<Option<VerifiedCheckpointCacheEntry>>>,
    ctx: CheckpointVerificationContext<'_>,
) -> Option<(
    lichen_core::CheckpointMeta,
    String,
    Block,
    Vec<SnapshotCategoryDigest>,
)> {
    if refresh.as_ref().is_some_and(|handle| handle.is_finished()) {
        if let Some(handle) = refresh.take() {
            match handle.await {
                Ok(Some(entry)) => {
                    let latest_slot = entry
                        .checkpoints
                        .first()
                        .map(|checkpoint| checkpoint.meta.slot)
                        .unwrap_or(0);
                    info!(
                        "✅ Refreshed verified checkpoint cache at slot {}",
                        latest_slot
                    );
                    *cache = Some(entry);
                }
                Ok(None) => {
                    debug!("Verified checkpoint cache refresh found no eligible checkpoint");
                    *cache = None;
                }
                Err(err) => {
                    warn!("⚠️  Verified checkpoint cache refresh failed: {}", err);
                }
            }
        }
    }

    if let Some(cached) = cache.as_mut() {
        let removed = cached.prune_unavailable_checkpoints();
        if removed > 0 {
            warn!(
                "⚠️  Pruned {} unavailable checkpoint advertisement(s) from verified cache before serving metadata",
                removed
            );
        }
        if cached.is_empty() {
            *cache = None;
        }
    }

    if let Some(cached) = cache.as_ref() {
        if cached.is_fresh() && cached.has_snapshot_manifest() {
            return Some(cached.checkpoint());
        }
        if refresh.is_some() {
            return Some(cached.checkpoint());
        }
    }

    if refresh.is_none() {
        let data_dir = ctx.data_dir.to_string();
        let state = ctx.state.clone();
        let chain_id = ctx.chain_id.to_string();
        let min_validator_stake = ctx.min_validator_stake;
        let reusable_cache = cache.clone();
        let manifest_limit = if cache
            .as_ref()
            .is_some_and(|entry| !entry.has_snapshot_manifest())
        {
            1
        } else {
            0
        };
        debug!("Refreshing verified checkpoint cache in background");
        *refresh = Some(tokio::task::spawn_blocking(move || {
            let started = Instant::now();
            let ctx = CheckpointVerificationContext {
                data_dir: &data_dir,
                state: &state,
                chain_id: &chain_id,
                min_validator_stake,
            };
            let verified = recent_verified_checkpoints(
                ctx,
                RECENT_VERIFIED_CHECKPOINT_ADVERTISEMENT_LIMIT,
                manifest_limit,
            );
            if started.elapsed().as_secs() >= 2 {
                warn!(
                    "⚠️  Verified checkpoint cache refresh took {}s",
                    started.elapsed().as_secs()
                );
            }
            if verified.is_empty() {
                None
            } else {
                let mut entry = VerifiedCheckpointCacheEntry {
                    checkpoints: verified,
                    verified_at: Instant::now(),
                };
                if let Some(previous) = reusable_cache.as_ref() {
                    entry.reuse_snapshot_manifests_from(previous);
                }
                Some(entry)
            }
        }));
    }

    cache.as_ref().map(VerifiedCheckpointCacheEntry::checkpoint)
}

async fn verified_checkpoint_meta_anchors_cached(
    cache: &mut Option<VerifiedCheckpointCacheEntry>,
    refresh: &mut Option<tokio::task::JoinHandle<Option<VerifiedCheckpointCacheEntry>>>,
    ctx: CheckpointVerificationContext<'_>,
) -> Vec<CheckpointMetaAnchor> {
    let _ = latest_verified_checkpoint_cached(cache, refresh, ctx).await;

    cache
        .as_ref()
        .map(VerifiedCheckpointCacheEntry::checkpoint_anchors)
        .unwrap_or_default()
}

#[cfg(test)]
fn verify_committed_block_authenticity(
    block: &Block,
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
) -> Result<(), String> {
    verify_committed_block_authenticity_with_chain_id(
        block,
        validator_set,
        stake_pool,
        "",
        MIN_VALIDATOR_STAKE,
    )
}

#[cfg(test)]
fn verify_committed_block_authenticity_with_chain_id(
    block: &Block,
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
    chain_id: &str,
    min_validator_stake: u64,
) -> Result<(), String> {
    if block.header.slot == 0 {
        return Ok(());
    }

    if block.commit_signatures.is_empty() {
        return Err(format!(
            "block {} has no commit certificate",
            block.header.slot
        ));
    }

    block.verify_commit_with_chain_id_and_min_stake(
        chain_id,
        validator_set,
        stake_pool,
        min_validator_stake,
    )
}

fn validate_block_payload_commitments(block: &Block) -> Result<(), String> {
    let tx_hashes: Vec<Hash> = block.transactions.iter().map(Transaction::hash).collect();
    let reconstructed_tx_root = lichen_core::merkle_tx_root_from_hashes(&tx_hashes);
    if block.header.tx_root != reconstructed_tx_root {
        return Err(format!(
            "block {} transaction root mismatch: header={} reconstructed={}",
            block.header.slot,
            block.header.tx_root.to_hex(),
            reconstructed_tx_root.to_hex()
        ));
    }

    let consensus_transactions: Vec<_> = block
        .transactions
        .iter()
        .enumerate()
        .filter(|(_, transaction)| transaction.is_consensus())
        .collect();
    if consensus_transactions.len() > 1
        || consensus_transactions
            .first()
            .is_some_and(|(index, _)| *index != 0)
    {
        return Err(format!(
            "block {} has a noncanonical consensus transaction layout",
            block.header.slot
        ));
    }
    if let Some((_, transaction)) = consensus_transactions.first() {
        let certificate = CanonicalCommitCertificate::from_transaction(transaction)?
            .ok_or_else(|| "canonical commit certificate is missing".to_string())?;
        certificate.verify_child_metadata(&block.tx_fees_paid, &block.oracle_prices)?;
    }
    Ok(())
}

fn verify_synced_block_parent_certificate(
    state: &StateStore,
    block: &Block,
    chain_id: &str,
) -> Result<(), String> {
    if block.header.slot <= 1 {
        return Ok(());
    }

    let consensus_transaction = block
        .transactions
        .first()
        .filter(|transaction| transaction.is_consensus());
    let Some(consensus_transaction) = consensus_transaction else {
        if chain_id.to_ascii_lowercase().contains("mainnet") {
            return Err(format!(
                "mainnet block {} has no canonical parent commit transaction",
                block.header.slot
            ));
        }
        return Ok(());
    };

    let parent = state.get_block(&block.header.parent_hash)?.ok_or_else(|| {
        format!(
            "block {} canonical parent {} is unavailable",
            block.header.slot,
            block.header.parent_hash.to_hex()
        )
    })?;
    if parent.header.slot + 1 != block.header.slot {
        return Err(format!(
            "block {} canonical parent has noncontiguous slot {}",
            block.header.slot, parent.header.slot
        ));
    }

    let certificate = CanonicalCommitCertificate::from_transaction(consensus_transaction)?
        .ok_or_else(|| "canonical parent commit transaction is missing".to_string())?;
    certificate.verify_child_metadata(&block.tx_fees_paid, &block.oracle_prices)?;
    certificate.verify_parent(&parent, chain_id, MIN_VALIDATOR_STAKE)?;
    let local_parent_post_state_root = state.compute_state_root();
    if certificate.parent_post_state_root != local_parent_post_state_root {
        return Err(format!(
            "block {} parent post-state root {} does not match local {}",
            block.header.slot,
            certificate.parent_post_state_root.to_hex(),
            local_parent_post_state_root.to_hex(),
        ));
    }
    Ok(())
}

#[cfg(test)]
fn verify_synced_block_consensus_authenticity(
    block: &Block,
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
) -> Result<(), String> {
    let temp_dir = tempfile::tempdir().map_err(|err| err.to_string())?;
    let state = StateStore::open(temp_dir.path())?;
    verify_synced_block_consensus_authenticity_with_chain_id(
        &state,
        block,
        validator_set,
        stake_pool,
        "",
    )
}

fn verify_synced_block_consensus_authenticity_with_chain_id(
    state: &StateStore,
    block: &Block,
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
    chain_id: &str,
) -> Result<(), String> {
    validate_block_payload_commitments(block)?;
    if block.header.slot == 0 {
        return Ok(());
    }

    let proposer = Pubkey(block.header.validator);
    match validator_set.get_validator(&proposer) {
        Some(validator) if !validator.pending_activation => {}
        Some(_) => {
            return Err(format!(
                "block {} proposer {} is pending activation",
                block.header.slot,
                proposer.to_base58()
            ));
        }
        None => {
            return Err(format!(
                "block {} proposer {} is not in the active validator set",
                block.header.slot,
                proposer.to_base58()
            ));
        }
    }

    let activation_slot = if chain_id == "lichen-testnet-1" {
        TESTNET_CHAIN_DOMAIN_ACTIVATION_SLOT
    } else {
        0
    };
    if !block.verify_historical_signature_with_chain_id(chain_id, activation_slot) {
        return Err(format!(
            "block {} producer signature is invalid for chain {}",
            block.header.slot, chain_id
        ));
    }

    if block.commit_signatures.is_empty() {
        return Err(format!(
            "block {} has no commit certificate",
            block.header.slot
        ));
    }
    block.verify_commit_with_chain_id_and_min_stake_for_history(
        chain_id,
        activation_slot,
        validator_set,
        stake_pool,
        MIN_VALIDATOR_STAKE,
    )?;
    verify_synced_block_parent_certificate(state, block, chain_id)
}

struct CheckpointAnchor<'a> {
    slot: u64,
    state_root: [u8; 32],
    checkpoint_header: &'a lichen_core::BlockHeader,
    commit_certificate: &'a CanonicalCommitCertificate,
    canonical_proof: &'a CheckpointCanonicalProof,
    chain_id: &'a str,
}

fn verify_checkpoint_anchor(
    anchor: CheckpointAnchor<'_>,
    min_validator_stake: u64,
) -> Result<(), String> {
    // The child certificate authenticates both finality and the checkpoint's
    // complete post-effects state root before downloaded bytes reach live state.
    let header = anchor.checkpoint_header;
    if header.slot != anchor.slot {
        return Err(format!(
            "checkpoint header slot mismatch: expected {}, got {}",
            anchor.slot, header.slot
        ));
    }
    let block = Block {
        header: header.clone(),
        transactions: Vec::new(),
        tx_fees_paid: Vec::new(),
        oracle_prices: Vec::new(),
        commit_round: 0,
        commit_signatures: Vec::new(),
    };
    if !block.verify_signature_with_chain_id(anchor.chain_id) {
        return Err("checkpoint header signature verification failed".to_string());
    }
    verify_checkpoint_canonical_proof(
        &block,
        anchor.commit_certificate,
        anchor.canonical_proof,
        anchor.chain_id,
        min_validator_stake,
    )?;
    if anchor.commit_certificate.parent_post_state_root != Hash(anchor.state_root) {
        return Err(format!(
            "checkpoint state root {} does not match canonical parent post-state root {}",
            hex::encode(anchor.state_root),
            anchor.commit_certificate.parent_post_state_root.to_hex(),
        ));
    }
    Ok(())
}

#[cfg(test)]
fn verify_block_validators_hash(
    block: &Block,
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
    min_validator_stake: u64,
) -> Result<(), String> {
    if block.header.validators_hash == Hash([0u8; 32]) {
        return Ok(());
    }

    let consensus_set = validator_set.consensus_set();
    let expected = compute_validators_hash(&consensus_set, stake_pool);
    if block.header.validators_hash != expected {
        if let Some(promoted_expected) =
            compute_promoted_pending_validators_hash(validator_set, stake_pool, min_validator_stake)
        {
            if block.header.validators_hash == promoted_expected {
                return Ok(());
            }
        }

        return Err(format!(
            "validators_hash mismatch (block={}, local={})",
            block.header.validators_hash.to_hex(),
            expected.to_hex(),
        ));
    }

    Ok(())
}

#[cfg(test)]
fn compute_promoted_pending_validators_hash(
    validator_set: &ValidatorSet,
    stake_pool: &StakePool,
    min_validator_stake: u64,
) -> Option<Hash> {
    let mut promoted = validator_set.clone();
    let mut changed = false;

    for validator in promoted.validators_mut() {
        if !validator.pending_activation {
            continue;
        }

        let resolved_stake = stake_pool
            .get_stake(&validator.pubkey)
            .map(|stake| stake.total_stake())
            .unwrap_or(validator.stake);

        if resolved_stake >= min_validator_stake {
            validator.stake = resolved_stake;
            validator.pending_activation = false;
            changed = true;
        }
    }

    if !changed {
        return None;
    }

    Some(compute_validators_hash(
        &promoted.consensus_set(),
        stake_pool,
    ))
}

const VALIDATOR_ACTIVATION_WARMUP_SLOTS: u64 = 100;

fn should_add_local_validator_as_pending(
    is_joining_network: bool,
    current_tip: u64,
    stake_start_slot: Option<u64>,
) -> bool {
    if let Some(start_slot) = stake_start_slot {
        if current_tip > start_slot.saturating_add(VALIDATOR_ACTIVATION_WARMUP_SLOTS) {
            return false;
        }
    }

    // A validator discovered after genesis must cross at least one full local
    // height boundary before it can enter the frozen consensus snapshot.
    // This keeps restart and late-discovery behavior aligned across nodes.
    is_joining_network || current_tip > 0
}

fn checkpoint_anchor_support(
    anchors: &HashMap<VerifiedCheckpointAnchorKey, VerifiedCheckpointAnchor>,
    slot: u64,
    state_root: [u8; 32],
) -> usize {
    anchors
        .keys()
        .filter(|key| key.slot == slot && key.state_root == state_root)
        .map(|key| key.source)
        .collect::<HashSet<_>>()
        .len()
}

fn checkpoint_anchor_manifest_support(
    anchors: &HashMap<VerifiedCheckpointAnchorKey, VerifiedCheckpointAnchor>,
    slot: u64,
    state_root: [u8; 32],
    snapshot_manifest_root: [u8; 32],
) -> usize {
    anchors
        .iter()
        .filter(|(key, anchor)| {
            !anchor.snapshot_manifest.is_empty()
                && snapshot_manifest_root != [0u8; 32]
                && key.slot == slot
                && key.state_root == state_root
                && key.snapshot_manifest_root == snapshot_manifest_root
        })
        .map(|(key, _)| key.source)
        .collect::<HashSet<_>>()
        .len()
}

fn checkpoint_snapshot_download_ready(root_support: usize, manifest_support: usize) -> bool {
    root_support >= MIN_WARP_CHECKPOINT_ANCHOR_PEERS && manifest_support > 0
}

fn checkpoint_source_sort_key(source: VerifiedCheckpointSource) -> (u8, [u8; 32]) {
    match source {
        VerifiedCheckpointSource::Validator(pubkey) => (1, pubkey.0),
        VerifiedCheckpointSource::Node(node_id) => (0, node_id),
    }
}

fn remove_checkpoint_anchors_for_source(
    anchors: &mut HashMap<VerifiedCheckpointAnchorKey, VerifiedCheckpointAnchor>,
    peers: &mut HashMap<VerifiedCheckpointAnchorKey, SocketAddr>,
    source: VerifiedCheckpointSource,
    peer_addr: SocketAddr,
) -> usize {
    let before = anchors.len();
    let remove_keys: HashSet<VerifiedCheckpointAnchorKey> = anchors
        .keys()
        .filter(|key| key.source == source || peers.get(key).is_some_and(|addr| *addr == peer_addr))
        .copied()
        .collect();
    anchors.retain(|key, _| !remove_keys.contains(key));
    peers.retain(|key, _| !remove_keys.contains(key));
    before.saturating_sub(anchors.len())
}

fn best_ready_checkpoint_anchor(
    anchors: &HashMap<VerifiedCheckpointAnchorKey, VerifiedCheckpointAnchor>,
    rejected_snapshot_sources: &HashSet<(VerifiedCheckpointSource, u64, [u8; 32])>,
) -> Option<(
    VerifiedCheckpointAnchorKey,
    VerifiedCheckpointAnchor,
    usize,
    usize,
)> {
    anchors
        .iter()
        .filter_map(|(key, anchor)| {
            if anchor.snapshot_manifest.is_empty() {
                return None;
            }
            if rejected_snapshot_sources.contains(&(key.source, key.slot, key.state_root)) {
                return None;
            }
            let support = checkpoint_anchor_support(anchors, key.slot, key.state_root);
            let manifest_support = checkpoint_anchor_manifest_support(
                anchors,
                key.slot,
                key.state_root,
                key.snapshot_manifest_root,
            );
            if !checkpoint_snapshot_download_ready(support, manifest_support) {
                return None;
            }
            Some((*key, anchor.clone(), support, manifest_support))
        })
        .max_by(|left, right| {
            let left_source = checkpoint_source_sort_key(left.0.source);
            let right_source = checkpoint_source_sort_key(right.0.source);
            left.1
                .slot
                .cmp(&right.1.slot)
                .then(left.2.cmp(&right.2))
                .then(left.3.cmp(&right.3))
                .then(
                    left.0
                        .snapshot_manifest_root
                        .cmp(&right.0.snapshot_manifest_root),
                )
                .then(left.0.state_root.cmp(&right.0.state_root))
                .then(left_source.cmp(&right_source))
        })
}

fn same_slot_checkpoint_root_mismatch(
    local_slot: u64,
    checkpoint_slot: u64,
    local_root: Hash,
    checkpoint_root: Hash,
) -> bool {
    checkpoint_slot > 0 && local_slot == checkpoint_slot && local_root != checkpoint_root
}

fn has_replayed_past_checkpoint(state: &StateStore, checkpoint_slot: u64) -> bool {
    checkpoint_slot
        .checked_add(1)
        .and_then(|next_slot| state.get_block_by_slot(next_slot).ok().flatten())
        .is_some()
}

fn checkpoint_root_for_same_slot_repair(
    state: &StateStore,
    local_slot: u64,
    checkpoint_slot: u64,
) -> Option<Hash> {
    if checkpoint_slot > 0
        && local_slot == checkpoint_slot
        && !has_replayed_past_checkpoint(state, checkpoint_slot)
    {
        Some(state.compute_state_root_cold_start())
    } else {
        None
    }
}

fn verified_checkpoint_snapshot_needed(
    local_slot: u64,
    checkpoint_slot: u64,
    local_root: Hash,
    checkpoint_root: Hash,
) -> bool {
    checkpoint_slot > local_slot + 100
        || same_slot_checkpoint_root_mismatch(
            local_slot,
            checkpoint_slot,
            local_root,
            checkpoint_root,
        )
}

fn should_commit_verified_snapshot(
    local_slot: u64,
    snapshot_slot: u64,
    local_root: Hash,
    snapshot_root: Hash,
) -> bool {
    local_slot < snapshot_slot
        || same_slot_checkpoint_root_mismatch(local_slot, snapshot_slot, local_root, snapshot_root)
}

#[derive(Clone)]
struct VerifiedCheckpointAnchor {
    slot: u64,
    state_root: [u8; 32],
    snapshot_manifest: Vec<SnapshotCategoryDigest>,
    snapshot_manifest_root: [u8; 32],
    block: Block,
}

/// Default Binance REST fallback URL.
/// Override via LICHEN_ORACLE_REST_URL (e.g. for Binance US: https://api.binance.us/api/v3/...)
const MICRO_SCALE: f64 = 1_000_000.0;
const DEFAULT_BINANCE_WS_URL: &str =
    "wss://stream.binance.com:9443/ws/solusdt@aggTrade/ethusdt@aggTrade/bnbusdt@aggTrade/neousdt@aggTrade/gasusdt@aggTrade/btcusdt@aggTrade";
const DEFAULT_BINANCE_REST_URL: &str =
    "https://api.binance.com/api/v3/ticker/price?symbols=[%22SOLUSDT%22,%22ETHUSDT%22,%22BNBUSDT%22,%22NEOUSDT%22,%22GASUSDT%22,%22BTCUSDT%22]";

fn reset_24h_stats_if_expired(
    state: &StateStore,
    block_slot: u64,
    block_ts: u64,
) -> Result<(), String> {
    let mut batch = state.begin_batch_at_slot(block_slot);
    let analytics_entry = state.get_symbol_registry("ANALYTICS")?;
    let dex_entry = state.get_symbol_registry("DEX")?;

    if let (Some(analytics_entry), Some(dex_entry)) = (analytics_entry, dex_entry) {
        let analytics_pk = analytics_entry.program;
        let now_ts = block_ts;
        let pair_count = analytics_batch_u64(&batch, &dex_entry.program, b"dex_pair_count")?;
        for pair_id in 1..=pair_count {
            let ts_key = format!("ana_24h_ts_{}", pair_id);
            let last_reset = match batch.get_contract_storage(&analytics_pk, ts_key.as_bytes())? {
                Some(data) if data.len() >= 8 => {
                    u64::from_le_bytes(data[0..8].try_into().unwrap_or([0; 8]))
                }
                _ => 0,
            };

            if last_reset == 0 {
                batch.put_contract_storage(
                    &analytics_pk,
                    ts_key.as_bytes(),
                    &now_ts.to_le_bytes(),
                )?;
                continue;
            }

            if now_ts.saturating_sub(last_reset) < 86400 {
                continue;
            }

            let stats_key = format!("ana_24h_{}", pair_id);
            let current_close =
                match batch.get_contract_storage(&analytics_pk, stats_key.as_bytes())? {
                    Some(data) if data.len() >= 48 => {
                        u64::from_le_bytes(data[32..40].try_into().unwrap_or([0; 8]))
                    }
                    _ => {
                        let lp_key = format!("ana_lp_{}", pair_id);
                        match batch.get_contract_storage(&analytics_pk, lp_key.as_bytes())? {
                            Some(data) if data.len() >= 8 => {
                                u64::from_le_bytes(data[0..8].try_into().unwrap_or([0; 8]))
                            }
                            _ => 0,
                        }
                    }
                };

            let mut stats = Vec::with_capacity(48);
            stats.extend_from_slice(&0u64.to_le_bytes());
            stats.extend_from_slice(&current_close.to_le_bytes());
            stats.extend_from_slice(&current_close.to_le_bytes());
            stats.extend_from_slice(&current_close.to_le_bytes());
            stats.extend_from_slice(&current_close.to_le_bytes());
            stats.extend_from_slice(&0u64.to_le_bytes());
            batch.put_contract_storage(&analytics_pk, stats_key.as_bytes(), &stats)?;

            batch.put_contract_storage(&analytics_pk, ts_key.as_bytes(), &now_ts.to_le_bytes())?;

            debug!("📊 24h stats reset for pair {} (window expired)", pair_id);
        }
    }
    state.commit_batch(batch)
}
/// REST ticker response
#[derive(Deserialize)]
struct BinanceTicker {
    symbol: String,
    price: String,
}

fn env_duration_secs(name: &str, default_secs: u64) -> Duration {
    let secs = env::var(name)
        .ok()
        .and_then(|raw| raw.trim().parse::<u64>().ok())
        .filter(|secs| *secs > 0)
        .unwrap_or(default_secs);
    Duration::from_secs(secs)
}

fn env_u64(name: &str, default: u64) -> u64 {
    env::var(name)
        .ok()
        .and_then(|raw| raw.trim().parse::<u64>().ok())
        .unwrap_or(default)
}

fn price_delta_bps(previous: u64, current: u64) -> u64 {
    if previous == 0 {
        return u64::MAX;
    }
    let delta = previous.abs_diff(current) as u128;
    ((delta * 10_000) / previous as u128) as u64
}

fn should_submit_oracle_attestation(
    last: Option<&(u64, Instant)>,
    price_raw: u64,
    min_interval: Duration,
    max_staleness: Duration,
    min_change_bps: u64,
) -> bool {
    match last {
        None => true,
        Some((last_price, last_at)) => {
            let elapsed = last_at.elapsed();
            elapsed >= max_staleness
                || (elapsed >= min_interval
                    && price_delta_bps(*last_price, price_raw) >= min_change_bps)
        }
    }
}

fn build_oracle_attestation_tx(
    state: &StateStore,
    chain_id: &str,
    validator_seed: &[u8; 32],
    validator_pubkey: Pubkey,
    asset: &str,
    price_raw: u64,
    decimals: u8,
) -> Result<Transaction, String> {
    if price_raw == 0 {
        return Err("oracle attestation price must be > 0".to_string());
    }
    if decimals > 18 {
        return Err("oracle attestation decimals must be 0..=18".to_string());
    }

    let pool = state.get_stake_pool()?;
    let stake_info = pool
        .get_stake(&validator_pubkey)
        .ok_or_else(|| "validator has no stake for oracle attestation".to_string())?;
    if !stake_info.is_active || !stake_info.meets_minimum() {
        return Err("validator is not active for oracle attestation".to_string());
    }

    let tip = state.get_last_slot().unwrap_or(0);
    let recent_blockhash = state
        .get_block_by_slot(tip)?
        .map(|block| block.hash())
        .ok_or_else(|| "oracle attestation requires a recent blockhash".to_string())?;

    let asset_bytes = asset.as_bytes();
    let mut data = Vec::with_capacity(2 + asset_bytes.len() + 8 + 1);
    data.push(30u8);
    data.push(asset_bytes.len() as u8);
    data.extend_from_slice(asset_bytes);
    data.extend_from_slice(&price_raw.to_le_bytes());
    data.push(decimals);

    let ix = lichen_core::Instruction {
        program_id: CORE_SYSTEM_PROGRAM_ID,
        accounts: vec![validator_pubkey],
        data,
    };
    let msg = lichen_core::Message::new(vec![ix], recent_blockhash);
    let mut tx = Transaction::new(msg);
    let kp = Keypair::from_seed(validator_seed);
    tx.signatures
        .push(kp.sign(&tx.message.signing_bytes_for_chain_id(chain_id)));
    Ok(tx)
}

fn is_oracle_attestation_tx_for(tx: &Transaction, validator_pubkey: Pubkey, asset: &str) -> bool {
    let Some(ix) = tx.message.instructions.first() else {
        return false;
    };
    if ix.program_id != CORE_SYSTEM_PROGRAM_ID || ix.accounts.first() != Some(&validator_pubkey) {
        return false;
    }
    let data = &ix.data;
    if data.len() < 2 || data[0] != 30 {
        return false;
    }
    let asset_len = data[1] as usize;
    let expected_len = 2usize
        .saturating_add(asset_len)
        .saturating_add(8)
        .saturating_add(1);
    if data.len() != expected_len {
        return false;
    }
    data.get(2..2 + asset_len) == Some(asset.as_bytes())
}

#[derive(Clone)]
struct OracleFeedTxContext {
    mempool: Arc<Mutex<Mempool>>,
    p2p_peer_manager: Option<Arc<lichen_p2p::PeerManager>>,
    p2p_config: P2PConfig,
    validator_seed: [u8; 32],
    validator_pubkey: Pubkey,
    chain_id: String,
}

async fn submit_oracle_attestation_tx(
    state: &StateStore,
    tx_context: &OracleFeedTxContext,
    asset: &str,
    price_raw: u64,
    decimals: u8,
) -> bool {
    let tx = match build_oracle_attestation_tx(
        state,
        &tx_context.chain_id,
        &tx_context.validator_seed,
        tx_context.validator_pubkey,
        asset,
        price_raw,
        decimals,
    ) {
        Ok(tx) => tx,
        Err(e) => {
            warn!("Skipping oracle attestation for {}: {}", asset, e);
            return false;
        }
    };

    {
        let fee_config = FeeConfig::default_from_constants();
        let computed_fee = TxProcessor::compute_transaction_fee(&tx, &fee_config);
        let mut pool = tx_context.mempool.lock().await;
        let replaced = pool.remove_transactions_matching(|pending| {
            is_oracle_attestation_tx_for(pending, tx_context.validator_pubkey, asset)
        });
        if replaced > 0 {
            debug!(
                "Replaced {} stale oracle attestation tx(s) for {} before enqueueing latest price",
                replaced, asset
            );
        }
        if let Err(e) = pool.add_transaction(tx.clone(), computed_fee, 0) {
            // "already in mempool" is expected when the same price+blockhash
            // produces the same deterministic tx hash between feeder ticks
            if e.contains("already in mempool") {
                debug!(
                    "Oracle attestation tx for {} already in mempool (awaiting block inclusion)",
                    asset
                );
            } else {
                warn!(
                    "Failed to add oracle attestation tx for {} to mempool: {}",
                    asset, e
                );
            }
            return false;
        }
    }

    if let Some(peer_mgr) = &tx_context.p2p_peer_manager {
        let target_id = tx.hash().0;
        let msg = lichen_p2p::P2PMessage::new(
            lichen_p2p::MessageType::Transaction(tx),
            tx_context.p2p_config.listen_addr,
        );
        peer_mgr
            .route_to_closest(&target_id, lichen_p2p::NON_CONSENSUS_FANOUT, msg)
            .await;
    }

    true
}

fn spawn_oracle_price_feeder(
    state: StateStore,
    shared_prices: SharedOraclePrices,
    dex_broadcaster: std::sync::Arc<lichen_rpc::dex_ws::DexEventBroadcaster>,
    tx_context: OracleFeedTxContext,
) {
    tokio::spawn(async move {
        // Configurable Binance endpoints via env vars (for geo-blocked regions)
        let oracle_ws_url: String = std::env::var("LICHEN_ORACLE_WS_URL")
            .unwrap_or_else(|_| DEFAULT_BINANCE_WS_URL.to_string());
        let oracle_rest_url: String = std::env::var("LICHEN_ORACLE_REST_URL")
            .unwrap_or_else(|_| DEFAULT_BINANCE_REST_URL.to_string());
        info!("🔮 Oracle WS: {}", oracle_ws_url);
        info!("🔮 Oracle REST: {}", oracle_rest_url);

        // Use the shared atomics to source validator oracle attestations.
        let wsol_micro = shared_prices.wsol_micro.clone();
        let weth_micro = shared_prices.weth_micro.clone();
        let wbnb_micro = shared_prices.wbnb_micro.clone();
        let wneo_micro = shared_prices.wneo_micro.clone();
        let wgas_micro = shared_prices.wgas_micro.clone();
        let wbtc_micro = shared_prices.wbtc_micro.clone();
        let ws_healthy = shared_prices.ws_healthy.clone();

        // Spawn WebSocket reader task FIRST so prices start flowing immediately
        // even while we wait for ANALYTICS symbol registry (joining node sync).
        let last_ws_update_ms = shared_prices.last_ws_update_ms.clone();
        {
            let ws_prices = shared_prices.clone();
            let ws_url = oracle_ws_url.clone();
            tokio::spawn(async move {
                binance_ws_loop(ws_prices, ws_url).await;
            });
        }

        // Resolve analytics contract pubkey — retry up to 60s for joining nodes
        // that haven't synced the symbol registry yet.
        let analytics_pk = {
            let mut resolved = None;
            for attempt in 0..12 {
                match state.get_symbol_registry("ANALYTICS") {
                    Ok(Some(entry)) => {
                        resolved = Some(entry.program);
                        break;
                    }
                    _ => {
                        if attempt == 0 {
                            info!("🔮 Oracle price feeder: waiting for ANALYTICS symbol registry (joining node sync)...");
                        }
                        tokio::time::sleep(Duration::from_secs(5)).await;
                    }
                }
            }
            match resolved {
                Some(pk) => pk,
                None => {
                    warn!("🔮 Oracle price feeder: ANALYTICS symbol not found after 60s, aborting");
                    return;
                }
            }
        };

        // REST fallback HTTP client (used only when WebSocket is unhealthy)
        let http = reqwest::Client::builder()
            .timeout(Duration::from_secs(5))
            .build()
            .unwrap_or_else(|_| reqwest::Client::new());

        let rest_url = oracle_rest_url.clone();

        info!("🔮 Oracle price feeder started (WebSocket real-time → signed oracle attestations)");

        let candle_intervals: [u64; 9] =
            [60, 300, 900, 3600, 14400, 86400, 259200, 604800, 31536000];
        let mut last_attested: HashMap<&'static str, (u64, Instant)> = HashMap::new();
        let oracle_attestation_min_interval = env_duration_secs("LICHEN_ORACLE_ATTEST_MIN_SECS", 5);
        let oracle_attestation_max_staleness =
            env_duration_secs("LICHEN_ORACLE_ATTEST_MAX_STALENESS_SECS", 15);
        let oracle_attestation_min_change_bps = env_u64("LICHEN_ORACLE_ATTEST_MIN_CHANGE_BPS", 1);
        info!(
            "🔮 Oracle attestation cadence: min={}s max_staleness={}s change={}bps",
            oracle_attestation_min_interval.as_secs(),
            oracle_attestation_max_staleness.as_secs(),
            oracle_attestation_min_change_bps,
        );

        const PRICE_SCALE_F: f64 = 1_000_000_000.0; // 1e9 for DEX price scaling

        // Candle writer loop: 5-second tick (WS broadcasts only — state is
        // written by apply_oracle_from_block during consensus block processing).
        // Oracle feeds + DEX bands + candles are now written deterministically in
        // apply_oracle_from_block() during block effects — NOT here.
        let mut write_tick = time::interval(Duration::from_secs(5));

        loop {
            write_tick.tick().await;

            // Read current prices from atomics
            let mut cur_wsol = wsol_micro.load(Ordering::Relaxed);
            let mut cur_weth = weth_micro.load(Ordering::Relaxed);
            let mut cur_wbnb = wbnb_micro.load(Ordering::Relaxed);
            let mut cur_wneo = wneo_micro.load(Ordering::Relaxed);
            let mut cur_wgas = wgas_micro.load(Ordering::Relaxed);
            let mut cur_wbtc = wbtc_micro.load(Ordering::Relaxed);

            // REST fallback if WebSocket is not healthy, no prices yet,
            // or WS data is stale (no message received within 15 seconds).
            let ws_stale = {
                let last_update = last_ws_update_ms.load(Ordering::Relaxed);
                if last_update == 0 {
                    true // never received a WS message
                } else {
                    let now_ms = std::time::SystemTime::now()
                        .duration_since(std::time::UNIX_EPOCH)
                        .map(|d| d.as_millis() as u64)
                        .unwrap_or(0);
                    now_ms.saturating_sub(last_update) > 15_000
                }
            };
            if !ws_healthy.load(Ordering::Relaxed)
                || ws_stale
                || (cur_wsol == 0
                    && cur_weth == 0
                    && cur_wbnb == 0
                    && cur_wneo == 0
                    && cur_wgas == 0
                    && cur_wbtc == 0)
            {
                if let Ok(resp) = http.get(&rest_url).send().await {
                    if let Ok(tickers) = resp.json::<Vec<BinanceTicker>>().await {
                        for t in &tickers {
                            let p: f64 = t.price.parse().unwrap_or(0.0);
                            if p <= 0.0 {
                                continue;
                            }
                            let micro = (p * MICRO_SCALE) as u64;
                            match t.symbol.as_str() {
                                "SOLUSDT" => {
                                    wsol_micro.store(micro, Ordering::Relaxed);
                                    cur_wsol = micro;
                                }
                                "ETHUSDT" => {
                                    weth_micro.store(micro, Ordering::Relaxed);
                                    cur_weth = micro;
                                }
                                "BNBUSDT" => {
                                    wbnb_micro.store(micro, Ordering::Relaxed);
                                    cur_wbnb = micro;
                                }
                                "NEOUSDT" => {
                                    wneo_micro.store(micro, Ordering::Relaxed);
                                    cur_wneo = micro;
                                }
                                "GASUSDT" => {
                                    wgas_micro.store(micro, Ordering::Relaxed);
                                    cur_wgas = micro;
                                }
                                "BTCUSDT" => {
                                    wbtc_micro.store(micro, Ordering::Relaxed);
                                    cur_wbtc = micro;
                                }
                                _ => {}
                            }
                        }
                    }
                }
            }

            // NOTE: Oracle feed writes, DEX price band writes, candle writes,
            // last-price writes, and 24h stats writes are ALL handled
            // deterministically in apply_oracle_from_block() during block effects.
            // This feeder submits signed native oracle attestation txs and
            // reads consensus-written state to broadcast WS events.

            let (wneo_enabled, wgas_enabled, wbtc_enabled) = wrapped_oracle_assets_enabled(&state);
            let mut attestation_prices = vec![
                ("LICN", GenesisPrices::default().licn_usd_8dec),
                ("wSOL", cur_wsol.saturating_mul(100)),
                ("wETH", cur_weth.saturating_mul(100)),
                ("wBNB", cur_wbnb.saturating_mul(100)),
            ];
            if wneo_enabled {
                attestation_prices.push(("wNEO", cur_wneo.saturating_mul(100)));
            }
            if wgas_enabled {
                attestation_prices.push(("wGAS", cur_wgas.saturating_mul(100)));
            }
            if wbtc_enabled {
                attestation_prices.push(("wBTC", cur_wbtc.saturating_mul(100)));
            }
            for (asset, price_raw) in attestation_prices {
                if price_raw == 0 {
                    continue;
                }
                let should_submit = should_submit_oracle_attestation(
                    last_attested.get(asset),
                    price_raw,
                    oracle_attestation_min_interval,
                    oracle_attestation_max_staleness,
                    oracle_attestation_min_change_bps,
                );
                if !should_submit {
                    continue;
                }
                if submit_oracle_attestation_tx(&state, &tx_context, asset, price_raw, 8).await {
                    last_attested.insert(asset, (price_raw, Instant::now()));
                }
            }

            let wsol_usd = cur_wsol as f64 / MICRO_SCALE;
            let weth_usd = cur_weth as f64 / MICRO_SCALE;
            let wbnb_usd = cur_wbnb as f64 / MICRO_SCALE;
            let wneo_usd = cur_wneo as f64 / MICRO_SCALE;
            let wgas_usd = cur_wgas as f64 / MICRO_SCALE;
            let wbtc_usd = cur_wbtc as f64 / MICRO_SCALE;

            if wsol_usd <= 0.0
                && weth_usd <= 0.0
                && wbnb_usd <= 0.0
                && wneo_usd <= 0.0
                && wgas_usd <= 0.0
                && wbtc_usd <= 0.0
            {
                continue;
            }

            // WS broadcasts — read consensus state and emit to WebSocket clients
            let current_slot = state.get_last_slot().unwrap_or(0);

            let licn_usd: f64 = lichen_core::consensus::licn_price_from_state(&state);
            let pair_prices = oracle_pair_prices(
                OraclePairPriceInputs {
                    licn_usd,
                    wsol_usd,
                    weth_usd,
                    wbnb_usd,
                    wneo_usd,
                    wgas_usd,
                    wbtc_usd,
                },
                wneo_enabled,
                wgas_enabled,
                wbtc_enabled,
            );

            for (pair_id, price_f64) in &pair_prices {
                if *price_f64 <= 0.0 {
                    continue;
                }

                // ── WS broadcast: read consensus-written state and emit ──
                // Candles, last price, and 24h stats are written deterministically
                // by apply_oracle_from_block() during block processing. This feeder
                // only READS that data and broadcasts it via WebSocket.

                // Read 24h stats written by consensus
                let stats_key = format!("ana_24h_{}", pair_id);
                let stats = match state.get_contract_storage(&analytics_pk, stats_key.as_bytes()) {
                    Ok(Some(d)) if d.len() >= 48 => d,
                    _ => vec![0u8; 48],
                };

                // ── WS broadcast: ticker update for this pair ──
                let volume_24h = u64::from_le_bytes(stats[0..8].try_into().unwrap_or([0; 8]));
                let open_raw = u64::from_le_bytes(stats[24..32].try_into().unwrap_or([0; 8]));
                let open_f = open_raw as f64 / PRICE_SCALE_F;
                let change_24h = if open_f > 0.0 {
                    ((*price_f64 - open_f) / open_f) * 100.0
                } else {
                    0.0
                };
                dex_broadcaster.emit_ticker(
                    *pair_id, *price_f64, *price_f64, *price_f64, volume_24h, change_24h,
                );

                // ── WS broadcast: candle updates for all intervals ──
                // Read consensus-written candles and broadcast via WebSocket
                for &ci in &candle_intervals {
                    let count_key_c = format!("ana_cc_{}_{}", pair_id, ci);
                    let candle_count_c: u64 =
                        match state.get_contract_storage(&analytics_pk, count_key_c.as_bytes()) {
                            Ok(Some(d)) if d.len() >= 8 => {
                                u64::from_le_bytes(d[0..8].try_into().unwrap_or([0; 8]))
                            }
                            _ => 0,
                        };
                    if candle_count_c > 0 {
                        let sequence = candle_count_c - 1;
                        let idx_c = analytics_candle_storage_index(sequence, ci);
                        let ck = format!("ana_c_{}_{}_{}", pair_id, ci, idx_c);
                        if let Ok(Some(cd)) =
                            state.get_contract_storage(&analytics_pk, ck.as_bytes())
                        {
                            if cd.len() >= 48 {
                                let o = u64::from_le_bytes(cd[0..8].try_into().unwrap_or([0; 8]))
                                    as f64
                                    / PRICE_SCALE_F;
                                let h = u64::from_le_bytes(cd[8..16].try_into().unwrap_or([0; 8]))
                                    as f64
                                    / PRICE_SCALE_F;
                                let l = u64::from_le_bytes(cd[16..24].try_into().unwrap_or([0; 8]))
                                    as f64
                                    / PRICE_SCALE_F;
                                let c = u64::from_le_bytes(cd[24..32].try_into().unwrap_or([0; 8]))
                                    as f64
                                    / PRICE_SCALE_F;
                                let v = u64::from_le_bytes(cd[32..40].try_into().unwrap_or([0; 8]));
                                dex_broadcaster.emit_candle(
                                    *pair_id,
                                    ci,
                                    o,
                                    h,
                                    l,
                                    c,
                                    v,
                                    current_slot,
                                );
                            }
                        }
                    }
                }
            }

            debug!(
                "🔮 Oracle candles updated: wSOL=${:.2} wETH=${:.2} wBNB=${:.2} wNEO=${:.2} wGAS=${:.2} wBTC=${:.2}",
                wsol_usd, weth_usd, wbnb_usd, wneo_usd, wgas_usd, wbtc_usd
            );
        }
    });
}

/// Binance WebSocket reader loop with auto-reconnect.
/// Connects to aggTrade streams, parses prices, stores in atomics.
/// On disconnect, retries with exponential backoff (1s → 30s max).
async fn binance_ws_loop(prices: SharedOraclePrices, ws_url: String) {
    let mut backoff_secs: u64 = 1;

    // Read timeout: if no WS message arrives within this window,
    // treat the connection as dead and reconnect.  Binance aggTrade
    // streams for SOL/ETH/BNB/NEO/GAS/BTC produce messages during
    // active trading.  30s silence is a clear signal of a stale
    // connection (TCP half-open, silent Binance-side close, etc.).
    const WS_READ_TIMEOUT: Duration = Duration::from_secs(30);

    loop {
        info!("🔮 Binance WebSocket connecting to {}...", ws_url);
        prices.ws_healthy.store(false, Ordering::Relaxed);

        match tokio_tungstenite::connect_async(ws_url.as_str()).await {
            Ok((ws_stream, _)) => {
                info!("🔮 Binance WebSocket connected (real-time aggTrade feed)");
                backoff_secs = 1; // reset backoff on successful connect
                prices.ws_healthy.store(true, Ordering::Relaxed);

                let (mut write, mut read) = ws_stream.split();

                loop {
                    let msg_result = match tokio::time::timeout(WS_READ_TIMEOUT, read.next()).await
                    {
                        Ok(Some(msg)) => msg,
                        Ok(None) => {
                            // Stream ended
                            break;
                        }
                        Err(_) => {
                            warn!("🔮 Binance WebSocket read timeout ({}s with no data), reconnecting", WS_READ_TIMEOUT.as_secs());
                            break;
                        }
                    };
                    match msg_result {
                        Ok(tungstenite::Message::Text(ref text)) => {
                            // Record that we received a message (for feeder staleness check)
                            let now_ms = std::time::SystemTime::now()
                                .duration_since(std::time::UNIX_EPOCH)
                                .map(|d| d.as_millis() as u64)
                                .unwrap_or(0);
                            prices.last_ws_update_ms.store(now_ms, Ordering::Relaxed);

                            // aggTrade format: {"e":"aggTrade","s":"SOLUSDT","p":"82.30",...}
                            if let Ok(trade) = serde_json::from_str::<serde_json::Value>(text) {
                                if let (Some(sym), Some(price_str)) =
                                    (trade["s"].as_str(), trade["p"].as_str())
                                {
                                    let price: f64 = price_str.parse().unwrap_or(0.0);
                                    if price > 0.0 {
                                        let micro = (price * MICRO_SCALE) as u64;
                                        match sym {
                                            "SOLUSDT" => {
                                                prices.wsol_micro.store(micro, Ordering::Relaxed)
                                            }
                                            "ETHUSDT" => {
                                                prices.weth_micro.store(micro, Ordering::Relaxed)
                                            }
                                            "BNBUSDT" => {
                                                prices.wbnb_micro.store(micro, Ordering::Relaxed)
                                            }
                                            "NEOUSDT" => {
                                                prices.wneo_micro.store(micro, Ordering::Relaxed)
                                            }
                                            "GASUSDT" => {
                                                prices.wgas_micro.store(micro, Ordering::Relaxed)
                                            }
                                            "BTCUSDT" => {
                                                prices.wbtc_micro.store(micro, Ordering::Relaxed)
                                            }
                                            _ => {}
                                        }
                                    }
                                }
                            }
                        }
                        Ok(tungstenite::Message::Ping(data))
                            if write
                                .send(tungstenite::Message::Pong(data.clone()))
                                .await
                                .is_err() =>
                        {
                            warn!("🔮 Binance WebSocket pong send failed");
                            break;
                        }
                        Ok(tungstenite::Message::Ping(_)) => {}
                        Ok(tungstenite::Message::Close(_)) => {
                            info!("🔮 Binance WebSocket closed by server");
                            break;
                        }
                        Err(e) => {
                            warn!("🔮 Binance WebSocket read error: {}", e);
                            break;
                        }
                        _ => {} // Binary, Pong, Frame — ignore
                    }
                }

                prices.ws_healthy.store(false, Ordering::Relaxed);
                warn!("🔮 Binance WebSocket disconnected, reconnecting...");
            }
            Err(e) => {
                warn!("🔮 Binance WebSocket connect failed: {}", e);
            }
        }

        // Exponential backoff: 1 → 2 → 4 → 8 → 16 → 30 (capped)
        let delay = backoff_secs.min(30);
        tokio::time::sleep(Duration::from_secs(delay)).await;
        backoff_secs = (backoff_secs * 2).min(60);
    }
}

/// Update a single candle for an oracle-priced pair.
/// Mirrors the logic in dex_analytics `update_candle` inside the caller's
/// atomic post-block batch.
fn oracle_update_candle(
    batch: &mut StateBatch,
    analytics_pk: &Pubkey,
    pair_id: u64,
    interval: u64,
    price: u64,
    unix_ts: u64,
) -> Result<(), String> {
    // Use unix timestamp (not slot) for period grouping so candle boundaries
    // align with wall-clock seconds (60s, 300s, 3600s, etc.).
    let candle_start = (unix_ts / interval) * interval;

    // Read current candle's start timestamp (use Option to distinguish missing from 0).
    let cur_key = format!("ana_cur_{}_{}", pair_id, interval);
    let stored_start = match batch.get_contract_storage(analytics_pk, cur_key.as_bytes())? {
        Some(d) if d.len() >= 8 => Some(u64::from_le_bytes(d[0..8].try_into().unwrap_or([0; 8]))),
        _ => None,
    };

    let count_key = format!("ana_cc_{}_{}", pair_id, interval);

    if stored_start == Some(candle_start) {
        // Same candle period — update OHLC in-place
        let candle_count = analytics_batch_u64(batch, analytics_pk, count_key.as_bytes())?;
        if candle_count == 0 {
            return Err(format!(
                "oracle candle current-period marker exists without a candle count for pair {} interval {}",
                pair_id, interval
            ));
        }
        let sequence = candle_count - 1;
        let idx = analytics_candle_storage_index(sequence, interval);
        let candle_key = format!("ana_c_{}_{}_{}", pair_id, interval, idx);

        let mut data = batch
            .get_contract_storage(analytics_pk, candle_key.as_bytes())?
            .ok_or_else(|| {
                format!(
                    "oracle candle count references missing candle for pair {} interval {} sequence {}",
                    pair_id, interval, sequence
                )
            })?;
        if data.len() < 48 {
            return Err(format!(
                "oracle candle is truncated for pair {} interval {} sequence {}",
                pair_id, interval, sequence
            ));
        }
        let high = u64::from_le_bytes(data[8..16].try_into().unwrap_or([0; 8]));
        let low = u64::from_le_bytes(data[16..24].try_into().unwrap_or([0; 8]));
        if price > high {
            data[8..16].copy_from_slice(&price.to_le_bytes());
        }
        if price < low {
            data[16..24].copy_from_slice(&price.to_le_bytes());
        }
        data[24..32].copy_from_slice(&price.to_le_bytes());
        batch.put_contract_storage(analytics_pk, candle_key.as_bytes(), &data)?;
    } else {
        // New candle period — create a new candle
        let candle_count = analytics_batch_u64(batch, analytics_pk, count_key.as_bytes())?;

        // Build new candle: open(8)+high(8)+low(8)+close(8)+volume(8)+timestamp(8) = 48
        let mut candle = Vec::with_capacity(48);
        candle.extend_from_slice(&price.to_le_bytes()); // open
        candle.extend_from_slice(&price.to_le_bytes()); // high
        candle.extend_from_slice(&price.to_le_bytes()); // low
        candle.extend_from_slice(&price.to_le_bytes()); // close
        candle.extend_from_slice(&0u64.to_le_bytes()); // volume (oracle updates have 0 volume)
        candle.extend_from_slice(&candle_start.to_le_bytes()); // period-start time (aligned)

        let new_idx = analytics_candle_storage_index(candle_count, interval);
        let candle_key = format!("ana_c_{}_{}_{}", pair_id, interval, new_idx);
        batch.put_contract_storage(analytics_pk, candle_key.as_bytes(), &candle)?;

        // Update count
        batch.put_contract_storage(
            analytics_pk,
            count_key.as_bytes(),
            &candle_count.saturating_add(1).to_le_bytes(),
        )?;

        // Store current candle start timestamp.
        batch.put_contract_storage(
            analytics_pk,
            cur_key.as_bytes(),
            &candle_start.to_le_bytes(),
        )?;
    }
    Ok(())
}

// ═══════════════════════════════════════════════════════════════════════
//  LOG MANAGEMENT — background task that prunes old daily log files.
//  Runs immediately on spawn then every 6 hours while the validator is alive.
// ═══════════════════════════════════════════════════════════════════════

/// Spawn a background task that periodically removes log files older than
/// `max_age_days` from `log_dir`.  Targets files matching the
/// `validator.log.YYYY-MM-DD` pattern produced by
/// `tracing_appender::rolling::daily`.
fn spawn_log_cleanup_task(log_dir: PathBuf, max_age_days: u64) {
    tokio::spawn(async move {
        let sweep_interval = tokio::time::Duration::from_secs(3 * 3600); // 3 hours
        loop {
            let cutoff =
                std::time::SystemTime::now() - std::time::Duration::from_secs(max_age_days * 86400);
            if let Ok(entries) = fs::read_dir(&log_dir) {
                for entry in entries.flatten() {
                    let path = entry.path();
                    let name = match path.file_name().and_then(|n| n.to_str()) {
                        Some(n) => n.to_string(),
                        None => continue,
                    };
                    if !name.starts_with("validator.log.") {
                        continue;
                    }
                    if let Ok(meta) = fs::metadata(&path) {
                        if let Ok(modified) = meta.modified() {
                            if modified < cutoff {
                                match fs::remove_file(&path) {
                                    Ok(_) => info!("🗑️  Removed old log file: {}", name),
                                    Err(e) => warn!("Failed to remove old log {}: {}", name, e),
                                }
                            }
                        }
                    }
                }
            }
            tokio::time::sleep(sweep_interval).await;
        }
    });
}

fn spawn_governed_proposal_tx_index_backfill_task(state: StateStore) {
    if env_flag_enabled("LICHEN_DISABLE_BACKGROUND_HISTORY_REPAIR") {
        info!("🧾 Background history repair disabled via LICHEN_DISABLE_BACKGROUND_HISTORY_REPAIR");
        return;
    }

    tokio::spawn(async move {
        time::sleep(Duration::from_secs(
            BACKGROUND_HISTORY_REPAIR_START_DELAY_SECS,
        ))
        .await;

        let started = Instant::now();
        let result = tokio::task::spawn_blocking(move || {
            state.backfill_governed_proposal_tx_index_throttled(
                false,
                GOVERNED_TX_BACKFILL_THROTTLE_EVERY_ROWS,
                Duration::from_millis(GOVERNED_TX_BACKFILL_THROTTLE_SLEEP_MS),
            )
        })
        .await;

        match result {
            Ok(Ok(report)) => {
                let elapsed_ms = started.elapsed().as_millis();
                if report.linked > 0 || report.existing_links > 0 || report.proposal_txs > 0 {
                    info!(
                        "🧾 Governed proposal tx index repair completed in {}ms: rows={}, proposal_txs={}, existing_links={}, linked={}",
                        elapsed_ms,
                        report.tx_by_slot_rows,
                        report.proposal_txs,
                        report.existing_links,
                        report.linked
                    );
                } else {
                    debug!(
                        "🧾 Governed proposal tx index repair found no proposal txs (rows={}, {}ms)",
                        report.tx_by_slot_rows, elapsed_ms
                    );
                }
                if report.missing_transactions > 0 || report.unresolved > 0 {
                    warn!(
                        "🧾 Governed proposal tx index repair source incomplete: missing_transactions={}, unresolved={}, first_unresolved_tx={}",
                        report.missing_transactions,
                        report.unresolved,
                        report.first_unresolved_tx.as_deref().unwrap_or("none")
                    );
                }
            }
            Ok(Err(err)) => {
                warn!("🧾 Governed proposal tx index repair failed: {}", err);
            }
            Err(err) => {
                warn!("🧾 Governed proposal tx index repair task failed: {}", err);
            }
        }
    });
}

// ═══════════════════════════════════════════════════════════════════════
//  CLI ARGUMENT HELPERS — support both `--flag value` and `--flag=value`
// ═══════════════════════════════════════════════════════════════════════

/// Find the value for a CLI flag, supporting both `--flag value` and `--flag=value`.
/// Pass the canonical spelling for each accepted flag.
fn get_flag_value<'a>(args: &'a [String], names: &[&str]) -> Option<&'a str> {
    for (i, arg) in args.iter().enumerate() {
        for name in names {
            if arg == *name {
                // --flag value
                return args.get(i + 1).map(|s| s.as_str());
            }
            if let Some(val) = arg.strip_prefix(&format!("{}=", name)) {
                // --flag=value
                return Some(val);
            }
        }
    }
    None
}

/// Check if a boolean flag is present, supporting `--flag` and `--flag=true`.
fn has_flag(args: &[String], name: &str) -> bool {
    args.iter()
        .any(|a| a == name || a.starts_with(&format!("{}=", name)))
}

fn is_version_request(args: &[String]) -> bool {
    args.iter()
        .skip(1)
        .any(|arg| matches!(arg.as_str(), "--version" | "-V"))
}

#[derive(Debug, Clone, Copy)]
struct RestrictionSchemaReport {
    before_schema: Option<bool>,
    after_schema: Option<bool>,
    before_root: Hash,
    after_root: Hash,
    legacy_root: Hash,
    restriction_root: Hash,
    last_slot: u64,
    has_genesis_block: bool,
    changed: bool,
}

fn restriction_schema_label(schema: Option<bool>) -> &'static str {
    match schema {
        Some(true) => "active",
        Some(false) => "legacy",
        None => "legacy_unset",
    }
}

fn restriction_schema_data_dir(args: &[String]) -> PathBuf {
    let p2p_port = get_flag_value(args, &["--p2p-port"])
        .and_then(|s| s.parse::<u16>().ok())
        .unwrap_or(7001);
    let network_arg = get_flag_value(args, &["--network"]).map(|s| s.to_lowercase());
    let data_dir = get_flag_value(args, &["--db-path"])
        .map(|s| s.to_string())
        .unwrap_or_else(|| {
            if let Some(net) = network_arg {
                format!("./data/state-{}", net)
            } else {
                format!("./data/state-{}", p2p_port)
            }
        });

    let path = PathBuf::from(data_dir);
    if path.is_absolute() {
        path
    } else {
        std::env::current_dir()
            .unwrap_or_else(|_| PathBuf::from("."))
            .join(path)
    }
}

fn build_restriction_schema_report(
    state: &StateStore,
    before_schema: Option<bool>,
    before_root: Hash,
    changed: bool,
) -> RestrictionSchemaReport {
    RestrictionSchemaReport {
        before_schema,
        after_schema: state.get_state_root_schema(),
        before_root,
        after_root: state.compute_state_root_cold_start(),
        legacy_root: state.compute_state_root_without_restrictions_cold_start(),
        restriction_root: state.compute_state_root_with_restrictions_cold_start(),
        last_slot: state.get_last_slot().unwrap_or(0),
        has_genesis_block: state.get_block_by_slot(0).unwrap_or(None).is_some(),
        changed,
    }
}

fn activate_restriction_schema_for_state(
    state: &StateStore,
    network: &str,
) -> Result<RestrictionSchemaReport, String> {
    if network != "testnet" {
        return Err(format!(
            "Refusing restriction state-root schema activation on '{}'; RG-804 allows testnet only",
            network
        ));
    }

    let before_schema = state.get_state_root_schema();
    let before_root = state.compute_state_root_cold_start();
    if state.get_block_by_slot(0)?.is_none() {
        return Err(
            "Refusing restriction state-root schema activation: local state has no stored slot-0 genesis block"
                .to_string(),
        );
    }

    let changed = before_schema != Some(true);
    if changed {
        state.set_state_root_schema(true)?;
    }

    let report = build_restriction_schema_report(state, before_schema, before_root, changed);
    if report.after_schema != Some(true) {
        return Err("Restriction state-root schema activation did not persist".to_string());
    }
    if report.after_root != report.restriction_root {
        return Err(format!(
            "Restriction state-root schema activation verification failed: after_root={} restricted_root={}",
            report.after_root.to_hex(),
            report.restriction_root.to_hex()
        ));
    }

    Ok(report)
}

fn print_restriction_schema_report(data_dir: &Path, report: &RestrictionSchemaReport) {
    println!("data_dir={}", data_dir.display());
    println!(
        "before_schema={}",
        restriction_schema_label(report.before_schema)
    );
    println!(
        "after_schema={}",
        restriction_schema_label(report.after_schema)
    );
    println!("changed={}", report.changed);
    println!("last_slot={}", report.last_slot);
    println!("has_genesis_block={}", report.has_genesis_block);
    println!("before_state_root={}", report.before_root.to_hex());
    println!("after_state_root={}", report.after_root.to_hex());
    println!("legacy_state_root={}", report.legacy_root.to_hex());
    println!(
        "restriction_state_root={}",
        report.restriction_root.to_hex()
    );
}

fn maybe_run_restriction_schema_admin(args: &[String]) -> Option<i32> {
    let activate = has_flag(args, ACTIVATE_RESTRICTION_SCHEMA_FLAG);
    let show = has_flag(args, SHOW_RESTRICTION_SCHEMA_FLAG);
    if !activate && !show {
        return None;
    }
    if activate && show {
        eprintln!(
            "{} and {} are mutually exclusive",
            ACTIVATE_RESTRICTION_SCHEMA_FLAG, SHOW_RESTRICTION_SCHEMA_FLAG
        );
        return Some(2);
    }

    let network = get_flag_value(args, &["--network"])
        .map(|s| s.to_lowercase())
        .unwrap_or_else(|| "testnet".to_string());
    let data_dir = restriction_schema_data_dir(args);
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let state = match StateStore::open_with_cache_mb(&data_dir, cache_size_mb) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("Failed to open state DB at {}: {}", data_dir.display(), err);
            return Some(1);
        }
    };

    let result = if activate {
        activate_restriction_schema_for_state(&state, &network)
    } else {
        let before_schema = state.get_state_root_schema();
        let before_root = state.compute_state_root_cold_start();
        Ok(build_restriction_schema_report(
            &state,
            before_schema,
            before_root,
            false,
        ))
    };

    match result {
        Ok(report) => {
            print_restriction_schema_report(&data_dir, &report);
            Some(0)
        }
        Err(err) => {
            eprintln!("{}", err);
            Some(1)
        }
    }
}

