fn maybe_run_sparse_state_commitment_admin(args: &[String]) -> Option<i32> {
    let rebuild = has_flag(args, REBUILD_SPARSE_STATE_COMMITMENT_FLAG);
    let activate = has_flag(args, ACTIVATE_SPARSE_STATE_COMMITMENT_FLAG);
    let activate_shielded = has_flag(args, ACTIVATE_SHIELDED_STATE_COMMITMENT_FLAG);
    let show = has_flag(args, SHOW_STATE_COMMITMENT_SCHEMA_FLAG);
    if !rebuild && !activate && !activate_shielded && !show {
        return None;
    }
    if show && (rebuild || activate || activate_shielded) {
        eprintln!(
            "{} cannot be combined with {}, {}, or {}",
            SHOW_STATE_COMMITMENT_SCHEMA_FLAG,
            REBUILD_SPARSE_STATE_COMMITMENT_FLAG,
            ACTIVATE_SPARSE_STATE_COMMITMENT_FLAG,
            ACTIVATE_SHIELDED_STATE_COMMITMENT_FLAG
        );
        return Some(2);
    }
    if activate && activate_shielded {
        eprintln!(
            "{} and {} are mutually exclusive",
            ACTIVATE_SPARSE_STATE_COMMITMENT_FLAG, ACTIVATE_SHIELDED_STATE_COMMITMENT_FLAG
        );
        return Some(2);
    }
    if activate {
        let confirm = get_flag_value(args, &["--confirm"]);
        if confirm != Some(SPARSE_STATE_COMMITMENT_CONFIRMATION) {
            eprintln!(
                "Refusing activation without --confirm {SPARSE_STATE_COMMITMENT_CONFIRMATION}"
            );
            return Some(1);
        }
    }
    if activate_shielded {
        let confirm = get_flag_value(args, &["--confirm"]);
        if confirm != Some(SHIELDED_STATE_COMMITMENT_CONFIRMATION) {
            eprintln!(
                "Refusing activation without --confirm {SHIELDED_STATE_COMMITMENT_CONFIRMATION}"
            );
            return Some(1);
        }
    }

    let data_dir = restriction_schema_data_dir(args);
    let secondary_dir = get_flag_value(args, &["--secondary-dir"]).map(PathBuf::from);
    if secondary_dir.is_some() && !show {
        eprintln!("--secondary-dir is allowed only with {SHOW_STATE_COMMITMENT_SCHEMA_FLAG}");
        return Some(2);
    }
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let state = match secondary_dir.as_ref() {
        Some(path) => StateStore::open_secondary_with_cache_mb(&data_dir, path, cache_size_mb),
        None if show => StateStore::open_read_only_with_cache_mb(&data_dir, cache_size_mb),
        None => StateStore::open_with_cache_mb(&data_dir, cache_size_mb),
    };
    let state = match state {
        Ok(state) => state,
        Err(err) => {
            eprintln!("Failed to open state DB at {}: {}", data_dir.display(), err);
            return Some(1);
        }
    };
    if secondary_dir.is_some() {
        if let Err(err) = state.try_catch_up_with_primary() {
            eprintln!("{err}");
            return Some(1);
        }
    }

    let result = if show {
        state.verify_sparse_state_commitment()
    } else if activate_shielded {
        state.activate_shielded_state_commitment()
    } else {
        state.rebuild_sparse_state_commitment(activate)
    };

    match result {
        Ok(report) => {
            if let Some(path) = &secondary_dir {
                println!("secondary_dir={}", path.display());
            }
            print_sparse_state_commitment_report(
                &data_dir,
                &report,
                state.is_sparse_state_commitment_ready(),
            );
            Some(0)
        }
        Err(err) => {
            eprintln!("{}", err);
            Some(1)
        }
    }
}

#[derive(Debug, Clone)]
struct DexRepairReport {
    symbol: String,
    program: Pubkey,
    changed: bool,
    code_changed: bool,
    abi_changed: bool,
    before_hash: String,
    after_hash: String,
    before_version: u32,
    after_version: u32,
    owner: Pubkey,
    abi_loaded: bool,
}

fn testnet_dex_repair_wasm_path(contracts_dir: &Path, dir_name: &str) -> PathBuf {
    contracts_dir
        .join(dir_name)
        .join(format!("{dir_name}.wasm"))
}

fn testnet_dex_repair_abi_path(contracts_dir: &Path, dir_name: &str) -> PathBuf {
    contracts_dir.join(dir_name).join("abi.json")
}

fn read_testnet_dex_repair_abi(path: &Path) -> Result<Option<ContractAbi>, String> {
    if !path.exists() {
        return Ok(None);
    }
    let bytes = fs::read(path).map_err(|err| format!("read {}: {err}", path.display()))?;
    serde_json::from_slice(&bytes)
        .map(Some)
        .map_err(|err| format!("decode {}: {err}", path.display()))
}

fn testnet_dex_repair_abi_changed(
    existing: &Option<ContractAbi>,
    candidate: &Option<ContractAbi>,
) -> bool {
    let Some(candidate) = candidate else {
        return false;
    };
    match existing {
        Some(existing) => serde_json::to_vec(existing).ok() != serde_json::to_vec(candidate).ok(),
        None => true,
    }
}

fn repair_testnet_dex_contract(
    state: &StateStore,
    contracts_dir: &Path,
    symbol: &str,
    dir_name: &str,
    dry_run: bool,
) -> Result<DexRepairReport, String> {
    let registry = state
        .get_symbol_registry(symbol)?
        .ok_or_else(|| format!("{symbol}: symbol not found"))?;
    let program = registry.program;
    let mut account: Account = state.get_account(&program)?.ok_or_else(|| {
        format!(
            "{symbol}: contract account {} not found",
            program.to_base58()
        )
    })?;
    if !account.executable {
        return Err(format!(
            "{symbol}: {} is not executable",
            program.to_base58()
        ));
    }

    let mut contract: ContractAccount = serde_json::from_slice(&account.data)
        .map_err(|err| format!("{symbol}: decode contract account: {err}"))?;
    let before_hash = contract.code_hash;
    let before_version = contract.version;
    let wasm = fs::read(testnet_dex_repair_wasm_path(contracts_dir, dir_name))
        .map_err(|err| format!("{symbol}: read {dir_name}.wasm: {err}"))?;
    let after_hash = Hash::hash(&wasm);
    let abi = read_testnet_dex_repair_abi(&testnet_dex_repair_abi_path(contracts_dir, dir_name))?;
    let code_changed = before_hash != after_hash;
    let abi_changed = testnet_dex_repair_abi_changed(&contract.abi, &abi);
    let changed = code_changed || abi_changed;

    if changed && !dry_run {
        if code_changed {
            contract.previous_code_hash = Some(before_hash);
            contract.code = wasm;
            contract.code_hash = after_hash;
            contract.version = contract.version.saturating_add(1);
            contract.pending_upgrade = None;
        }
        if let Some(abi) = abi.clone() {
            contract.abi = Some(abi);
        }
        account.data = serde_json::to_vec(&contract)
            .map_err(|err| format!("{symbol}: encode repaired contract: {err}"))?;
        state.put_account(&program, &account)?;
    }

    Ok(DexRepairReport {
        symbol: symbol.to_string(),
        program,
        changed,
        code_changed,
        abi_changed,
        before_hash: before_hash.to_hex(),
        after_hash: after_hash.to_hex(),
        before_version,
        after_version: if code_changed && !dry_run {
            before_version.saturating_add(1)
        } else {
            before_version
        },
        owner: contract.owner,
        abi_loaded: abi.is_some(),
    })
}

fn print_testnet_dex_repair_reports(reports: &[DexRepairReport], dry_run: bool, data_dir: &Path) {
    println!("data_dir={}", data_dir.display());
    println!("mode={}", if dry_run { "dry-run" } else { "write" });
    println!("contracts={}", reports.len());
    println!(
        "changed={}",
        reports.iter().filter(|report| report.changed).count()
    );
    for report in reports {
        let mut fields = BTreeMap::new();
        fields.insert("symbol", report.symbol.clone());
        fields.insert("program", report.program.to_base58());
        fields.insert("changed", report.changed.to_string());
        fields.insert("code_changed", report.code_changed.to_string());
        fields.insert("abi_changed", report.abi_changed.to_string());
        fields.insert("owner", report.owner.to_base58());
        fields.insert("before_hash", report.before_hash.clone());
        fields.insert("after_hash", report.after_hash.clone());
        fields.insert("before_version", report.before_version.to_string());
        fields.insert("after_version", report.after_version.to_string());
        fields.insert("abi_loaded", report.abi_loaded.to_string());
        println!(
            "{}",
            fields
                .iter()
                .map(|(key, value)| format!("{key}={value}"))
                .collect::<Vec<_>>()
                .join(" ")
        );
    }
}

fn maybe_run_testnet_dex_repair_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, REPAIR_TESTNET_DEX_CONTRACTS_FLAG) {
        return None;
    }

    let network = get_flag_value(args, &["--network"])
        .map(|s| s.to_lowercase())
        .unwrap_or_else(|| "testnet".to_string());
    if network != "testnet" {
        eprintln!("Refusing DEX contract repair on '{network}'; this utility is testnet-only");
        return Some(1);
    }

    let dry_run = has_flag(args, "--dry-run");
    let confirm = get_flag_value(args, &["--confirm"]);
    if !dry_run && confirm != Some(DEX_REPAIR_CONFIRMATION) {
        eprintln!("Refusing write without --confirm {DEX_REPAIR_CONFIRMATION}");
        return Some(1);
    }

    let data_dir = restriction_schema_data_dir(args);
    let contracts_dir = match get_flag_value(args, &["--contracts-dir"]) {
        Some(path) => PathBuf::from(path),
        None => {
            eprintln!("Missing --contracts-dir for DEX contract repair");
            return Some(2);
        }
    };
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let state = match StateStore::open_with_cache_mb(&data_dir, cache_size_mb) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("Failed to open state DB at {}: {}", data_dir.display(), err);
            return Some(1);
        }
    };

    let mut reports = Vec::new();
    for (symbol, dir_name) in TESTNET_DEX_REPAIR_CONTRACTS {
        match repair_testnet_dex_contract(&state, &contracts_dir, symbol, dir_name, dry_run) {
            Ok(report) => reports.push(report),
            Err(err) => {
                eprintln!("{err}");
                return Some(1);
            }
        }
    }
    print_testnet_dex_repair_reports(&reports, dry_run, &data_dir);
    Some(0)
}

fn digest_contract_entries<'a, I>(entries: I) -> (usize, usize, String)
where
    I: IntoIterator<Item = (&'a [u8], &'a [u8])>,
{
    let mut hasher = Sha256::new();
    let mut count = 0usize;
    let mut bytes = 0usize;
    for (key, value) in entries {
        count += 1;
        bytes += value.len();
        hasher.update((key.len() as u64).to_le_bytes());
        hasher.update(key);
        hasher.update((value.len() as u64).to_le_bytes());
        hasher.update(value);
    }
    (count, bytes, hex::encode(hasher.finalize()))
}

fn printable_storage_key(key: &[u8]) -> String {
    if key
        .iter()
        .all(|byte| byte.is_ascii_graphic() || *byte == b' ')
    {
        String::from_utf8_lossy(key).into_owned()
    } else {
        format!("0x{}", hex::encode(key))
    }
}

fn print_contract_digest_line(symbol: &str, label: &str, count: usize, bytes: usize, hash: &str) {
    println!(
        "storage symbol={} prefix={} count={} bytes={} digest={}",
        symbol, label, count, bytes, hash
    );
}

fn maybe_run_contract_storage_digest_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, SHOW_CONTRACT_STORAGE_DIGEST_FLAG) {
        return None;
    }

    let data_dir = restriction_schema_data_dir(args);
    let secondary_dir = get_flag_value(args, &["--secondary-dir"]).map(PathBuf::from);
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let state = match secondary_dir.as_ref() {
        Some(path) => StateStore::open_secondary_with_cache_mb(&data_dir, path, cache_size_mb),
        None => StateStore::open_read_only_with_cache_mb(&data_dir, cache_size_mb),
    };
    let state = match state {
        Ok(state) => state,
        Err(err) => {
            eprintln!("Failed to open state DB at {}: {}", data_dir.display(), err);
            return Some(1);
        }
    };
    if secondary_dir.is_some() {
        if let Err(err) = state.try_catch_up_with_primary() {
            eprintln!("{err}");
            return Some(1);
        }
    }

    println!("data_dir={}", data_dir.display());
    if let Some(path) = &secondary_dir {
        println!("secondary_dir={}", path.display());
    }
    match state.get_last_slot() {
        Ok(slot) => {
            println!("last_slot={slot}");
            match state.get_block_by_slot(slot) {
                Ok(Some(block)) => {
                    println!("tip_block_hash={}", block.hash().to_hex());
                    println!("tip_header_state_root={}", block.header.state_root.to_hex());
                    println!("tip_timestamp={}", block.header.timestamp);
                    println!(
                        "tip_validator={}",
                        Pubkey(block.header.validator).to_base58()
                    );
                    println!("tip_tx_count={}", block.transactions.len());
                    match state.get_post_state_commitment_anchor(slot) {
                        Ok(Some(anchor)) => {
                            println!("tip_post_anchor_block={}", anchor.block_hash.to_hex());
                            println!("tip_post_anchor_root={}", anchor.state_root.to_hex());
                        }
                        Ok(None) => println!("tip_post_anchor=none"),
                        Err(err) => println!("tip_post_anchor_error={err}"),
                    }
                }
                Ok(None) => println!("tip_block=missing"),
                Err(err) => println!("tip_block_error={err}"),
            }
        }
        Err(err) => println!("last_slot_error={err}"),
    }
    if let Some(range) = get_flag_value(args, &["--slot-range"]) {
        match range.split_once(':') {
            Some((start, end)) => match (start.parse::<u64>(), end.parse::<u64>()) {
                (Ok(start), Ok(end)) if start <= end && end.saturating_sub(start) <= 100 => {
                    for slot in start..=end {
                        match state.get_block_by_slot(slot) {
                            Ok(Some(block)) => println!(
                                "block slot={} hash={} validator={} state_root={} txs={}",
                                slot,
                                block.hash().to_hex(),
                                Pubkey(block.header.validator).to_base58(),
                                block.header.state_root.to_hex(),
                                block.transactions.len()
                            ),
                            Ok(None) => println!("block slot={} missing", slot),
                            Err(err) => println!("block slot={} error={}", slot, err),
                        }
                    }
                }
                _ => {
                    eprintln!("Invalid --slot-range; expected start:end with <=100 slots");
                    return Some(1);
                }
            },
            None => {
                eprintln!("Invalid --slot-range; expected start:end");
                return Some(1);
            }
        }
    }
    print_read_only_state_root_report(&state);
    println!(
        "mossstake_slot_only_marker={}",
        state
            .get_metadata(MOSSSTAKE_SLOT_ONLY_METADATA_KEY)
            .ok()
            .flatten()
            .map(|value| String::from_utf8_lossy(&value).into_owned())
            .unwrap_or_else(|| "none".to_string())
    );

    let symbols = match get_flag_value(args, &["--symbols"]) {
        Some(value) => value
            .split(',')
            .map(|symbol| symbol.trim().to_uppercase())
            .filter(|symbol| !symbol.is_empty())
            .collect::<Vec<_>>(),
        None => match state.get_all_symbol_registry(usize::MAX) {
            Ok(entries) => entries.into_iter().map(|entry| entry.symbol).collect(),
            Err(err) => {
                eprintln!("Failed to read symbol registry: {err}");
                return Some(1);
            }
        },
    };

    let prefix_filters: &[&[u8]] = &[
        b"ana_",
        b"ana_c_",
        b"ana_cc_",
        b"ana_cur_",
        b"ana_lp_",
        b"ana_last_trade_ts_",
        b"ana_24h_",
        b"ana_24h_ts_",
        b"ana_rec_count",
        b"ana_total_volume",
        b"ana_trader_count",
        b"dex_trade_",
        b"dex_trade_count",
        b"dex_analytics_bridge_cursor",
        b"dex_sltp_trigger_cursor",
        b"dex_band_",
        b"mrg_",
        b"price_",
    ];

    for symbol in symbols {
        let entry = match state.get_symbol_registry(&symbol) {
            Ok(Some(entry)) => entry,
            Ok(None) => continue,
            Err(err) => {
                eprintln!("Failed to read symbol {symbol}: {err}");
                return Some(1);
            }
        };
        let mut entries = match state.load_contract_storage_map(&entry.program) {
            Ok(entries) => entries,
            Err(err) => {
                eprintln!("Failed to read storage for {symbol}: {err}");
                return Some(1);
            }
        };
        entries.sort_by(|a, b| a.0.cmp(&b.0));
        let (count, bytes, digest) =
            digest_contract_entries(entries.iter().map(|(key, value)| (&key[..], &value[..])));
        print_contract_digest_line(&symbol, "all", count, bytes, &digest);

        for prefix in prefix_filters {
            let filtered = entries
                .iter()
                .filter(|(key, _)| key.starts_with(prefix))
                .map(|(key, value)| (&key[..], &value[..]));
            let (count, bytes, digest) = digest_contract_entries(filtered);
            if count > 0 {
                print_contract_digest_line(
                    &symbol,
                    &printable_storage_key(prefix),
                    count,
                    bytes,
                    &digest,
                );
            }
        }

        let sample_keys = entries
            .iter()
            .filter(|(key, _)| {
                key.starts_with(b"ana_last_trade_ts_")
                    || key.starts_with(b"ana_cur_")
                    || key == b"dex_analytics_bridge_cursor"
                    || key == b"dex_trade_count"
            })
            .take(64)
            .map(|(key, value)| {
                let value_text = if value.len() == 8 {
                    u64::from_le_bytes(value[0..8].try_into().unwrap_or([0; 8])).to_string()
                } else {
                    format!("0x{}", hex::encode(value))
                };
                format!("{}={}", printable_storage_key(key), value_text)
            })
            .collect::<Vec<_>>();
        if !sample_keys.is_empty() {
            println!(
                "storage_samples symbol={} {}",
                symbol,
                sample_keys.join(" ")
            );
        }
    }

    Some(0)
}

fn open_admin_state_for_diagnostics(
    data_dir: &Path,
    secondary_dir: Option<&Path>,
    cache_size_mb: Option<usize>,
) -> Result<StateStore, String> {
    let state = match secondary_dir {
        Some(path) => StateStore::open_secondary_with_cache_mb(data_dir, path, cache_size_mb),
        None => StateStore::open_with_cache_mb(data_dir, cache_size_mb),
    }
    .map_err(|err| format!("Failed to open state DB at {}: {}", data_dir.display(), err))?;

    if secondary_dir.is_some() {
        state.try_catch_up_with_primary()?;
    }

    Ok(state)
}

fn hash_option_text(hash: Option<Hash>) -> String {
    hash.map(|value| value.to_hex())
        .unwrap_or_else(|| "none".to_string())
}

fn print_state_root_component_report(label: &str, report: &StateRootComponentReport) {
    println!(
        "state_root_components label={} root={} root_moss_slot_only={} root_moss_legacy={} prefix=0x{:02x} commitment_schema={} include_restrictions={} accounts={} contracts={} stake={} moss_active={} moss_slot_only={} moss_legacy={} restrictions={} shielded={}",
        label,
        report.root.to_hex(),
        report.root_with_mossstake_slot_only.to_hex(),
        report.root_with_mossstake_legacy.to_hex(),
        report.prefix,
        report.commitment_schema,
        report.include_restrictions,
        report.accounts_root.to_hex(),
        report.contract_root.to_hex(),
        report.stake_pool_hash.to_hex(),
        report.mossstake_pool_hash.to_hex(),
        report.mossstake_pool_slot_only_hash.to_hex(),
        report.mossstake_pool_legacy_hash.to_hex(),
        hash_option_text(report.restrictions_root),
        hash_option_text(report.shielded_root),
    );
}

fn print_diagnostic_block_summary(slot: u64, block: &Block) {
    println!(
        "block slot={} hash={} parent={} state_root={} tx_root={} validator={} timestamp={} txs={} fees={} oracle_prices={} commit_round={} commits={}",
        slot,
        block.hash().to_hex(),
        block.header.parent_hash.to_hex(),
        block.header.state_root.to_hex(),
        block.header.tx_root.to_hex(),
        Pubkey(block.header.validator).to_base58(),
        block.header.timestamp,
        block.transactions.len(),
        block.tx_fees_paid.len(),
        block.oracle_prices.len(),
        block.commit_round,
        block.commit_signatures.len(),
    );

    for (tx_index, tx) in block.transactions.iter().enumerate() {
        println!(
            "tx index={} hash={} message_hash={} type={:?} signatures={} instructions={} recent_blockhash={} compute_budget={} compute_unit_price={}",
            tx_index,
            tx.hash().to_hex(),
            tx.message_hash().to_hex(),
            tx.tx_type,
            tx.signatures.len(),
            tx.message.instructions.len(),
            tx.message.recent_blockhash.to_hex(),
            tx.message.effective_compute_budget(),
            tx.message.effective_compute_unit_price(),
        );
        for (ix_index, ix) in tx.message.instructions.iter().enumerate() {
            let opcode = ix
                .data
                .first()
                .map(|byte| format!("0x{byte:02x}"))
                .unwrap_or_else(|| "none".to_string());
            let preview_len = ix.data.len().min(32);
            println!(
                "instruction tx={} index={} program={} accounts={} data_len={} opcode={} data_prefix=0x{}",
                tx_index,
                ix_index,
                ix.program_id.to_base58(),
                ix.accounts.len(),
                ix.data.len(),
                opcode,
                hex::encode(&ix.data[..preview_len]),
            );
            for (account_index, account) in ix.accounts.iter().enumerate() {
                println!(
                    "instruction_account tx={} index={} account_index={} pubkey={}",
                    tx_index,
                    ix_index,
                    account_index,
                    account.to_base58(),
                );
            }
        }
    }
}

fn mossstake_opcode_name(opcode: u8) -> &'static str {
    match opcode {
        13 => "deposit",
        14 => "unstake",
        15 => "claim",
        16 => "transfer",
        _ => "unknown",
    }
}

fn maybe_run_mossstake_block_scan_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, SCAN_MOSSSTAKE_BLOCKS_FLAG) {
        return None;
    }

    let from_slot = get_flag_value(args, &["--from-slot"])
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(0);
    let to_slot =
        match get_flag_value(args, &["--to-slot"]).and_then(|value| value.parse::<u64>().ok()) {
            Some(slot) => slot,
            None => {
                eprintln!("{} requires --to-slot <slot>", SCAN_MOSSSTAKE_BLOCKS_FLAG);
                return Some(2);
            }
        };
    if to_slot < from_slot {
        eprintln!("--to-slot must be >= --from-slot");
        return Some(2);
    }

    let data_dir = get_flag_value(args, &["--block-db-path", "--db-path"])
        .map(PathBuf::from)
        .unwrap_or_else(|| restriction_schema_data_dir(args));
    let secondary_dir =
        get_flag_value(args, &["--block-secondary-dir", "--secondary-dir"]).map(PathBuf::from);
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let progress_every = get_flag_value(args, &["--progress-every"])
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(100_000)
        .max(1);

    let state = match open_admin_state_for_diagnostics(
        &data_dir,
        secondary_dir.as_deref(),
        cache_size_mb,
    ) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("{err}");
            return Some(1);
        }
    };

    println!(
        "mossstake_scan_start data_dir={} secondary_dir={} from_slot={} to_slot={} progress_every={}",
        data_dir.display(),
        secondary_dir
            .as_ref()
            .map(|path| path.display().to_string())
            .unwrap_or_else(|| "none".to_string()),
        from_slot,
        to_slot,
        progress_every,
    );

    let mut mossstake_blocks = 0u64;
    let mut mossstake_instructions = 0u64;
    let mut last_progress_slot = from_slot;
    let result = state.for_each_canonical_block_in_range(from_slot, to_slot, |slot, block| {
        if slot == from_slot || slot.saturating_sub(last_progress_slot) >= progress_every {
            println!(
                "mossstake_scan_progress slot={} txs_in_block={} hits={}",
                slot,
                block.transactions.len(),
                mossstake_blocks,
            );
            last_progress_slot = slot;
        }

        let mut hits = Vec::new();
        for (tx_index, tx) in block.transactions.iter().enumerate() {
            for (ix_index, ix) in tx.message.instructions.iter().enumerate() {
                if ix.program_id != CORE_SYSTEM_PROGRAM_ID {
                    continue;
                }
                let Some(opcode) = ix.data.first().copied() else {
                    continue;
                };
                if !(13..=16).contains(&opcode) {
                    continue;
                }
                mossstake_instructions = mossstake_instructions.saturating_add(1);
                hits.push(format!(
                    "tx{}:ix{}:{}:{}:accounts{}:data{}",
                    tx_index,
                    ix_index,
                    opcode,
                    mossstake_opcode_name(opcode),
                    ix.accounts.len(),
                    ix.data.len()
                ));
            }
        }

        if !hits.is_empty() {
            mossstake_blocks = mossstake_blocks.saturating_add(1);
            println!(
                "mossstake_block slot={} timestamp={} hash={} parent={} state_root={} txs={} hits={}",
                slot,
                block.header.timestamp,
                block.hash().to_hex(),
                block.header.parent_hash.to_hex(),
                block.header.state_root.to_hex(),
                block.transactions.len(),
                hits.join(","),
            );
        }

        Ok(())
    });

    match result {
        Ok(visited) => {
            println!(
                "mossstake_scan_complete visited_blocks={} mossstake_blocks={} mossstake_instructions={}",
                visited, mossstake_blocks, mossstake_instructions,
            );
            Some(0)
        }
        Err(err) => {
            eprintln!("{err}");
            Some(1)
        }
    }
}

fn print_forced_mossstake_replay_diagnostic(
    state: &StateStore,
    block: &Block,
    replay_mode: MossStakeReplayMode,
    label: &str,
) {
    let producer = Pubkey(block.header.validator);
    let speculative_processor =
        TxProcessor::new_speculative_with_mossstake_replay_mode(state.clone(), replay_mode);
    let speculative = speculative_processor.process_transactions_speculative_at_slot(
        &block.transactions,
        &producer,
        block.header.slot,
    );
    let after = state.state_root_component_report_for_batch(&speculative.batch);
    let candidate_root = match replay_mode {
        MossStakeReplayMode::SlotOnly => after.root_with_mossstake_slot_only,
        MossStakeReplayMode::LegacyWallClock => after.root_with_mossstake_legacy,
    };
    println!(
        "forced_mossstake_replay label={} mode={:?} candidate_root={} expected_root={} match={} root_slot_only={} root_legacy={} tx_successes={} tx_failures={}",
        label,
        replay_mode,
        candidate_root.to_hex(),
        block.header.state_root.to_hex(),
        candidate_root == block.header.state_root,
        after.root_with_mossstake_slot_only.to_hex(),
        after.root_with_mossstake_legacy.to_hex(),
        speculative.results.iter().filter(|result| result.success).count(),
        speculative.results.iter().filter(|result| !result.success).count(),
    );
    for (index, result) in speculative.results.iter().enumerate() {
        if !result.success {
            println!(
                "forced_mossstake_replay_tx_error label={} mode={:?} index={} error={}",
                label,
                replay_mode,
                index,
                result.error.as_deref().unwrap_or("unknown"),
            );
        }
    }
}

fn maybe_run_block_replay_diagnostic_admin(args: &[String]) -> Option<i32> {
    let dump_block_json = get_flag_value(args, &[DUMP_BLOCK_JSON_FLAG]).map(PathBuf::from);
    let diagnose_replay = has_flag(args, DIAGNOSE_BLOCK_REPLAY_FLAG);
    if !diagnose_replay && dump_block_json.is_none() {
        return None;
    }

    let slot = match get_flag_value(args, &["--slot"]).and_then(|value| value.parse::<u64>().ok()) {
        Some(slot) => slot,
        None => {
            eprintln!(
                "{} and {} require --slot <slot>",
                DIAGNOSE_BLOCK_REPLAY_FLAG, DUMP_BLOCK_JSON_FLAG
            );
            return Some(2);
        }
    };

    let data_dir = restriction_schema_data_dir(args);
    let secondary_dir = get_flag_value(args, &["--secondary-dir"]).map(PathBuf::from);
    let block_data_dir = get_flag_value(args, &["--block-db-path"])
        .map(PathBuf::from)
        .unwrap_or_else(|| data_dir.clone());
    let block_secondary_dir = get_flag_value(args, &["--block-secondary-dir"]).map(PathBuf::from);
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let block_json = get_flag_value(args, &["--block-json"]).map(PathBuf::from);
    let cold_store_path = if get_flag_value(args, &["--block-db-path"]).is_some() {
        get_flag_value(args, &["--cold-store"]).map(PathBuf::from)
    } else {
        match resolve_public_command_cold_store_path(args, &block_data_dir) {
            Ok(path) => path,
            Err(err) => {
                eprintln!("{err}");
                return Some(2);
            }
        }
    };

    if dump_block_json.is_some() && block_json.is_some() {
        eprintln!(
            "{} and --block-json are mutually exclusive",
            DUMP_BLOCK_JSON_FLAG
        );
        return Some(2);
    }

    if let Some(path) = dump_block_json {
        let mut block_source = match open_admin_state_for_diagnostics(
            &block_data_dir,
            block_secondary_dir.as_deref().or(secondary_dir.as_deref()),
            cache_size_mb,
        ) {
            Ok(state) => state,
            Err(err) => {
                eprintln!("{err}");
                return Some(1);
            }
        };
        if let Some(cold_path) = cold_store_path.as_deref() {
            if let Err(err) = block_source.open_cold_store_read_only(cold_path) {
                eprintln!(
                    "Failed to open cold store at {}: {}",
                    cold_path.display(),
                    err
                );
                return Some(1);
            }
        }
        let block = match block_source.get_block_by_slot(slot) {
            Ok(Some(block)) => block,
            Ok(None) => {
                eprintln!("block slot {slot} missing from source DB");
                return Some(1);
            }
            Err(err) => {
                eprintln!("Failed to read block slot {slot}: {err}");
                return Some(1);
            }
        };

        let json = match serde_json::to_string_pretty(&block) {
            Ok(json) => json,
            Err(err) => {
                eprintln!("Failed to encode block slot {slot} as JSON: {err}");
                return Some(1);
            }
        };
        if path.as_os_str() == "-" {
            println!("{json}");
        } else if let Err(err) = fs::write(&path, json) {
            eprintln!("Failed to write block JSON to {}: {}", path.display(), err);
            return Some(1);
        } else {
            println!("wrote_block_json={}", path.display());
        }
        return Some(0);
    }

    let state = match open_admin_state_for_diagnostics(
        &data_dir,
        secondary_dir.as_deref(),
        cache_size_mb,
    ) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("{err}");
            return Some(1);
        }
    };

    let block = if let Some(path) = block_json {
        match fs::read(&path)
            .map_err(|err| format!("Failed to read block JSON from {}: {}", path.display(), err))
            .and_then(|bytes| {
                serde_json::from_slice::<Block>(&bytes).map_err(|err| {
                    format!(
                        "Failed to decode block JSON from {}: {}",
                        path.display(),
                        err
                    )
                })
            }) {
            Ok(block) => block,
            Err(err) => {
                eprintln!("{err}");
                return Some(1);
            }
        }
    } else {
        let block_state = if block_data_dir == data_dir && block_secondary_dir == secondary_dir {
            None
        } else {
            match open_admin_state_for_diagnostics(
                &block_data_dir,
                block_secondary_dir.as_deref(),
                cache_size_mb,
            ) {
                Ok(state) => Some(state),
                Err(err) => {
                    eprintln!("{err}");
                    return Some(1);
                }
            }
        };
        let block_source = block_state.as_ref().unwrap_or(&state);
        match block_source.get_block_by_slot(slot) {
            Ok(Some(block)) => block,
            Ok(None) => {
                eprintln!("block slot {slot} missing from source DB");
                return Some(1);
            }
            Err(err) => {
                eprintln!("Failed to read block slot {slot}: {err}");
                return Some(1);
            }
        }
    };

    println!("replay_state_db={}", data_dir.display());
    if let Some(path) = &secondary_dir {
        println!("replay_state_secondary={}", path.display());
    }
    if let Some(path) = get_flag_value(args, &["--block-json"]) {
        println!("block_source_json={path}");
    } else {
        println!("block_source_db={}", block_data_dir.display());
        if let Some(path) = &block_secondary_dir {
            println!("block_source_secondary={}", path.display());
        }
    }
    match state.get_last_slot() {
        Ok(last_slot) => println!("replay_state_last_slot={last_slot}"),
        Err(err) => println!("replay_state_last_slot_error={err}"),
    }

    print_diagnostic_block_summary(slot, &block);
    print_state_root_component_report("before", &state.state_root_component_report());

    if block.transactions.is_empty() {
        println!("speculative_replay skipped_empty_block=true");
        println!(
            "speculative_root_match={}",
            state.compute_state_root() == block.header.state_root
        );
        return Some(0);
    }

    let producer = Pubkey(block.header.validator);
    let speculative_processor = TxProcessor::new_speculative(state.clone());
    let speculative = speculative_processor.process_transactions_speculative_at_slot(
        &block.transactions,
        &producer,
        block.header.slot,
    );
    for (index, result) in speculative.results.iter().enumerate() {
        println!(
            "tx_result index={} success={} fee_paid={} compute_units={} return_code={} error={}",
            index,
            result.success,
            result.fee_paid,
            result.compute_units_used,
            result
                .return_code
                .map(|code| code.to_string())
                .unwrap_or_else(|| "none".to_string()),
            result.error.as_deref().unwrap_or("none"),
        );
    }
    let after = state.state_root_component_report_for_batch(&speculative.batch);
    print_state_root_component_report("after_speculative", &after);
    println!(
        "expected_block_state_root={}",
        block.header.state_root.to_hex()
    );
    println!(
        "speculative_root_match={}",
        after.root == block.header.state_root
    );
    print_forced_mossstake_replay_diagnostic(
        &state,
        &block,
        MossStakeReplayMode::SlotOnly,
        "after_forced_slot_only",
    );
    print_forced_mossstake_replay_diagnostic(
        &state,
        &block,
        MossStakeReplayMode::LegacyWallClock,
        "after_forced_wall_clock",
    );

    Some(0)
}

fn path_has_entries(path: &Path) -> Result<bool, String> {
    match fs::read_dir(path) {
        Ok(mut entries) => Ok(entries.next().is_some()),
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => Ok(false),
        Err(err) => Err(format!("Failed to inspect {}: {}", path.display(), err)),
    }
}

async fn run_chain_replay_diagnostic(
    source: StateStore,
    target: StateStore,
    to_slot: u64,
    progress_every: u64,
    min_validator_stake: u64,
    slot_duration_ms: u64,
    fast_discovery: bool,
) -> Result<(), String> {
    let target_tip = target.get_last_slot().unwrap_or(0);
    if target_tip == 0 && target.get_block_by_slot(0)?.is_none() {
        let genesis = source
            .get_block_by_slot(0)?
            .ok_or_else(|| "source DB is missing genesis block".to_string())?;
        if let Some(bundle) = extract_genesis_state_bundle(&genesis)? {
            apply_genesis_state_bundle(&target, &bundle)?;
        }
        if let Some(config) = extract_genesis_config(&genesis) {
            target.put_metadata(CHAIN_ID_METADATA_KEY, config.chain_id.as_bytes())?;
            let bootstrap_grants_enabled = config.consensus.validator_bootstrap_grants_enabled
                || config.chain_id == "lichen-testnet-1";
            target.put_metadata(
                VALIDATOR_BOOTSTRAP_GRANTS_ENABLED_METADATA_KEY,
                if bootstrap_grants_enabled {
                    VALIDATOR_BOOTSTRAP_GRANTS_ENABLED_VALUE
                } else {
                    b"0"
                },
            )?;
            println!(
                "diagnostic_chain_replay genesis_policy chain_id={} bootstrap_grants_enabled={}",
                config.chain_id, bootstrap_grants_enabled
            );
        }
        target.put_block_atomic(&genesis, Some(0), Some(0))?;
        target.set_last_slot(0)?;
        println!(
            "diagnostic_chain_replay initialized_genesis hash={} state_root={}",
            genesis.hash().to_hex(),
            genesis.header.state_root.to_hex()
        );
    }

    let diagnostic_activation = initialize_post_block_effects_activation_slot(&target, true)?;
    println!("diagnostic_chain_replay post_block_effects_activation_slot={diagnostic_activation}");

    let validator_set = Arc::new(RwLock::new(
        target
            .load_validator_set()
            .unwrap_or_else(|_| ValidatorSet::new()),
    ));
    let stake_pool = Arc::new(RwLock::new(
        target.get_stake_pool().unwrap_or_else(|_| StakePool::new()),
    ));

    let start_slot = target.get_last_slot().unwrap_or(0).saturating_add(1);
    if start_slot > to_slot {
        println!(
            "diagnostic_chain_replay already_at_or_past_target start_slot={} to_slot={}",
            start_slot, to_slot
        );
        return Ok(());
    }

    println!(
        "diagnostic_chain_replay start_slot={} to_slot={} progress_every={} min_validator_stake={} slot_duration_ms={} fast_discovery={}",
        start_slot, to_slot, progress_every, min_validator_stake, slot_duration_ms, fast_discovery
    );

    for slot in start_slot..=to_slot {
        let block = source
            .get_block_by_slot(slot)?
            .ok_or_else(|| format!("source DB is missing block at slot {slot}"))?;

        activate_pending_validators_before_replay_height(
            &target,
            &validator_set,
            &stake_pool,
            slot,
            min_validator_stake,
        )
        .await;

        if !(fast_discovery && block.transactions.is_empty()) {
            if let Err(err) = validate_then_replay_block_transactions(
                &target,
                &block,
                "diagnostic chain replay",
                true,
            ) {
                println!(
                    "diagnostic_chain_replay_mismatch slot={} error={}",
                    slot, err
                );
                print_diagnostic_block_summary(slot, &block);
                print_state_root_component_report(
                    "before_mismatch",
                    &target.state_root_component_report(),
                );
                if !block.transactions.is_empty() {
                    print_forced_mossstake_replay_diagnostic(
                        &target,
                        &block,
                        MossStakeReplayMode::SlotOnly,
                        "mismatch_forced_slot_only",
                    );
                    print_forced_mossstake_replay_diagnostic(
                        &target,
                        &block,
                        MossStakeReplayMode::LegacyWallClock,
                        "mismatch_forced_wall_clock",
                    );
                }
                return Err(err);
            }
        }

        if fast_discovery {
            target.put_replay_block_header_atomic(&block, None, None)?;
        } else {
            target.put_block_atomic(&block, None, None)?;
        }
        apply_post_block_effects_after_store(
            &target,
            &validator_set,
            &stake_pool,
            &block,
            min_validator_stake,
            slot_duration_ms,
        )
        .await;

        if progress_every > 0
            && (slot == start_slot || slot % progress_every == 0 || slot == to_slot)
        {
            let root = if fast_discovery {
                "skipped_fast_discovery".to_string()
            } else {
                target.compute_state_root().to_hex()
            };
            println!(
                "diagnostic_chain_replay_progress slot={} block_hash={} post_root={}",
                slot,
                block.hash().to_hex(),
                root
            );
        }
    }

    let root = if fast_discovery {
        "skipped_fast_discovery".to_string()
    } else {
        target.compute_state_root().to_hex()
    };
    println!(
        "diagnostic_chain_replay_complete slot={} root={}",
        target.get_last_slot().unwrap_or(0),
        root
    );
    Ok(())
}

fn maybe_run_chain_replay_diagnostic_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, DIAGNOSE_CHAIN_REPLAY_FLAG) {
        return None;
    }

    let target_dir = restriction_schema_data_dir(args);
    let source_dir = match get_flag_value(args, &["--block-db-path"]) {
        Some(path) => PathBuf::from(path),
        None => {
            eprintln!(
                "{} requires --block-db-path <source-db>",
                DIAGNOSE_CHAIN_REPLAY_FLAG
            );
            return Some(2);
        }
    };
    if target_dir == source_dir {
        eprintln!(
            "Refusing to replay into the source DB: {}",
            target_dir.display()
        );
        return Some(2);
    }

    let to_slot = match get_flag_value(args, &["--to-slot"]).and_then(|value| value.parse().ok()) {
        Some(slot) => slot,
        None => {
            eprintln!("{} requires --to-slot <slot>", DIAGNOSE_CHAIN_REPLAY_FLAG);
            return Some(2);
        }
    };
    let progress_every = get_flag_value(args, &["--progress-every"])
        .and_then(|value| value.parse().ok())
        .unwrap_or(10_000);
    let min_validator_stake = get_flag_value(args, &["--min-validator-stake"])
        .and_then(|value| value.parse().ok())
        .unwrap_or(MIN_VALIDATOR_STAKE);
    let slot_duration_ms = get_flag_value(args, &["--slot-duration-ms"])
        .and_then(|value| value.parse().ok())
        .unwrap_or(400);
    let fast_discovery = has_flag(args, "--fast-discovery");
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let source_secondary_dir = get_flag_value(args, &["--block-secondary-dir"]).map(PathBuf::from);
    let resume = has_flag(args, "--resume");

    match path_has_entries(&target_dir) {
        Ok(true) if !resume => {
            eprintln!(
                "Refusing to use non-empty target {}; pass --resume or remove it",
                target_dir.display()
            );
            return Some(2);
        }
        Ok(_) => {}
        Err(err) => {
            eprintln!("{err}");
            return Some(1);
        }
    }

    let source = match open_admin_state_for_diagnostics(
        &source_dir,
        source_secondary_dir.as_deref(),
        cache_size_mb,
    ) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("{err}");
            return Some(1);
        }
    };
    let target = match StateStore::open_with_cache_mb(&target_dir, cache_size_mb) {
        Ok(state) => state,
        Err(err) => {
            eprintln!(
                "Failed to open target state DB at {}: {}",
                target_dir.display(),
                err
            );
            return Some(1);
        }
    };

    let runtime = match tokio::runtime::Builder::new_current_thread()
        .enable_all()
        .build()
    {
        Ok(runtime) => runtime,
        Err(err) => {
            eprintln!("Failed to create diagnostic runtime: {}", err);
            return Some(1);
        }
    };

    match runtime.block_on(run_chain_replay_diagnostic(
        source,
        target,
        to_slot,
        progress_every,
        min_validator_stake,
        slot_duration_ms,
        fast_discovery,
    )) {
        Ok(()) => Some(0),
        Err(err) => {
            eprintln!("{err}");
            Some(1)
        }
    }
}

fn maybe_run_stake_pool_digest_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, SHOW_STAKE_POOL_DIGEST_FLAG) {
        return None;
    }

    let data_dir = restriction_schema_data_dir(args);
    let secondary_dir = get_flag_value(args, &["--secondary-dir"]).map(PathBuf::from);
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let state = match secondary_dir.as_ref() {
        Some(path) => StateStore::open_secondary_with_cache_mb(&data_dir, path, cache_size_mb),
        None => StateStore::open_read_only_with_cache_mb(&data_dir, cache_size_mb),
    };
    let state = match state {
        Ok(state) => state,
        Err(err) => {
            eprintln!("Failed to open state DB at {}: {}", data_dir.display(), err);
            return Some(1);
        }
    };
    if secondary_dir.is_some() {
        if let Err(err) = state.try_catch_up_with_primary() {
            eprintln!("{err}");
            return Some(1);
        }
    }

    println!("data_dir={}", data_dir.display());
    if let Some(path) = &secondary_dir {
        println!("secondary_dir={}", path.display());
    }
    match state.get_last_slot() {
        Ok(slot) => {
            println!("last_slot={slot}");
            match state.get_block_by_slot(slot) {
                Ok(Some(block)) => {
                    println!("tip_block_hash={}", block.hash().to_hex());
                    println!("tip_header_state_root={}", block.header.state_root.to_hex());
                    println!(
                        "tip_validator={}",
                        Pubkey(block.header.validator).to_base58()
                    );
                }
                Ok(None) => println!("tip_block=missing"),
                Err(err) => println!("tip_block_error={err}"),
            }
        }
        Err(err) => println!("last_slot_error={err}"),
    }
    if let Some(range) = get_flag_value(args, &["--slot-range"]) {
        match range.split_once(':') {
            Some((start, end)) => match (start.parse::<u64>(), end.parse::<u64>()) {
                (Ok(start), Ok(end)) if start <= end && end.saturating_sub(start) <= 100 => {
                    for slot in start..=end {
                        match state.get_block_by_slot(slot) {
                            Ok(Some(block)) => println!(
                                "block slot={} hash={} validator={} state_root={} txs={}",
                                slot,
                                block.hash().to_hex(),
                                Pubkey(block.header.validator).to_base58(),
                                block.header.state_root.to_hex(),
                                block.transactions.len()
                            ),
                            Ok(None) => println!("block slot={} missing", slot),
                            Err(err) => println!("block slot={} error={}", slot, err),
                        }
                    }
                }
                _ => {
                    eprintln!("Invalid --slot-range; expected start:end with <=100 slots");
                    return Some(1);
                }
            },
            None => {
                eprintln!("Invalid --slot-range; expected start:end");
                return Some(1);
            }
        }
    }
    print_read_only_state_root_report(&state);

    let pool = match state.get_stake_pool() {
        Ok(pool) => pool,
        Err(err) => {
            eprintln!("Failed to read stake pool: {err}");
            return Some(1);
        }
    };
    let stats = pool.get_stats();
    println!("stake_pool_hash={}", pool.canonical_hash().to_hex());
    println!("stake_pool_entries={}", pool.stake_entries().len());
    println!("stake_pool_total_staked={}", pool.total_stake());
    println!("stake_pool_total_slashed={}", pool.total_slashed());
    println!(
        "stake_pool_bootstrap_grants_issued={}",
        pool.bootstrap_grants_issued()
    );
    println!(
        "stake_pool_stats active_validators={} total_unclaimed_rewards={}",
        stats.active_validators, stats.total_unclaimed_rewards
    );

    let mut entries = pool.stake_entries();
    entries.sort_by_key(|entry| entry.validator.0);
    for entry in entries {
        println!(
            "stake_entry validator={} amount={} delegated={} active={} rewards_earned={} last_reward_slot={} blocks_produced={} earned_amount={} bootstrap_debt={} total_claimed={} total_debt_repaid={} bootstrap_index={} start_slot={} last_migration_slot={} penalty_boost_until={}",
            entry.validator.to_base58(),
            entry.amount,
            entry.delegated_amount,
            entry.is_active,
            entry.rewards_earned,
            entry.last_reward_slot,
            entry.blocks_produced,
            entry.earned_amount,
            entry.bootstrap_debt,
            entry.total_claimed,
            entry.total_debt_repaid,
            entry.bootstrap_index,
            entry.start_slot,
            entry.last_migration_slot,
            entry.penalty_boost_until,
        );
    }

    Some(0)
}

#[derive(Debug, Default)]
struct RecentPostBlockEffectsAudit {
    first_slot: u64,
    tip: u64,
    blocks_checked: u64,
    missing_block_slots: Vec<u64>,
    comprehensive_missing_slots: Vec<u64>,
    stake_pool_missing_slots: Vec<u64>,
    reward_missing_slots: Vec<u64>,
    fee_missing_slots: Vec<u64>,
    marker_conflicts: Vec<String>,
}

impl RecentPostBlockEffectsAudit {
    fn is_repairable(&self) -> bool {
        self.missing_block_slots.is_empty() && self.marker_conflicts.is_empty()
    }

    fn is_complete(&self) -> bool {
        self.is_economically_complete() && self.comprehensive_missing_slots.is_empty()
    }

    fn is_economically_complete(&self) -> bool {
        self.is_repairable()
            && self.stake_pool_missing_slots.is_empty()
            && self.reward_missing_slots.is_empty()
            && self.fee_missing_slots.is_empty()
    }
}

fn audit_recent_post_block_effects(
    state: &StateStore,
    historical_window: u64,
    activation_slot: u64,
) -> Result<RecentPostBlockEffectsAudit, String> {
    let tip = state.get_last_slot()?;
    let first_slot = if tip == 0 {
        activation_slot
    } else {
        tip.saturating_sub(historical_window).max(activation_slot)
    };
    let mut report = RecentPostBlockEffectsAudit {
        first_slot,
        tip,
        ..RecentPostBlockEffectsAudit::default()
    };
    if tip == 0 || first_slot > tip {
        return Ok(report);
    }

    for slot in first_slot..=tip {
        let Some(block) = state.get_block_by_slot(slot)? else {
            report.missing_block_slots.push(slot);
            continue;
        };
        report.blocks_checked = report.blocks_checked.saturating_add(1);
        let block_hash = block.hash();

        match state.get_post_block_effects_hash(slot)? {
            Some(hash) if hash == block_hash => {}
            Some(hash) => report.marker_conflicts.push(format!(
                "post_block_effects slot={} stored={} canonical={}",
                slot,
                hash.to_hex(),
                block_hash.to_hex()
            )),
            None => report.comprehensive_missing_slots.push(slot),
        }
        match state.get_stake_pool_production_hash(slot)? {
            Some(hash) if hash == block_hash => {}
            Some(hash) => report.marker_conflicts.push(format!(
                "stake_pool_production slot={} stored={} canonical={}",
                slot,
                hash.to_hex(),
                block_hash.to_hex()
            )),
            None => report.stake_pool_missing_slots.push(slot),
        }
        match state.get_reward_distribution_hash(slot)? {
            Some(hash) if hash == block_hash => {}
            Some(hash) => report.marker_conflicts.push(format!(
                "reward_distribution slot={} stored={} canonical={}",
                slot,
                hash.to_hex(),
                block_hash.to_hex()
            )),
            None => report.reward_missing_slots.push(slot),
        }
        match state.get_fee_distribution_hash(slot)? {
            Some(hash) if hash == block_hash => {}
            Some(hash) => report.marker_conflicts.push(format!(
                "fee_distribution slot={} stored={} canonical={}",
                slot,
                hash.to_hex(),
                block_hash.to_hex()
            )),
            None => report.fee_missing_slots.push(slot),
        }
    }

    Ok(report)
}

fn sampled_slots(slots: &[u64]) -> String {
    const LIMIT: usize = 16;
    let mut values = slots
        .iter()
        .take(LIMIT)
        .map(u64::to_string)
        .collect::<Vec<_>>();
    if slots.len() > LIMIT {
        values.push(format!("...+{}", slots.len() - LIMIT));
    }
    if values.is_empty() {
        "none".to_string()
    } else {
        values.join(",")
    }
}

fn print_recent_post_block_effects_audit(label: &str, report: &RecentPostBlockEffectsAudit) {
    println!(
        "post_block_effects_audit label={} first_slot={} tip={} blocks_checked={} missing_blocks={} comprehensive_missing={} stake_pool_missing={} reward_missing={} fee_missing={} conflicts={} repairable={} economic_complete={} comprehensive_complete={}",
        label,
        report.first_slot,
        report.tip,
        report.blocks_checked,
        report.missing_block_slots.len(),
        report.comprehensive_missing_slots.len(),
        report.stake_pool_missing_slots.len(),
        report.reward_missing_slots.len(),
        report.fee_missing_slots.len(),
        report.marker_conflicts.len(),
        report.is_repairable(),
        report.is_economically_complete(),
        report.is_complete(),
    );
    println!(
        "post_block_effects_slots label={} missing_blocks={} comprehensive_missing={} stake_pool_missing={} reward_missing={} fee_missing={}",
        label,
        sampled_slots(&report.missing_block_slots),
        sampled_slots(&report.comprehensive_missing_slots),
        sampled_slots(&report.stake_pool_missing_slots),
        sampled_slots(&report.reward_missing_slots),
        sampled_slots(&report.fee_missing_slots),
    );
    for conflict in &report.marker_conflicts {
        println!("post_block_effects_conflict label={} {}", label, conflict);
    }
}

fn maybe_run_recent_post_block_effects_repair_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, REPAIR_RECENT_POST_BLOCK_EFFECTS_FLAG) {
        return None;
    }

    let historical_window = get_flag_value(args, &["--window"])
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(RECENT_POST_BLOCK_EFFECTS_RECOVERY_WINDOW);
    if historical_window == 0 || historical_window > 65_536 {
        eprintln!("--window must be between 1 and 65536 historical slots");
        return Some(2);
    }

    let execute = has_flag(args, "--execute");
    if execute
        && get_flag_value(args, &["--confirm"])
            != Some(RECENT_POST_BLOCK_EFFECTS_REPAIR_CONFIRMATION)
    {
        eprintln!(
            "--execute requires --confirm {}",
            RECENT_POST_BLOCK_EFFECTS_REPAIR_CONFIRMATION
        );
        return Some(2);
    }

    let data_dir = restriction_schema_data_dir(args);
    let secondary_dir = get_flag_value(args, &["--secondary-dir"]).map(PathBuf::from);
    if execute && secondary_dir.is_some() {
        eprintln!("--secondary-dir is read-only and cannot be used with --execute");
        return Some(2);
    }
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let state = match open_admin_state_for_diagnostics(
        &data_dir,
        secondary_dir.as_deref(),
        cache_size_mb,
    ) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("{err}");
            return Some(1);
        }
    };

    println!("data_dir={}", data_dir.display());
    if let Some(path) = &secondary_dir {
        println!("secondary_dir={}", path.display());
    }
    let activation_slot = match post_block_effects_activation_slot(&state) {
        Ok(Some(slot)) => slot,
        Ok(None) => {
            println!("post_block_effects_activation_slot=unset");
            if execute {
                eprintln!(
                    "Refusing repair without {}: align pre-activation state from a quorum-verified snapshot before starting this release",
                    POST_BLOCK_EFFECTS_ACTIVATION_SLOT_KEY
                );
                return Some(1);
            }
            println!("execute=false repair_required=false pre_activation_alignment_required=true");
            return Some(0);
        }
        Err(err) => {
            eprintln!("Failed to read post-block activation boundary: {err}");
            return Some(1);
        }
    };
    println!("post_block_effects_activation_slot={activation_slot}");
    let before = match audit_recent_post_block_effects(&state, historical_window, activation_slot) {
        Ok(report) => report,
        Err(err) => {
            eprintln!("Failed to audit recent post-block effects: {err}");
            return Some(1);
        }
    };
    print_recent_post_block_effects_audit("before", &before);
    let before_pool_hash = match state.get_stake_pool() {
        Ok(pool) => pool.canonical_hash(),
        Err(err) => {
            eprintln!("Failed to read stake pool: {err}");
            return Some(1);
        }
    };
    println!("stake_pool_hash_before={}", before_pool_hash.to_hex());

    if !before.is_repairable() {
        eprintln!(
            "Refusing repair: recent canonical blocks are missing or completion markers conflict"
        );
        return Some(1);
    }
    if !execute {
        println!(
            "execute=false repair_required={}",
            !before.is_economically_complete()
        );
        return Some(0);
    }

    let validator_set = match state.load_validator_set() {
        Ok(set) => Arc::new(RwLock::new(set)),
        Err(err) => {
            eprintln!("Failed to load validator set: {err}");
            return Some(1);
        }
    };
    let stake_pool = match state.get_stake_pool() {
        Ok(pool) => Arc::new(RwLock::new(pool)),
        Err(err) => {
            eprintln!("Failed to load stake pool: {err}");
            return Some(1);
        }
    };
    let min_validator_stake = get_flag_value(args, &["--min-validator-stake"])
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(MIN_VALIDATOR_STAKE);
    let runtime = match tokio::runtime::Builder::new_current_thread()
        .enable_all()
        .build()
    {
        Ok(runtime) => runtime,
        Err(err) => {
            eprintln!("Failed to create repair runtime: {err}");
            return Some(1);
        }
    };
    let repair_result = runtime.block_on(async {
        let mut repaired = recover_recent_stored_block_post_effects_if_needed(
            &state,
            &validator_set,
            &stake_pool,
            activation_slot,
            min_validator_stake,
            historical_window,
            "Offline recent post-block repair",
        )
        .await?;
        let tip = state.get_last_slot()?;
        if tip > 0 {
            let block = state
                .get_block_by_slot(tip)?
                .ok_or_else(|| format!("stored tip slot {} is missing its canonical block", tip))?;
            if recover_stored_block_economic_effects_if_needed(
                &state,
                &validator_set,
                &stake_pool,
                &block,
                activation_slot,
                min_validator_stake,
                "Offline recent post-block repair",
            )
            .await?
            {
                repaired = repaired.saturating_add(1);
            }
        }
        if repaired > 0 {
            ensure_tip_post_state_commitment_anchor(&state)?;
        }
        Ok::<u64, String>(repaired)
    });
    let repaired = match repair_result {
        Ok(repaired) => repaired,
        Err(err) => {
            eprintln!("Recent post-block repair failed: {err}");
            return Some(1);
        }
    };
    println!("economically_repaired_blocks={repaired}");

    let after = match audit_recent_post_block_effects(&state, historical_window, activation_slot) {
        Ok(report) => report,
        Err(err) => {
            eprintln!("Failed post-repair audit: {err}");
            return Some(1);
        }
    };
    print_recent_post_block_effects_audit("after", &after);
    let after_pool_hash = match state.get_stake_pool() {
        Ok(pool) => pool.canonical_hash(),
        Err(err) => {
            eprintln!("Failed to read repaired stake pool: {err}");
            return Some(1);
        }
    };
    println!("stake_pool_hash_after={}", after_pool_hash.to_hex());
    if !after.is_economically_complete() {
        eprintln!(
            "Recent post-block repair did not produce an economically complete audited window"
        );
        return Some(1);
    }
    println!("execute=true economic_repair_complete=true");
    Some(0)
}

fn export_roundtrip_snapshot_entries(
    state: &StateStore,
    category: &str,
    chunk_size: u64,
) -> Result<SnapshotEntries, String> {
    match category {
        "validator_set" => {
            let set = state.load_validator_set()?;
            let set = canonical_validator_set_snapshot(&set);
            return Ok(vec![(
                b"validator_set".to_vec(),
                serialize_legacy_bincode(&set, "validator_set snapshot")?,
            )]);
        }
        "stake_pool" => {
            let pool = state.get_stake_pool()?;
            return Ok(vec![(
                b"stake_pool".to_vec(),
                pool.canonical_snapshot_bytes()?,
            )]);
        }
        "mossstake_pool" => {
            let pool = state.get_mossstake_pool()?;
            return Ok(vec![(
                b"mossstake_pool".to_vec(),
                pool.canonical_snapshot_bytes()?,
            )]);
        }
        _ => {}
    }

    let mut entries = Vec::new();
    let mut cursor: Option<Vec<u8>> = None;
    loop {
        let page = state.export_snapshot_category_cursor_untracked(
            category,
            cursor.as_deref(),
            chunk_size,
        )?;
        entries.extend(page.entries);
        if !page.has_more {
            break;
        }
        let Some(next_cursor) = page.next_cursor else {
            return Err(format!(
                "{} snapshot export had more entries but no cursor",
                category
            ));
        };
        cursor = Some(next_cursor);
    }

    Ok(entries)
}

fn print_roundtrip_root_components(label: &str, state: &StateStore) {
    let report = state.state_root_component_report();
    println!("{}_root={}", label, report.root.to_hex());
    println!(
        "{}_state_commitment_schema={}",
        label,
        StateStore::state_commitment_schema_label(report.commitment_schema)
    );
    println!("{}_state_root_prefix=0x{:02x}", label, report.prefix);
    println!("{}_accounts_root={}", label, report.accounts_root.to_hex());
    println!("{}_contracts_root={}", label, report.contract_root.to_hex());
    println!(
        "{}_stake_pool_hash={}",
        label,
        report.stake_pool_hash.to_hex()
    );
    println!(
        "{}_mossstake_pool_hash={}",
        label,
        report.mossstake_pool_hash.to_hex()
    );
    println!(
        "{}_restrictions_root={}",
        label,
        report
            .restrictions_root
            .map(|root| root.to_hex())
            .unwrap_or_else(|| "disabled".to_string())
    );
    println!(
        "{}_shielded_root={}",
        label,
        report
            .shielded_root
            .map(|root| root.to_hex())
            .unwrap_or_else(|| "disabled".to_string())
    );
}

struct RoundtripTempStateDir {
    path: PathBuf,
}

impl Drop for RoundtripTempStateDir {
    fn drop(&mut self) {
        if let Err(err) = fs::remove_dir_all(&self.path) {
            if err.kind() != std::io::ErrorKind::NotFound {
                eprintln!(
                    "Warning: failed to remove temporary roundtrip DB {}: {}",
                    self.path.display(),
                    err
                );
            }
        }
    }
}

fn maybe_run_warp_snapshot_roundtrip_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, VERIFY_WARP_SNAPSHOT_ROUNDTRIP_FLAG) {
        return None;
    }

    let data_dir = restriction_schema_data_dir(args);
    let secondary_dir = get_flag_value(args, &["--secondary-dir"]).map(PathBuf::from);
    let cache_size_mb = get_flag_value(args, &["--cache-size-mb"]).and_then(|s| s.parse().ok());
    let chunk_size = get_flag_value(args, &["--chunk-size"])
        .and_then(|value| value.parse::<u64>().ok())
        .unwrap_or(1000)
        .clamp(1, MAX_SNAPSHOT_CHUNK_SIZE);

    let source = match secondary_dir.as_ref() {
        Some(path) => StateStore::open_secondary_with_cache_mb(&data_dir, path, cache_size_mb),
        None => StateStore::open_with_cache_mb(&data_dir, cache_size_mb),
    };
    let source = match source {
        Ok(state) => state,
        Err(err) => {
            eprintln!(
                "Failed to open source state DB at {}: {}",
                data_dir.display(),
                err
            );
            return Some(1);
        }
    };
    if secondary_dir.is_some() {
        if let Err(err) = source.try_catch_up_with_primary() {
            eprintln!("{err}");
            return Some(1);
        }
    }

    let target_path = env::temp_dir().join(format!(
        "lichen-warp-snapshot-roundtrip-{}-{}",
        std::process::id(),
        current_unix_millis()
    ));
    if let Err(err) = fs::remove_dir_all(&target_path) {
        if err.kind() != std::io::ErrorKind::NotFound {
            eprintln!(
                "Failed to clear temporary roundtrip DB {}: {}",
                target_path.display(),
                err
            );
            return Some(1);
        }
    }
    let _target_guard = RoundtripTempStateDir {
        path: target_path.clone(),
    };
    let target = match StateStore::open(&target_path) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("Failed to open temporary roundtrip DB: {}", err);
            return Some(1);
        }
    };

    println!("source_dir={}", data_dir.display());
    if let Some(path) = &secondary_dir {
        println!("secondary_dir={}", path.display());
    }
    println!("target_dir={}", target_path.display());
    println!("chunk_size={chunk_size}");
    if let Ok(slot) = source.get_last_slot() {
        println!("source_last_slot={slot}");
    }

    for category_name in WARP_SNAPSHOT_CATEGORIES {
        let entries = match export_roundtrip_snapshot_entries(&source, category_name, chunk_size) {
            Ok(entries) => entries,
            Err(err) => {
                eprintln!(
                    "Failed to export {} snapshot category: {}",
                    category_name, err
                );
                return Some(1);
            }
        };
        let count = entries.len();
        if let Err(err) = import_ordered_snapshot_category(&target, category_name, &entries) {
            eprintln!(
                "Failed to import {} snapshot category: {}",
                category_name, err
            );
            return Some(1);
        }
        println!("category={} entries={}", category_name, count);
    }

    for (label, result) in [
        ("account", target.reconcile_account_count()),
        ("active_account", target.reconcile_active_account_count()),
        ("program", target.reconcile_program_count()),
        ("validator", target.reconcile_validator_count()),
    ] {
        if let Err(err) = result {
            eprintln!("Failed to reconcile {} count: {}", label, err);
            return Some(1);
        }
    }
    target.invalidate_merkle_cache();
    if target.uses_sparse_state_commitment() {
        match target.rebuild_sparse_state_commitment(false) {
            Ok(report) => println!(
                "target_sparse_rebuild_root={} accounts={} contracts={}",
                report.current_state_root.to_hex(),
                report.accounts_leaf_count,
                report.contract_leaf_count
            ),
            Err(err) => {
                eprintln!("Failed to rebuild target sparse state commitment: {}", err);
                return Some(1);
            }
        }
    }

    let expected_root = source.compute_state_root_cold_start();
    print_roundtrip_root_components("source", &source);
    print_roundtrip_root_components("target", &target);

    match validate_state_root_with_schema(
        &target,
        source.get_last_slot().unwrap_or_default(),
        expected_root,
        "warp snapshot roundtrip",
        true,
    ) {
        Ok(()) => {
            println!("roundtrip_status=ok");
            Some(0)
        }
        Err(err) => {
            eprintln!("roundtrip_status=mismatch");
            eprintln!("{err}");
            Some(1)
        }
    }
}

