fn shielded_state_bundle_counts(bundle: &ShieldedStateBundle) -> Vec<(String, usize)> {
    bundle
        .iter()
        .map(|(category, entries)| (category.clone(), entries.len()))
        .collect()
}

fn export_shielded_transaction_records(
    state: &StateStore,
    shielded_txs: &[SnapshotEntry],
) -> Result<SnapshotEntries, String> {
    let mut seen = HashSet::<[u8; 32]>::new();
    let mut entries = Vec::new();

    for (key, _) in shielded_txs {
        if key.len() < 48 {
            continue;
        }
        let mut hash_bytes = [0u8; 32];
        hash_bytes.copy_from_slice(&key[16..48]);
        if !seen.insert(hash_bytes) {
            continue;
        }

        let hash = Hash(hash_bytes);
        let tx = state.get_transaction(&hash)?.ok_or_else(|| {
            format!(
                "missing transaction record for shielded tx {}",
                hash.to_hex()
            )
        })?;
        let mut value = Vec::with_capacity(512);
        value.push(0xBC);
        value.extend_from_slice(&serialize_legacy_bincode(
            &tx,
            "shielded transaction record",
        )?);
        entries.push((hash.0.to_vec(), value));
    }

    Ok(entries)
}

fn export_shielded_state_bundle(
    state: &StateStore,
    chunk_size: u64,
) -> Result<ShieldedStateBundle, String> {
    let mut bundle = Vec::with_capacity(SHIELDED_STATE_BUNDLE_CATEGORIES.len() + 1);
    let mut shielded_txs_entries: Option<SnapshotEntries> = None;
    for category in SHIELDED_STATE_BUNDLE_CATEGORIES {
        let entries = export_roundtrip_snapshot_entries(state, category, chunk_size)
            .map_err(|err| format!("{} export failed: {}", category, err))?;
        if *category == "shielded_txs" {
            shielded_txs_entries = Some(entries.clone());
        }
        bundle.push(((*category).to_string(), entries));
    }
    if let Some(entries) = shielded_txs_entries.as_deref() {
        let transaction_entries = export_shielded_transaction_records(state, entries)
            .map_err(|err| format!("shielded transaction record export failed: {}", err))?;
        bundle.push((
            SHIELDED_TRANSACTION_RECORDS_CATEGORY.to_string(),
            transaction_entries,
        ));
    }
    Ok(bundle)
}

fn validate_shielded_state_bundle(
    bundle: ShieldedStateBundle,
) -> Result<HashMap<String, SnapshotEntries>, String> {
    let mut categories = HashMap::new();
    for (category, entries) in bundle {
        if !SHIELDED_STATE_BUNDLE_ALLOWED_CATEGORIES.contains(&category.as_str()) {
            return Err(format!(
                "shielded state bundle contains unsupported category: {}",
                category
            ));
        }
        if categories.insert(category.clone(), entries).is_some() {
            return Err(format!(
                "shielded state bundle contains duplicate category: {}",
                category
            ));
        }
    }

    for category in SHIELDED_STATE_BUNDLE_CATEGORIES {
        if !categories.contains_key(*category) {
            return Err(format!(
                "shielded state bundle is missing required category: {}",
                category
            ));
        }
    }

    Ok(categories)
}

fn maybe_run_shielded_state_bundle_admin(args: &[String]) -> Option<i32> {
    let export_path = get_flag_value(args, &[EXPORT_SHIELDED_STATE_BUNDLE_FLAG]).map(PathBuf::from);
    let import_path = get_flag_value(args, &[IMPORT_SHIELDED_STATE_BUNDLE_FLAG]).map(PathBuf::from);

    match (export_path, import_path) {
        (None, None) => None,
        (Some(_), Some(_)) => {
            eprintln!(
                "{} and {} are mutually exclusive",
                EXPORT_SHIELDED_STATE_BUNDLE_FLAG, IMPORT_SHIELDED_STATE_BUNDLE_FLAG
            );
            Some(2)
        }
        (Some(path), None) => {
            let data_dir = restriction_schema_data_dir(args);
            let chunk_size = get_flag_value(args, &["--chunk-size"])
                .and_then(|s| s.parse().ok())
                .unwrap_or(2_000);
            let state = match StateStore::open(&data_dir) {
                Ok(state) => state,
                Err(err) => {
                    eprintln!("Failed to open state DB at {}: {}", data_dir.display(), err);
                    return Some(1);
                }
            };
            let bundle = match export_shielded_state_bundle(&state, chunk_size) {
                Ok(bundle) => bundle,
                Err(err) => {
                    eprintln!("Failed to export shielded state bundle: {}", err);
                    return Some(1);
                }
            };
            let counts = shielded_state_bundle_counts(&bundle);
            let bytes = match serialize_legacy_bincode_limited(
                &bundle,
                STATE_SNAPSHOT_ENTRIES_CODEC_LIMIT_BYTES,
                "shielded state bundle",
            ) {
                Ok(bytes) => bytes,
                Err(err) => {
                    eprintln!("Failed to encode shielded state bundle: {}", err);
                    return Some(1);
                }
            };
            if let Err(err) = fs::write(&path, bytes) {
                eprintln!("Failed to write {}: {}", path.display(), err);
                return Some(1);
            }
            println!("data_dir={}", data_dir.display());
            println!("output={}", path.display());
            for (category, count) in counts {
                println!("category={} entries={}", category, count);
            }
            Some(0)
        }
        (None, Some(path)) => {
            let confirm = get_flag_value(args, &["--confirm"]);
            if confirm != Some(SHIELDED_STATE_BUNDLE_IMPORT_CONFIRMATION) {
                eprintln!(
                    "Refusing write without --confirm {SHIELDED_STATE_BUNDLE_IMPORT_CONFIRMATION}"
                );
                return Some(1);
            }
            let data_dir = restriction_schema_data_dir(args);
            let bytes = match fs::read(&path) {
                Ok(bytes) => bytes,
                Err(err) => {
                    eprintln!("Failed to read {}: {}", path.display(), err);
                    return Some(1);
                }
            };
            let bundle = match deserialize_legacy_bincode_strict::<ShieldedStateBundle>(
                &bytes,
                STATE_SNAPSHOT_ENTRIES_CODEC_LIMIT_BYTES,
                "shielded state bundle",
            ) {
                Ok(bundle) => bundle,
                Err(err) => {
                    eprintln!("Failed to decode shielded state bundle: {}", err);
                    return Some(1);
                }
            };
            let mut categories = match validate_shielded_state_bundle(bundle) {
                Ok(categories) => categories,
                Err(err) => {
                    eprintln!("{}", err);
                    return Some(1);
                }
            };
            let state = match StateStore::open(&data_dir) {
                Ok(state) => state,
                Err(err) => {
                    eprintln!("Failed to open state DB at {}: {}", data_dir.display(), err);
                    return Some(1);
                }
            };
            let deleted = match state.clear_shielded_state_categories() {
                Ok(deleted) => deleted,
                Err(err) => {
                    eprintln!(
                        "Failed to clear existing shielded state categories: {}",
                        err
                    );
                    return Some(1);
                }
            };
            println!("data_dir={}", data_dir.display());
            println!("input={}", path.display());
            println!("deleted_entries={}", deleted);
            for category in SHIELDED_STATE_BUNDLE_CATEGORIES {
                let entries = categories
                    .remove(*category)
                    .expect("validated shielded category");
                match import_ordered_snapshot_category(&state, category, &entries) {
                    Ok(imported) => println!("category={} imported={}", category, imported),
                    Err(err) => {
                        eprintln!("Failed to import {}: {}", category, err);
                        return Some(1);
                    }
                }
            }
            if let Some(entries) = categories.remove(SHIELDED_TRANSACTION_RECORDS_CATEGORY) {
                match import_ordered_snapshot_category(
                    &state,
                    SHIELDED_TRANSACTION_RECORDS_CATEGORY,
                    &entries,
                ) {
                    Ok(imported) => println!(
                        "category={} imported={}",
                        SHIELDED_TRANSACTION_RECORDS_CATEGORY, imported
                    ),
                    Err(err) => {
                        eprintln!(
                            "Failed to import {}: {}",
                            SHIELDED_TRANSACTION_RECORDS_CATEGORY, err
                        );
                        return Some(1);
                    }
                }
            }
            Some(0)
        }
    }
}

fn maybe_run_shielded_state_rebuild_admin(args: &[String]) -> Option<i32> {
    if !has_flag(args, REBUILD_SHIELDED_STATE_FROM_BLOCKS_FLAG) {
        return None;
    }

    let dry_run = has_flag(args, "--dry-run");
    if !dry_run {
        let confirm = get_flag_value(args, &["--confirm"]);
        if confirm != Some(SHIELDED_STATE_REBUILD_CONFIRMATION) {
            eprintln!("Refusing write without --confirm {SHIELDED_STATE_REBUILD_CONFIRMATION}");
            return Some(1);
        }
    }

    let data_dir = restriction_schema_data_dir(args);
    let state = match StateStore::open(&data_dir) {
        Ok(state) => state,
        Err(err) => {
            eprintln!("Failed to open state DB at {}: {}", data_dir.display(), err);
            return Some(1);
        }
    };

    match state.rebuild_shielded_state_from_canonical_blocks(dry_run) {
        Ok(report) => {
            print_shielded_state_rebuild_report(&data_dir, &report);
            Some(0)
        }
        Err(err) => {
            eprintln!("Failed to rebuild shielded state: {err}");
            Some(1)
        }
    }
}

