    fn make_signed_transfer_tx(
        from_kp: &Keypair,
        from: Pubkey,
        to: Pubkey,
        amount_licn: u64,
        recent_blockhash: Hash,
    ) -> Transaction {
        let mut data = vec![0u8];
        data.extend_from_slice(&Account::licn_to_spores(amount_licn).to_le_bytes());
        let ix = Instruction {
            program_id: CORE_SYSTEM_PROGRAM_ID,
            accounts: vec![from, to],
            data,
        };
        let message = Message::new(vec![ix], recent_blockhash);
        let mut tx = Transaction::new(message);
        tx.signatures.push(from_kp.sign(&tx.message.serialize()));
        tx
    }

    fn make_oracle_replay_block(
        state: &StateStore,
        parent: &Block,
        producer: &Keypair,
        txs: Vec<Transaction>,
        slot: u64,
        timestamp: u64,
    ) -> Block {
        let producer_pubkey = producer.pubkey();
        let speculative = TxProcessor::new_speculative(state.clone())
            .process_transactions_speculative(&txs, &producer_pubkey);
        for result in &speculative.results {
            assert!(
                result.success,
                "oracle replay test tx should be valid: {:?}",
                result.error
            );
        }
        let state_root = state.compute_state_root_for_batch(&speculative.batch);
        let mut block = Block::new_with_timestamp(
            slot,
            parent.hash(),
            state_root,
            producer_pubkey.0,
            txs,
            timestamp,
        );
        block.tx_fees_paid = speculative
            .results
            .iter()
            .map(|result| result.fee_paid)
            .collect();
        block.sign(producer);
        block
    }

