    #[test]
    fn classify_bft_commit_storage_allows_only_fresh_next_block() {
        let block_hash = Hash([1u8; 32]);

        assert_eq!(
            classify_bft_commit_storage(11, 10, None, block_hash),
            BftCommitStorageDecision::FreshNextBlock
        );
        assert_eq!(
            classify_bft_commit_storage(10, 10, Some(block_hash), block_hash),
            BftCommitStorageDecision::DuplicateAtTip
        );
        assert_eq!(
            classify_bft_commit_storage(9, 10, Some(block_hash), block_hash),
            BftCommitStorageDecision::StaleAlreadyApplied
        );
        assert_eq!(
            classify_bft_commit_storage(12, 10, Some(block_hash), block_hash),
            BftCommitStorageDecision::StoredAheadOfTip
        );
        assert_eq!(
            classify_bft_commit_storage(10, 10, None, block_hash),
            BftCommitStorageDecision::StaleMissingBlock
        );
        assert_eq!(
            classify_bft_commit_storage(12, 10, None, block_hash),
            BftCommitStorageDecision::MissingParentGap
        );
        assert_eq!(
            classify_bft_commit_storage(10, 10, Some(Hash([2u8; 32])), block_hash),
            BftCommitStorageDecision::ConflictingStoredHash
        );
    }

    #[test]
    fn live_bft_pauses_when_tip_or_observation_runs_ahead() {
        assert!(!should_pause_live_bft_for_sync(10, 11, 10));
        assert!(!should_pause_live_bft_for_sync(10, 11, 11));
        assert!(!should_pause_live_bft_for_sync(10, 11, 12));
        assert!(should_pause_live_bft_for_sync(10, 12, 12));
        assert!(!should_pause_live_bft_for_sync(10, 11, 13));
        assert!(!should_yield_live_bft_for_catch_up(10, 11, 12));
        assert!(should_yield_live_bft_for_catch_up(10, 12, 12));
        assert!(!should_yield_live_bft_for_catch_up(10, 11, 13));
        assert!(should_yield_live_bft_for_catch_up(
            10,
            11,
            10 + LIVE_BFT_CATCH_UP_GAP + 1
        ));
    }

    #[test]
    fn validate_then_replay_mismatch_does_not_mutate_canonical_state() {
        let temp_dir = tempfile::tempdir().expect("create temp dir");
        let state = StateStore::open(temp_dir.path()).expect("open state");
        let alice_kp = Keypair::generate();
        let alice = alice_kp.pubkey();
        let bob = Pubkey([2u8; 32]);
        let treasury = Pubkey([3u8; 32]);
        let validator = Pubkey([42u8; 32]);

        state.set_treasury_pubkey(&treasury).expect("set treasury");
        state
            .put_account(&treasury, &Account::new(0, treasury))
            .expect("put treasury");
        state
            .put_account(&alice, &Account::new(1000, alice))
            .expect("fund alice");

        let genesis_root = state.compute_state_root_cold_start();
        let genesis =
            Block::new_with_timestamp(0, Hash::default(), genesis_root, validator.0, Vec::new(), 0);
        let genesis_hash = genesis.hash();
        state.put_block(&genesis).expect("put genesis");
        state.set_last_slot(0).expect("set last slot");

        let tx = make_signed_transfer_tx(&alice_kp, alice, bob, 1, genesis_hash);
        let tx_hash = tx.hash();
        let block =
            Block::new_with_timestamp(1, genesis_hash, Hash([9u8; 32]), validator.0, vec![tx], 1);
        let canonical_root_before = state.compute_state_root_cold_start();
        let alice_before = state
            .get_account(&alice)
            .expect("read alice")
            .expect("alice exists");

        let err = validate_then_replay_block_transactions(&state, &block, "test replay", false)
            .expect_err("wrong state root should fail before canonical replay");

        assert!(err.contains("state-root mismatch"));
        assert_eq!(state.compute_state_root_cold_start(), canonical_root_before);
        let alice_after = state
            .get_account(&alice)
            .expect("read alice after")
            .expect("alice remains");
        assert_eq!(alice_after.spores, alice_before.spores);
        assert_eq!(alice_after.spendable, alice_before.spendable);
        assert!(state.get_account(&bob).expect("read bob").is_none());
        assert!(state.get_transaction(&tx_hash).expect("read tx").is_none());
    }

    #[test]
    fn validate_then_replay_commits_failed_transaction_receipt() {
        let temp_dir = tempfile::tempdir().expect("create temp dir");
        let state = StateStore::open(temp_dir.path()).expect("open state");
        let alice_kp = Keypair::generate();
        let alice = alice_kp.pubkey();
        let bob = Pubkey([2u8; 32]);
        let treasury = Pubkey([3u8; 32]);
        let validator = Pubkey([42u8; 32]);

        state.set_treasury_pubkey(&treasury).expect("set treasury");
        state
            .put_account(&treasury, &Account::new(0, treasury))
            .expect("put treasury");
        state
            .put_account(&alice, &Account::new(1_000, alice))
            .expect("fund alice");

        let genesis_root = state.compute_state_root_cold_start();
        let genesis =
            Block::new_with_timestamp(0, Hash::default(), genesis_root, validator.0, Vec::new(), 0);
        let genesis_hash = genesis.hash();
        state.put_block(&genesis).expect("put genesis");
        state.set_last_slot(0).expect("set last slot");

        let tx = make_signed_transfer_tx(&alice_kp, alice, bob, 2_000, genesis_hash);
        let tx_hash = tx.hash();
        let speculative = TxProcessor::new_speculative(state.clone())
            .process_transactions_speculative(std::slice::from_ref(&tx), &validator);
        assert!(!speculative.results[0].success);
        assert!(speculative.results[0].receipt_eligible);
        let fee_paid = speculative.results[0].fee_paid;
        let initial_balance = state.get_balance(&alice).expect("alice balance");

        let mut block = Block::new_with_timestamp(
            1,
            genesis_hash,
            state.compute_state_root_for_batch(&speculative.batch),
            validator.0,
            vec![tx],
            1,
        );
        block.tx_fees_paid = vec![fee_paid];

        validate_then_replay_block_transactions(&state, &block, "failed receipt replay", false)
            .expect("deterministic failure should be replayable");

        assert!(state.get_transaction(&tx_hash).unwrap().is_some());
        assert_eq!(
            state.get_block_by_slot(1).unwrap().unwrap().hash(),
            block.hash()
        );
        let receipt = state.get_tx_meta_full(&tx_hash).unwrap().unwrap();
        assert_eq!(receipt.success, Some(false));
        assert_eq!(receipt.fee_paid, Some(fee_paid));
        assert!(receipt
            .error
            .as_deref()
            .unwrap()
            .contains("Execution error"));
        assert_eq!(
            state.get_balance(&alice).unwrap(),
            initial_balance - fee_paid
        );
        assert_eq!(state.get_balance(&bob).unwrap_or(0), 0);
    }

