    #[test]
    fn snapshot_manifest_match_rejects_archive_drift() {
        let expected = test_snapshot_manifest(23);
        validate_snapshot_manifest_matches(&expected, &expected).expect("identical manifests");

        let mut wrong_count = expected.clone();
        wrong_count[0].entry_count += 1;
        assert!(validate_snapshot_manifest_matches(&expected, &wrong_count)
            .expect_err("changed entry count must be rejected")
            .contains("snapshot manifest mismatch"));

        let mut wrong_hash = expected.clone();
        wrong_hash[1].sha256[0] ^= 1;
        assert!(validate_snapshot_manifest_matches(&expected, &wrong_hash)
            .expect_err("changed category hash must be rejected")
            .contains("snapshot manifest mismatch"));
    }

    #[test]
    fn warp_snapshot_category_requests_advance_in_canonical_order() {
        let mut progress = HashMap::new();
        assert_eq!(
            next_snapshot_category_request(&progress, WARP_SNAPSHOT_CATEGORIES),
            Some(("accounts", 0))
        );

        progress.insert("accounts".to_string(), (1, 3));
        assert_eq!(
            next_snapshot_category_request(&progress, WARP_SNAPSHOT_CATEGORIES),
            Some(("accounts", 1))
        );

        progress.insert("accounts".to_string(), (3, 3));
        assert_eq!(
            next_snapshot_category_request(&progress, WARP_SNAPSHOT_CATEGORIES),
            Some(("blocks", 0))
        );

        progress.insert("blocks".to_string(), (2, 5));
        assert_eq!(
            next_snapshot_category_request(&progress, WARP_SNAPSHOT_CATEGORIES),
            Some(("blocks", 2))
        );

        for category in WARP_SNAPSHOT_CATEGORIES {
            progress.insert((*category).to_string(), (1, 1));
        }
        assert_eq!(
            next_snapshot_category_request(&progress, WARP_SNAPSHOT_CATEGORIES),
            None
        );
    }

    #[test]
    fn checkpoint_metadata_requests_are_throttled_during_warp_snapshot() {
        let mut sync = SnapshotSync::new(true);

        assert!(sync.should_request_checkpoint_metadata());
        assert!(!sync.should_request_checkpoint_metadata());

        sync.last_checkpoint_metadata_request_at = Some(
            std::time::Instant::now()
                - std::time::Duration::from_secs(CHECKPOINT_METADATA_RETRY_SECS),
        );
        assert!(sync.should_request_checkpoint_metadata());

        sync.mark_warp_snapshot_active();
        sync.last_checkpoint_metadata_request_at = Some(
            std::time::Instant::now()
                - std::time::Duration::from_secs(CHECKPOINT_METADATA_RETRY_SECS * 2),
        );
        assert!(!sync.should_request_checkpoint_metadata());

        sync.mark_warp_snapshot_idle();
        assert!(sync.should_request_checkpoint_metadata());
    }

    #[test]
    fn stalled_checkpoint_snapshot_retries_are_bounded() {
        let mut retries = 0;

        for expected_attempt in 1..=SNAPSHOT_PROGRESS_MAX_STALLED_RETRIES {
            assert_eq!(
                checkpoint_snapshot_stall_decision(&mut retries),
                SnapshotStallDecision::Retry {
                    attempt: expected_attempt
                }
            );
        }

        assert_eq!(
            checkpoint_snapshot_stall_decision(&mut retries),
            SnapshotStallDecision::Abandon
        );
        assert_eq!(retries, SNAPSHOT_PROGRESS_MAX_STALLED_RETRIES);

        retries = 0;
        assert_eq!(
            checkpoint_snapshot_stall_decision(&mut retries),
            SnapshotStallDecision::Retry { attempt: 1 }
        );
    }

    #[test]
    fn verified_checkpoint_cache_invalidates_exact_unservable_anchor() {
        let manifest_a = vec![SnapshotCategoryDigest {
            category: "accounts".to_string(),
            entry_count: 1,
            sha256: [3u8; 32],
        }];
        let manifest_b = vec![SnapshotCategoryDigest {
            category: "accounts".to_string(),
            entry_count: 2,
            sha256: [4u8; 32],
        }];
        let root_a = [9u8; 32];
        let root_b = [10u8; 32];
        let make_checkpoint =
            |slot: u64, state_root: [u8; 32], manifest: Vec<SnapshotCategoryDigest>| {
                test_verified_checkpoint_data(
                    slot,
                    state_root,
                    format!("/tmp/slot-{slot}"),
                    manifest,
                )
            };
        let mut cache = VerifiedCheckpointCacheEntry {
            checkpoints: vec![
                make_checkpoint(100, root_a, manifest_a.clone()),
                make_checkpoint(101, root_b, manifest_b.clone()),
            ],
            verified_at: Instant::now(),
        };

        let mut wrong_manifest_root = advertised_snapshot_manifest_root(&manifest_a);
        wrong_manifest_root[0] ^= 1;
        assert!(
            !cache.remove_checkpoint_anchor(100, root_a, wrong_manifest_root),
            "different manifest roots must not evict cached checkpoint anchors"
        );
        assert_eq!(cache.checkpoints.len(), 2);

        assert!(cache.remove_checkpoint_anchor(
            100,
            root_a,
            advertised_snapshot_manifest_root(&manifest_a),
        ));
        assert_eq!(cache.checkpoints.len(), 1);
        assert_eq!(cache.checkpoints[0].meta.slot, 101);
        assert!(!cache.is_empty());

        assert!(cache.remove_checkpoint_anchor(
            101,
            root_b,
            advertised_snapshot_manifest_root(&manifest_b),
        ));
        assert!(cache.is_empty());
    }

    #[test]
    fn verified_checkpoint_cache_authorizes_only_exact_available_complete_archive() {
        let temp = tempfile::tempdir().expect("create temp dir");
        let checkpoint_path = temp.path().join("checkpoints/slot-100");
        std::fs::create_dir_all(&checkpoint_path).expect("create checkpoint dir");

        let state_root = [9u8; 32];
        let meta = lichen_core::CheckpointMeta {
            slot: 100,
            state_root,
            created_at: 100,
            total_accounts: 1,
        };
        std::fs::write(
            checkpoint_path.join("checkpoint_meta.json"),
            serde_json::to_vec(&meta).expect("serialize checkpoint metadata"),
        )
        .expect("write checkpoint metadata");

        let manifest = test_snapshot_manifest_for(31, CHECKPOINT_SNAPSHOT_CATEGORIES);
        let manifest_root = snapshot_manifest_root(&manifest);
        let cache = VerifiedCheckpointCacheEntry {
            checkpoints: vec![test_verified_checkpoint_data(
                meta.slot,
                state_root,
                checkpoint_path.display().to_string(),
                manifest,
            )],
            verified_at: Instant::now(),
        };

        let exact_anchor = CheckpointSnapshotRequestAnchor {
            slot: meta.slot,
            state_root,
            snapshot_manifest_root: manifest_root,
        };
        let session = cache
            .snapshot_export_session_for_anchor(exact_anchor)
            .expect("exact cached complete archive should authorize");
        assert_eq!(session.meta.slot, meta.slot);
        assert_eq!(session.categories, CHECKPOINT_SNAPSHOT_CATEGORIES);

        let mut wrong_manifest_root = manifest_root;
        wrong_manifest_root[0] ^= 1;
        assert!(
            cache
                .snapshot_export_session_for_anchor(CheckpointSnapshotRequestAnchor {
                    snapshot_manifest_root: wrong_manifest_root,
                    ..exact_anchor
                })
                .is_none(),
            "a different archive manifest must not authorize"
        );

        std::fs::remove_file(checkpoint_path.join("checkpoint_meta.json"))
            .expect("remove checkpoint metadata");
        assert!(
            cache
                .snapshot_export_session_for_anchor(exact_anchor)
                .is_none(),
            "a pruned checkpoint path must not authorize"
        );
    }

    #[test]
    fn verified_checkpoint_cache_reuses_only_unchanged_primary_manifests() {
        let temp = tempfile::tempdir().expect("create temp dir");
        let checkpoint_path = temp.path().join("checkpoints/slot-100");
        std::fs::create_dir_all(&checkpoint_path).expect("create checkpoint dir");
        std::fs::write(checkpoint_path.join("checkpoint_meta.json"), b"{}")
            .expect("write checkpoint marker");

        let state_root = [9u8; 32];
        let make_checkpoint = |slot, path: String, manifest| {
            test_verified_checkpoint_data(slot, state_root, path, manifest)
        };
        let manifest = test_snapshot_manifest_for(41, CHECKPOINT_SNAPSHOT_CATEGORIES);
        let previous = VerifiedCheckpointCacheEntry {
            checkpoints: vec![make_checkpoint(
                100,
                checkpoint_path.display().to_string(),
                manifest.clone(),
            )],
            verified_at: Instant::now(),
        };
        let mut refreshed = VerifiedCheckpointCacheEntry {
            checkpoints: vec![make_checkpoint(
                100,
                checkpoint_path.display().to_string(),
                Vec::new(),
            )],
            verified_at: Instant::now(),
        };

        refreshed.reuse_snapshot_manifests_from(&previous);
        assert_eq!(refreshed.checkpoints[0].snapshot_manifest, manifest);
        assert!(refreshed.has_snapshot_manifest());

        let new_checkpoint_path = temp.path().join("checkpoints/slot-101");
        std::fs::create_dir_all(&new_checkpoint_path).expect("create new checkpoint dir");
        std::fs::write(new_checkpoint_path.join("checkpoint_meta.json"), b"{}")
            .expect("write new checkpoint marker");
        let mut advanced = VerifiedCheckpointCacheEntry {
            checkpoints: vec![
                make_checkpoint(101, new_checkpoint_path.display().to_string(), Vec::new()),
                make_checkpoint(100, checkpoint_path.display().to_string(), Vec::new()),
            ],
            verified_at: Instant::now(),
        };

        advanced.reuse_snapshot_manifests_from(&previous);
        assert!(advanced.checkpoints[0].snapshot_manifest.is_empty());
        assert_eq!(advanced.checkpoints[1].snapshot_manifest, manifest);
        assert!(
            !advanced.has_snapshot_manifest(),
            "a reused older manifest must not suppress scanning the new primary checkpoint"
        );
    }

