    #[test]
    fn snapshot_checkpoint_lookup_uses_background_verified_cache() {
        let source = include_str!("main.rs");
        let start = source
            .find("Snapshot request handler started")
            .expect("snapshot request handler marker");
        let end = source[start..]
            .find("// Handle CheckpointMetaResponse")
            .map(|offset| start + offset)
            .expect("checkpoint metadata response marker");
        let section = &source[start..end];

        assert_eq!(
            section
                .matches("verified_checkpoint_meta_anchors_cached(")
                .count(),
            2,
            "snapshot serving should use the shared checkpoint metadata cache only for metadata responses"
        );
        assert_eq!(
            section.matches("latest_verified_checkpoint(").count(),
            0,
            "snapshot serving must not run full checkpoint verification inline"
        );
        assert!(
            section.contains("verified_checkpoint_refresh"),
            "snapshot serving must share a background checkpoint refresh handle"
        );
        assert_eq!(
            section.matches("checkpoint_auth_snapshot(").count(),
            0,
            "checkpoint verification must not depend on the receiver's current auth state"
        );
        assert_eq!(
            section
                .matches("snapshot_export_session_for_anchor(")
                .count(),
            1,
            "chunk serving must authorize against the verified checkpoint cache"
        );
        assert_eq!(
            section.matches("verified_checkpoint_for_anchor(").count(),
            0,
            "chunk serving must not synchronously rescan and hash a checkpoint archive"
        );
        assert_eq!(
            section
                .matches("validator_set_for_snapshot.read().await")
                .count(),
            0,
            "snapshot checkpoint lookup must not hold live validator-set read guards"
        );
        assert_eq!(
            section
                .matches("stake_pool_for_snapshot.read().await")
                .count(),
            0,
            "snapshot checkpoint lookup must not hold live stake-pool read guards"
        );
    }

