    #[test]
    fn stale_snapshot_staging_cleanup_only_removes_slot_dirs() {
        let temp = tempfile::tempdir().unwrap();
        let root = temp.path();
        let stale_one = root.join("staging-snapshot-1");
        let stale_two = root.join("staging-snapshot-42");
        let malformed = root.join("staging-snapshot-current");
        let empty_suffix = root.join("staging-snapshot-");
        let checkpoint = root.join("checkpoints").join("slot-1000");
        let rollback = root.join("snapshot-live-rollback");
        let proposal = root.join("proposal-staging");
        let file_with_staging_name = root.join("staging-snapshot-99");

        std::fs::create_dir_all(stale_one.join("db")).unwrap();
        std::fs::create_dir_all(&stale_two).unwrap();
        std::fs::create_dir_all(&malformed).unwrap();
        std::fs::create_dir_all(&empty_suffix).unwrap();
        std::fs::create_dir_all(&checkpoint).unwrap();
        std::fs::create_dir_all(&rollback).unwrap();
        std::fs::create_dir_all(&proposal).unwrap();
        std::fs::write(&file_with_staging_name, b"not a directory").unwrap();

        assert_eq!(
            snapshot_staging_slot_from_name("staging-snapshot-42"),
            Some(42)
        );
        assert_eq!(
            snapshot_staging_slot_from_name("staging-snapshot-current"),
            None
        );
        assert_eq!(snapshot_staging_slot_from_name("staging-snapshot-"), None);

        let removed = cleanup_stale_snapshot_staging_dirs(root.to_str().unwrap()).unwrap();
        assert_eq!(removed, 2);
        assert!(!stale_one.exists());
        assert!(!stale_two.exists());
        assert!(malformed.exists());
        assert!(empty_suffix.exists());
        assert!(checkpoint.exists());
        assert!(rollback.exists());
        assert!(proposal.exists());
        assert!(file_with_staging_name.exists());
    }

    #[test]
    fn sync_range_peer_order_rotates_primary_and_preserves_fallbacks() {
        let peers: Vec<SocketAddr> = ["127.0.0.1:7001", "127.0.0.1:7002", "127.0.0.1:7003"]
            .into_iter()
            .map(|addr| addr.parse().unwrap())
            .collect();

        assert_eq!(
            sync_range_peer_order(&peers, 0),
            vec![peers[0], peers[1], peers[2]]
        );
        assert_eq!(
            sync_range_peer_order(&peers, 1),
            vec![peers[1], peers[2], peers[0]]
        );
        assert_eq!(
            sync_range_peer_order(&peers, 2),
            vec![peers[2], peers[0], peers[1]]
        );
        assert!(sync_range_peer_order(&[], 0).is_empty());
    }

    #[test]
    fn sync_range_peer_candidates_prefer_peers_that_advertise_requested_tip() {
        let stale_high_score: SocketAddr = "127.0.0.1:7001".parse().unwrap();
        let stale_low_score: SocketAddr = "127.0.0.1:7002".parse().unwrap();
        let fresh_peer: SocketAddr = "127.0.0.1:7003".parse().unwrap();
        let fresher_peer: SocketAddr = "127.0.0.1:7004".parse().unwrap();
        let peer_infos = vec![
            (stale_high_score, 20, 641),
            (fresh_peer, 0, 642),
            (stale_low_score, -5, 641),
            (fresher_peer, 0, 643),
        ];

        assert_eq!(
            sync_range_peer_candidates(&peer_infos, 642, 4),
            vec![fresher_peer, fresh_peer, stale_high_score, stale_low_score]
        );
        assert_eq!(
            sync_range_peer_candidates(&peer_infos, 642, 1),
            vec![fresher_peer],
            "single-peer catch-up must not choose a stale peer when fresh peers are known"
        );
    }

